-- Poems batch 256
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('f82cb746-043c-471d-896a-a2421e32e90a','瑞金縣西池雙蓮汪簿有詩見寄因以和之','金君卿','宋','宋诗','song-poetry','','[]','惠政多應草木知，藕花呈瑞向西池。',64,'全唐诗/poet.song.23000.json','["惠政多應草木知，藕花呈瑞向西池。", "雙紅共蒂初含笑，衆卉千名總合奇。", "寵降帝妃媯汭日，恍迷仙佩漢臯時。", "若教潘令河陽見，肯羨東風桃李枝。"]'),
('1d1e012a-17ba-4156-8430-0e3e90703ea4','南塘閑泛二首  其一','金君卿','宋','宋诗','song-poetry','','[]','雨收平淀飲殘虹，蘋末無風碧印空。',64,'全唐诗/poet.song.23000.json','["雨收平淀飲殘虹，蘋末無風碧印空。", "寒凈渾疑踏冰去，清光直欲貯胸中。", "客檣隠隠逐飛鳥，釣舸悠悠任轉蓬。", "日暮韓隄猶極望，却將耕稼問漁翁。"]'),
('34aa0a8e-5307-4805-b7dd-0e2ce274a306','南塘閑泛二首  其二','金君卿','宋','宋诗','song-poetry','','[]','水鄉真箇似三吳，碧淀涵秋水鑑湖。',64,'全唐诗/poet.song.23000.json','["水鄉真箇似三吳，碧淀涵秋水鑑湖。", "十里香風起蓮萼，半空飛雪下鷗雛。", "隄森古木嚴征仗，塞繚方田展角圖。", "閑艤洛陽橋畔飲，風濤還到此中無。"]'),
('cc2089fe-bdc9-4317-966d-32e64587cf67','同陳郎中遊南塘','金君卿','宋','宋诗','song-poetry','','[]','水光烟色滿南塘，十里橫連古戰堭。',64,'全唐诗/poet.song.23000.json','["水光烟色滿南塘，十里橫連古戰堭。", "千頃芋畦楸罫局，萬章雲木羽林鎗。", "漁歌鬧處菱花紫，田婦歸時秫穗黄。", "賢守公餘行樂去，許陪旌騎問耕桑。"]'),
('c237bce7-d1b6-4fa7-95dc-c9848bb348cc','周濤權宰大冶以湖光亭詩見寄因和之','金君卿','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','面揖清光萬頃陂，滿簷秋色曙陰微。',64,'全唐诗/poet.song.23000.json','["面揖清光萬頃陂，滿簷秋色曙陰微。", "回環遠岫煙中辨，片段閑雲鏡裏飛。", "富冶地饒民訟簡，洞庭風便客舟稀。", "知君已厭江山思，亭下行吟日望歸。"]'),
('5ab59fa5-2d85-4b7e-b414-25fed369d5ef','寄所知','金君卿','宋','宋诗','song-poetry','','[]','正色當官取悔尤，清時無告獨包羞。',64,'全唐诗/poet.song.23000.json','["正色當官取悔尤，清時無告獨包羞。", "獄中劍氣猶盤鬰，火裏琴材未見收。", "自古聖賢由直道，遭時誣毀亦幽囚。", "願持仁義爲篙檝，敏手中流救覆舟。"]'),
('ec46c692-0f03-4bd5-bb96-9f616cac27c9','秋鴈','金君卿','宋','宋诗','song-poetry','','[]','北來南去年年事，微物還應不自由。',64,'全唐诗/poet.song.23000.json','["北來南去年年事，微物還應不自由。", "繒繳多機應遠謝，稻粱已飽更何求。", "瀟瀟風雨衡陽暮，渺渺烟波震澤秋。", "夜過邊城牢閉口，斷腸砧杵不禁愁。"]'),
('8d80c79b-121a-4a4a-8bb4-f348c0fcc875','寄別致政王允','金君卿','宋','宋诗','song-poetry','','[]','羨君高尚褫朝紳，始是人間自在身。',64,'全唐诗/poet.song.23000.json','["羨君高尚褫朝紳，始是人間自在身。", "深塢結廬窮水石，半山開徑入松筠。", "肩輿訪寺常携鶴，釃酒邀朋祇墊巾。", "我欲效尤歸未得，又驅疲馬踏京塵。"]'),
('011a83e4-cf4a-4f5a-bdbc-c5c2c7e029b3','鬰孤臺','金君卿','宋','宋诗','song-poetry','','[]','鱗鱗萬瓦遶雲根，環列諸峯勢獨尊。',64,'全唐诗/poet.song.23000.json','["鱗鱗萬瓦遶雲根，環列諸峯勢獨尊。", "屹若靈鼇浮海面，儼如謀將立轅門。", "贛流東匯龍蛇走，崆阜南來虎豹蹲。", "乘月偶爲逃暑飲，欲捫南斗當清樽。"]'),
('49ec5d63-8794-4a2c-9fb2-5e99355c18de','南康縣清暑臺','金君卿','宋','宋诗','song-poetry','','[]','子康疎畬人皆笑，即墨孤危衆所攻。',64,'全唐诗/poet.song.23000.json','["子康疎畬人皆笑，即墨孤危衆所攻。", "遇主卒封齊萬戶，會時猶位漢三公。", "二賢養正堪忻慕，百里徒勞且晦蒙。", "閑上高臺散幽鬰，獨開襟袖挹清風。"]'),
('f2cdab6c-c35a-4763-8034-70f026458706','冬至日代書呈諸兄','金君卿','宋','宋诗','song-poetry','','[]','人人懽聚慶新陽，我獨飛心戀北堂。',64,'全唐诗/poet.song.23000.json','["人人懽聚慶新陽，我獨飛心戀北堂。", "薄宦飄流成底事，數年牢落在他鄉。", "徒將遠意憑歸鴈，不及諸兄捧壽觴。", "何幸前春改官去，綵衣相逐戲親傍。"]'),
('23898be0-ba49-4fb7-bfbf-e51939a8ca1d','寄題三靈山程先生瑞墨閣','金君卿','宋','宋诗','song-poetry','','[]','翼舒層構倚雲霞，日下無雙處士家。',64,'全唐诗/poet.song.23000.json','["翼舒層構倚雲霞，日下無雙處士家。", "千疊靈山橫琬琰，八分宸筆動龍蛇。", "趨庭素業皆黄卷，揭版新詩半碧紗。", "我倦迷津欲歸老，頼君曾爲指仙槎。"]'),
('a65a4d2a-9e32-4216-88bc-fe8f9649a2f1','滕王閣','金君卿','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','無復朱樓萬幕垂，碧流青嶂似當時。',64,'全唐诗/poet.song.23000.json','["無復朱樓萬幕垂，碧流青嶂似當時。", "不須越舞并秦唱，自有韓文與杜詩。", "殘雪未消春到晚，彩毫爭落酒行遲。", "滿簾紅日江天暮，隔浦一聲楊柳枝。"]'),
('868f4dbd-7c25-4907-8496-fb79ccd3666b','和曾子固聞言事謫官者','金君卿','宋','宋诗','song-poetry','','[]','四海瘡痍劇蝟毛，愛君三諫未能逃。',64,'全唐诗/poet.song.23000.json','["四海瘡痍劇蝟毛，愛君三諫未能逃。", "所期力濟生民福，不爲名存信史褒。", "想見斯人心獨喜，願爲君黨義尤高。", "忠言已入身甘竄，始見吾徒氣思豪。"]'),
('47330d25-2b76-4ebd-bbc1-a5a9bdfea18a','送虔州知州','金君卿','宋','宋诗','song-poetry','','[]','所蒞驅除弊一新，政成草木亦知仁。',64,'全唐诗/poet.song.23000.json','["所蒞驅除弊一新，政成草木亦知仁。", "已書治最稱循史，好躡家聲作諍臣。", "飛詔罷歸漳水日，去帆催向汴隄春。", "未央賜對須南問，應記塵勞負弩人。"]'),
('95a6a000-ac35-4bdb-8255-49abfbec061f','離山陽阻風少憩歸思浩然','金君卿','宋','宋诗','song-poetry','','[]','雨寒風橫暫停橈，楚望亭南十里遥。',64,'全唐诗/poet.song.23000.json','["雨寒風橫暫停橈，楚望亭南十里遥。", "舟刺水村銜燕尾，橋橫煙市隠虹腰。", "歸程不待春潮漲，孤憤難憑斗酒銷。", "幸有同途江外客，不吟何以慰無聊。"]'),
('5e40459f-43c9-4c75-b855-95a59395b845','賦得憶梅寄朱公美','金君卿','宋','宋诗','song-poetry','','[]','七度經春不見梅，水邊亭下獨徘徊。',64,'全唐诗/poet.song.23000.json','["七度經春不見梅，水邊亭下獨徘徊。", "因思昨夜臘前雪，定是此時花盛開。", "遠信浪從江外至，新聲剛向笛中來。", "如何便得南歸去，共把清香醉幾回。"]'),
('3ea8f743-e16b-46ae-a0cf-b6d7a296773e','和周濤見寄','金君卿','宋','宋诗','song-poetry','','[]','薄宦留連未得歸，思親懷舊兩依依。',64,'全唐诗/poet.song.23000.json','["薄宦留連未得歸，思親懷舊兩依依。", "嶺頭梅信憑誰去，枕上鴻聲到此稀。", "君喜及瓜催北響，我嗟垂翅倦南飛。", "何時共作東都客，不厭京塵化旅衣。"]'),
('16b12dc4-d574-42f8-9cc8-ffa81f9024ce','和介甫寄安豐張公儀之什','金君卿','宋','宋诗','song-poetry','','[]','前賢立事豈徒然，惠政須教振古傳。',64,'全唐诗/poet.song.23000.json','["前賢立事豈徒然，惠政須教振古傳。", "芍水灌餘三萬頃，楚人祠已二千年。", "近聞令尹開新牐，不避風波上小船。", "堤築已完輿頌洽，去時民吏重留連。"]'),
('0b3b0bcd-d1de-43be-a1ac-6e349a9c7586','遊陽府寺','金君卿','宋','宋诗','song-poetry','','[]','山肋盤紆一徑斜，水煙深處梵王家。',64,'全唐诗/poet.song.23000.json','["山肋盤紆一徑斜，水煙深處梵王家。", "聞雷已薦鷄鳴笋，未火先嘗雀舌茶。", "吟客披雲題石壁，藥僧和露掃松花。", "縱遊向晚尋歸路，渡口平沙卧古槎。"]'),
('bddab89a-d396-47e3-a1dd-cb4fc5d98d63','蒙詔書奬諭寄呈王介甫相公','金君卿','宋','宋诗','song-poetry','','[]','鳳口銜書出九重，帝王親賜紫泥封。',64,'全唐诗/poet.song.23000.json','["鳳口銜書出九重，帝王親賜紫泥封。", "神光下燭將飛劍，真賞重鳴既啞鐘。", "砥礪若爲酬睿睠，驅馳何敢嘆塵蹤。", "仙翁更借提携力，竹杖由來解化龍。"]'),
('fc56bff0-4b30-4d00-9d91-7486ca3c395f','重修龍興觀寄呈江吳二尊師  其一','金君卿','宋','宋诗','song-poetry','','[]','壇宇榛蕪幾十年，遺基重葺控長川。',64,'全唐诗/poet.song.23000.json','["壇宇榛蕪幾十年，遺基重葺控長川。", "羽人便是雙飛鶴，仙籍須增一洞天。", "藍嶠逢秋無敗葉，龜池經夏有甘泉。", "操舟過客宜停棹，暫到塵襟自洒然。"]'),
('46925000-2acb-4555-86cf-6b3dc36a7806','重修龍興觀寄呈江吳二尊師  其二','金君卿','宋','宋诗','song-poetry','','[]','萬戶晴嵐生紫烟，絕塵佳致甲昌川。',64,'全唐诗/poet.song.23000.json','["萬戶晴嵐生紫烟，絕塵佳致甲昌川。", "輕舠急槳風中葉，碧瓦朱欄水底天。", "雨夜龍涎腥柱礎，霜秋桂子落嵓泉。", "二師自得幽棲趣，向此灰心肯復然。"]'),
('58a16dc2-c2d6-4029-9236-b5eda269b1b3','和永叔穎川西湖','金君卿','宋','宋诗','song-poetry','','["\u897f\u6e56"]','名遊無似郡城西，況是棠陰訟簡時。',64,'全唐诗/poet.song.23000.json','["名遊無似郡城西，況是棠陰訟簡時。", "信步桑間春去後，榜舟湖面夜歸遲。", "烟波際目無窮樂，沙鳥留人逐處隨。", "應爲獨醒須强醉，浩歌風月倒千巵。"]'),
('2d1acfad-efe0-4631-9c73-d22218c8c8c8','花沼分題','金君卿','宋','宋诗','song-poetry','','[]','寒光凈色照花林，更喜詩家共賞心。',64,'全唐诗/poet.song.23000.json','["寒光凈色照花林，更喜詩家共賞心。", "謝客不成春草夢，杜郎須强海棠吟。", "惟憂別去歌雲散，不管愁來鬢雪侵。", "且試主人新酒令，片紅飄琖十分斟。"]'),
('f42fc6d6-d28b-4f46-9c3d-b75bf8d12e2e','和永叔芍藥','金君卿','宋','宋诗','song-poetry','','[]','不逐羣花散漫開，風前一笑尚淹回。',64,'全唐诗/poet.song.23000.json','["不逐羣花散漫開，風前一笑尚淹回。", "使人便有留春意，對爾强須銜酒杯。", "時與樂并真勝會，筆緣情賦盡高才。", "如何只得新詩看，也似南園縱賞來。"]'),
('abbe2b6e-cbf7-4018-9e64-aabc31c7c22a','題贈南臺山院主吉大師','金君卿','宋','宋诗','song-poetry','','[]','三紀修行箬笠僧，布衣襤褸髮鬅鬙。',64,'全唐诗/poet.song.23000.json','["三紀修行箬笠僧，布衣襤褸髮鬅鬙。", "邑人與卜幽棲處，象法能通最上乘。", "常宿靈嵓敲玉磬，旋營精剎布金繩。", "江西望鎮稱臺嶺，使者重來喜共登。"]'),
('f05e891e-4863-4484-9225-c21552adc140','黄通有詩見寄因以答之','金君卿','宋','宋诗','song-poetry','','[]','一別俄然十二春，男兒志氣可因循。',64,'全唐诗/poet.song.23000.json','["一別俄然十二春，男兒志氣可因循。", "簡編少見承平日，世路稀逢磊落人。", "未免驅馳從縣道，已甘榮悴任天鈞。", "惟君知我須同醉，且喜清時祿逮親。"]'),
('077cdcdd-f30c-4f7c-be39-b363f6b272a4','題披雲閣','金君卿','宋','宋诗','song-poetry','','[]','仕路無如衣綵榮，喜聞弦誦日趨庭。',64,'全唐诗/poet.song.23000.json','["仕路無如衣綵榮，喜聞弦誦日趨庭。", "欲光子道兼三樂，須念家傳重一經。", "已敞高齋臨水鏡，更張層構倚山屏。", "佳名切礪男兒志，手抉浮雲見日星。"]'),
('052fcd46-f7ae-42a1-a1e0-f5b91293fde3','挽仁宗皇帝詞  其一','金君卿','宋','宋诗','song-poetry','','[]','廣輪三萬里聲明，四海謳歌號太平。',64,'全唐诗/poet.song.23000.json','["廣輪三萬里聲明，四海謳歌號太平。", "恭己愛慈同漢景，息民寬厚似周成。", "九郊上帝天和應，載饗明堂孝意精。", "惟有升中獨謙德，只應留待嗣君行。"]'),
('8cd71a2f-e587-4ab1-a0e0-673720af3830','挽仁宗皇帝詞  其二','金君卿','宋','宋诗','song-poetry','','[]','優賢從諫致時雍，舜目堯眉儼睟容。',64,'全唐诗/poet.song.23000.json','["優賢從諫致時雍，舜目堯眉儼睟容。", "靈算格天齊睿考，瑞元開筴倍神宗。", "夢迴綵仗歸霓闕，愁入宮聲咽暮鐘。", "臣子訴號空殞血，鼎湖無路許攀龍。"]'),
('99d4f88f-b582-4d9e-8a99-5172b5134b58','挽仁宗皇帝詞  其三','金君卿','宋','宋诗','song-poetry','','[]','慈儉身先治道間，未嘗論罸不從寬。',64,'全唐诗/poet.song.23000.json','["慈儉身先治道間，未嘗論罸不從寬。", "成功日比堯年盛，與子人知夏鼎安。", "憑几遺音傷萬古，抱弓銜恨泣千官。", "昭陵柏老伊川竭，宮掖三千淚始乾。"]'),
('d1ff740b-3ffe-42be-875c-e2d12b3fe296','挽仁宗皇帝詞  其四','金君卿','宋','宋诗','song-poetry','','[]','深仁醴澤浹威靈，最是櫜兵與緩刑。',64,'全唐诗/poet.song.23000.json','["深仁醴澤浹威靈，最是櫜兵與緩刑。", "坐接邇僚均父子，手揮宸翰走風霆。", "臣心未報空號慕，蒭牧無知亦涕零。", "視古諸侯從儉約，忍思遺詔尚丁寧。"]'),
('3bc5aa8c-03eb-4722-b3f5-5fa0cc1455cd','挽仁宗皇帝詞  其五','金君卿','宋','宋诗','song-poetry','','[]','億萬民靈四百州，銜恩哀慕幾時休。',64,'全唐诗/poet.song.23000.json','["億萬民靈四百州，銜恩哀慕幾時休。", "惜回長夜鈞天夢，歸侍仙都泰帝遊。", "蒼野路遥斑竹恨，翠微宮冷白楊秋。", "國人雨泣西郊暮，烟慘風悲亦爲愁。"]'),
('1912c99c-eb99-4e75-958d-bfc3fb260f33','感夢因接夢中所得詩句','金君卿','宋','宋诗','song-poetry','','[]','我后同堯舜，君臣詠載歌。',72,'全唐诗/poet.song.23000.json','["我后同堯舜，君臣詠載歌。", "天顔春日煦，庭列衆星羅。", "雅奏鈞音合，穠香瑞氣和。", "逢辰膺帝睠，既醉任顔酡。", "薦翣珍蒲異，儀庭舞獸多。", "太平無一事，圖報顧如何。"]'),
('902850a2-6c13-45d4-b7f3-5eb11de7f0fc','夢賦詩尋得唐韻冊檢看見恩字韻','金君卿','宋','宋诗','song-poetry','','[]','太平無事日，藩服盡賓門。',72,'全唐诗/poet.song.23000.json','["太平無事日，藩服盡賓門。", "九奏張新樂，千官奉至尊。", "光華逢舜旦，賡載誦堯言。", "在沼祥麟萃，來庭彩鳳翻。", "需雲和氣應，寶獸異香噴。", "下列容霑醉，何從報主恩。"]'),
('a27c4a95-ce16-4d3e-af8d-d1b8d9bb5843','和陳屯田秋雨','金君卿','宋','宋诗','song-poetry','','[]','雨勢正漫漫，空階滴未殘。',72,'全唐诗/poet.song.23000.json','["雨勢正漫漫，空階滴未殘。", "重陰連地暗，爽氣逼人寒。", "柱礎因雲潤，池魚得水懽。", "曉畦蔬甲綻，夜枕瓦聲乾。", "亂片飛林籜，衰紅泣砌蘭。", "前溪有歸客，清思發毫端。"]'),
('9e3d4285-f209-4326-b98d-bcfcbea3f2bf','文相生日','金君卿','宋','宋诗','song-poetry','','[]','羲御三星次，堯蓂九葉開。',288,'全唐诗/poet.song.23000.json','["羲御三星次，堯蓂九葉開。", "霄躔符有道，天驥下呈才。", "氣思淩諸謝，淵源過二崔。", "光華逢日月，騰躍契雲雷。", "迅步登文階，嚴聲凜柏臺。", "幽潛均照燭，精膽破姦回。", "地重圖書府，人瞻柱石才。", "堂基峻廉陛，鼎味仰鹽梅。", "師鉞方謀郄，樞庭喜得裴。", "往平蛟穴去，還入鳳池來。", "元化經綸內，真儒事業恢。", "威名攝窮裔，美利澤枯荄。", "陰德天須佑，精誠日可迴。", "祥光纔偶聖，妖彗不爲災。", "全粹圭無玷，晶明斗有魁。", "龍旆聊偃息，鴻渚暫徘徊。", "重倚周分陝，豐功稷啟邰。", "國醫先藥石，廟酌首罇罍。", "促召君前膝，圖勳位正槐。", "羣情欣愛日，憸黨極寒灰。", "王禮修嘗禘，天官總貨財。", "劘民歸砥礪，播物就坯胎。", "動植逢時若，君臣詠喜哉。", "兩京繄屏翰，大政輟公台。"]'),
('af9aa3ea-22ab-488d-928d-5a1e7ff56826','韓相生日','金君卿','宋','宋诗','song-poetry','','[]','商飈迎素律，兌澤薦元精。',288,'全唐诗/poet.song.23000.json','["商飈迎素律，兌澤薦元精。", "象順奎鈞爛，天鍾義氣清。", "千齡將聖偶，冢輔爲時生。", "粹藴森羣玉，沖襟貯四瀛。", "大方捐樸斵，淳辨復韶韺。", "先帝龍飛日，朝陽鳳一鳴。", "振文齊木鐸，保國敵金城。", "舊德方圖任，鴻鈞正倚平。", "具瞻歸峻嶽，衆口說和羹。", "固結君臣分，窮探禮樂情。", "用人兼畎畝，得士盡豪英。", "省罰蠲茶法，均徭審地征。", "鎮浮還美俗，恤隠起疲氓。", "考古淵源博，含章氣思宏。", "太平論極至，墜典悉興行。", "文物期三代，規摹小二京。", "納忠高子孟，任重等阿衡。", "國本重離正，身謀一羽輕。", "殊方想風烈，曒日照功名。", "嗣聖嘉深識，明神格至誠。", "官儀端表憲，圭瑞竦桓楹。", "邦揆車遵轄，時髦鹿在萍。", "戍亭無警燧，廓廟有奇兵。", "達節天須佑，真儒道始亨。"]'),
('75c0a48b-e849-4666-8b7b-4e1637fe5c20','宿德興周秀才書閣','金君卿','宋','宋诗','song-poetry','','[]','十室所可重，喜君吾道同。',24,'全唐诗/poet.song.23000.json','["十室所可重，喜君吾道同。", "因過一携手，醉卧六經中。"]'),
('720e2c3e-0a33-4210-9903-3261eda683a6','謝朱公美遺瓜酒','金君卿','宋','宋诗','song-poetry','','[]','龍蹄甘美蟻頭香，遠遠緘封遣老郎。',32,'全唐诗/poet.song.23000.json','["龍蹄甘美蟻頭香，遠遠緘封遣老郎。", "便向嵓亭逃暑去，恨無人共把觥觴。"]'),
('c8c928a1-8f67-4330-b135-9e9e53c1a6c8','雙溪','金君卿','宋','宋诗','song-poetry','','[]','雙派飛來一鏡寒，合流南注息驚湍。',32,'全唐诗/poet.song.23000.json','["雙派飛來一鏡寒，合流南注息驚湍。", "雨餘山脚雲收盡，兩幅青綃繞翠巒。"]'),
('56cdddca-a6bd-4618-aff0-0d468bff21a6','盛暑偶遊曠亭書于再生樟石碣之陰','金君卿','宋','宋诗','song-poetry','','[]','萬里雄風海嶠來，客襟聊爲曠亭開。',32,'全唐诗/poet.song.23000.json','["萬里雄風海嶠來，客襟聊爲曠亭開。", "千年古木清陰合，若比莊椿是美材。"]'),
('1c5cecf3-233e-4f8f-8e27-b073fd7039c9','寄別朱公美','金君卿','宋','宋诗','song-poetry','','[]','三載鄉坊義最親，驅車還是走京塵。',32,'全唐诗/poet.song.23000.json','["三載鄉坊義最親，驅車還是走京塵。", "雖無士會兼人智，猶有臨歧贈策人。"]'),
('701e2b48-e09d-43ff-bda9-ab7011287666','石龜塘','金君卿','宋','宋诗','song-poetry','','[]','石化神龜不計年，方塘依舊冽寒泉。',32,'全唐诗/poet.song.23000.json','["石化神龜不計年，方塘依舊冽寒泉。", "氛埃不到真仙境，擬倩麻姑種碧蓮。"]'),
('48bd110a-4b26-425c-9f7f-7cc000b5687a','南塘','金君卿','宋','宋诗','song-poetry','','[]','二月江南煙雨多，南塘一夜漲春波。',32,'全唐诗/poet.song.23000.json','["二月江南煙雨多，南塘一夜漲春波。", "堤邊遊女最歸晚，爭引漁舟作棹歌。"]'),
('d23e405d-19ec-4243-9704-614c7a7ae104','留題分宜前山吳隠士白雲亭  其一','金君卿','宋','宋诗','song-poetry','','[]','面挹晴光錦繡川，却臨蒼澗玉聲涓。',32,'全唐诗/poet.song.23000.json','["面挹晴光錦繡川，却臨蒼澗玉聲涓。", "逸民自有山中樂，不問山前令尹賢。"]'),
('3e6caff7-ede3-43a8-a70e-338f69aa4dee','留題分宜前山吳隠士白雲亭  其二','金君卿','宋','宋诗','song-poetry','','[]','江上青山山上泉，酌泉烹茗白雲間。',32,'全唐诗/poet.song.23000.json','["江上青山山上泉，酌泉烹茗白雲間。", "長官不擾民無訟，共喜登臨一日閑。"]'),
('49fa2549-1a5b-436c-8142-2c7ed8e04fb8','水心亭分題','金君卿','宋','宋诗','song-poetry','','[]','雨脚新收晚照開，水心亭上一曾來。',32,'全唐诗/poet.song.23000.json','["雨脚新收晚照開，水心亭上一曾來。", "紅裙只解邀人醉，競折新荷當酒杯。"]'),
('5ea560dc-6a28-4436-a577-9d1bc9418f4e','金沙亭','金君卿','宋','宋诗','song-poetry','','[]','亭闞方池物物新，花中名品富長春。',32,'全唐诗/poet.song.23000.json','["亭闞方池物物新，花中名品富長春。", "詩僧用意栽培處，四季常教有主人。"]'),
('78590dd1-bd44-4fbc-a2a7-f3e54835d990','五色雀','金君卿','宋','宋诗','song-poetry','','[]','晨氛澄霽海風調，綵絢珍禽入絳霄。',32,'全唐诗/poet.song.23000.json','["晨氛澄霽海風調，綵絢珍禽入絳霄。", "聞說舜庭方作樂，可容飛舞聽簫韶。"]'),
('ef7de928-6809-46b2-94c9-b476bae25b54','義烏','金君卿','宋','宋诗','song-poetry','','[]','徒知感義海邊州，未效精衷已白頭。',32,'全唐诗/poet.song.23000.json','["徒知感義海邊州，未效精衷已白頭。", "苑囿清陰無限好，棲身容借一枝不。"]'),
('60af2d94-6f8d-4165-bdae-7b45245c31ca','贈南華拱禪師','金君卿','宋','宋诗','song-poetry','','[]','祖葉彫零四百年，法燈今見拱師傳。',32,'全唐诗/poet.song.23000.json','["祖葉彫零四百年，法燈今見拱師傳。", "堂頭海會僧三百，晝課蓮經暮叩禪。"]'),
('edf4dc71-a55c-4ebe-afc0-58d24e8ee496','池亭避暑','金君卿','宋','宋诗','song-poetry','','[]','新花猶未出圓荷，月射風翻卷翠波。',32,'全唐诗/poet.song.23000.json','["新花猶未出圓荷，月射風翻卷翠波。", "對酒强須通夕醉，暑天清景此爲多。"]'),
('3a76b47a-da4f-4fff-bee7-0e97f0d0c8e4','和張公達端見寄','金君卿','宋','宋诗','song-poetry','','[]','殷勤寄語張夫子，休愛三山勝處遊。',32,'全唐诗/poet.song.23000.json','["殷勤寄語張夫子，休愛三山勝處遊。", "聞說詔書催入覲，便須飛步上鼇頭。"]'),
('634c4504-11d5-40cc-b51d-a89f28aea8a4','和康甫兄見寄','金君卿','宋','宋诗','song-poetry','','[]','夢想南亭倚翠岑，手栽松竹已成陰。',32,'全唐诗/poet.song.23000.json','["夢想南亭倚翠岑，手栽松竹已成陰。", "白雲不是無留意，出得山來四海心。"]'),
('76f73d01-4726-4172-b3a8-34374e0424d0','李白墳','金君卿','宋','宋诗','song-poetry','','[]','謝公山下見孤墳，下闞平江萬頃雲。',32,'全唐诗/poet.song.23000.json','["謝公山下見孤墳，下闞平江萬頃雲。", "盡日艤舟空悵望，謫仙風骨在遺文。"]'),
('416bf70c-f608-4294-9822-649b80ddef87','偶書茭湖院','金君卿','宋','宋诗','song-poetry','','[]','波漾晴光入戶庭，隔湖煙掃髻螺青。',32,'全唐诗/poet.song.23000.json','["波漾晴光入戶庭，隔湖煙掃髻螺青。", "老僧猶厭當官道，面壁焚香晝誦經。"]'),
('00ede28e-b731-431b-9269-7871d873c9c2','贈成祕校','金君卿','宋','宋诗','song-poetry','','[]','四門嵓下一翹英，滿腹詩書學已成。',32,'全唐诗/poet.song.23000.json','["四門嵓下一翹英，滿腹詩書學已成。", "講義羣庠初應辟，絳帷羅列盡諸生。"]'),
('2c0ab2ab-fa1d-49c6-8675-0812fb346412','病起','金君卿','宋','宋诗','song-poetry','','[]','黄祖城邊下石船，蕉林暗地雨如煙。',32,'全唐诗/poet.song.23000.json','["黄祖城邊下石船，蕉林暗地雨如煙。", "只知問俗求民瘼，却愧經旬卧瘴天。"]'),
('b974a969-7c17-497e-9980-5660963ba7a3','金竹峯','金君卿','宋','宋诗','song-poetry','','[]','重重巖崿插晴空，雲際叢開菡萏峯。',32,'全唐诗/poet.song.23000.json','["重重巖崿插晴空，雲際叢開菡萏峯。", "疑是葛仙歸洞府，移將江上九芙蓉。"]'),
('33b77536-159c-47a2-8aa6-12a151ee6d26','大雲倉阻風','金君卿','宋','宋诗','song-poetry','','[]','走越遊梁萬里回，却臨江渡已殘梅。',32,'全唐诗/poet.song.23000.json','["走越遊梁萬里回，却臨江渡已殘梅。", "歸帆未落青溪尾，雲壓寒風水面來。"]'),
('edfd9c37-b909-4d8b-a2dd-6d117a1ecf1b','石','金君卿','宋','宋诗','song-poetry','','[]','地隘風波勢已驚，更容頑險暗中傾。',32,'全唐诗/poet.song.23000.json','["地隘風波勢已驚，更容頑險暗中傾。", "自嗟忠信猶防患，却任舟人委曲行。"]'),
('6f6aae1d-be06-48d8-9b88-6fee77ab5d28','披襟臺','金君卿','宋','宋诗','song-poetry','','[]','紫微行樂不到處，絕勝何人共賞心。',32,'全唐诗/poet.song.23000.json','["紫微行樂不到處，絕勝何人共賞心。", "況是難逢開口笑，强須携手一披襟。"]'),
('6b94be4e-0b7a-4087-b95b-9354eda97208','留應聖宮','金君卿','宋','宋诗','song-poetry','','[]','松掃醮壇青羽蓋，杉圍精館碧油幢。',32,'全唐诗/poet.song.23000.json','["松掃醮壇青羽蓋，杉圍精館碧油幢。", "葛張二老今何許，雲外歸來鶴一雙。"]'),
('2edbe278-380e-431d-ac39-42de459ed7c5','題晞上人齊物堂','金君卿','宋','宋诗','song-poetry','','[]','莫論西竺與南華，了得真筌只一家。',32,'全唐诗/poet.song.23000.json','["莫論西竺與南華，了得真筌只一家。", "聲色外來無物我，茫茫名利是空花。"]'),
('81b14d23-d4c9-4fb5-a8c7-cc886ab9a80d','題公定兄滴翠亭','金君卿','宋','宋诗','song-poetry','','[]','數岫翠嵐濃欲滴，一軒靜境闃無塵。',32,'全唐诗/poet.song.23000.json','["數岫翠嵐濃欲滴，一軒靜境闃無塵。", "暑風滿枕日高起，誰識羲皇傲世人。"]'),
('912dd5a7-d9be-41ef-8b4a-49f64245000d','真珠亭','金君卿','宋','宋诗','song-poetry','','[]','新寺回廊入翠微，亭前珠樹鬭芳菲。',32,'全唐诗/poet.song.23000.json','["新寺回廊入翠微，亭前珠樹鬭芳菲。", "寄言遊者休披採，還似人懷薏苡歸。"]'),
('5b270b6d-79bc-4d8f-a4f8-bf2172bf9382','池州','金君卿','宋','宋诗','song-poetry','','[]','秋浦南邊絕點埃，碧圍煙嶂一屏開。',32,'全唐诗/poet.song.23000.json','["秋浦南邊絕點埃，碧圍煙嶂一屏開。", "當時小杜行吟處，重見高陽騎從來。"]'),
('ac911823-1615-424c-b7f9-0aed243b8e4e','晚過黄池村','金君卿','宋','宋诗','song-poetry','','[]','輕風剪煙素，繩繩縈嵓阿。',72,'全唐诗/poet.song.23000.json','["輕風剪煙素，繩繩縈嵓阿。", "白鳥相間飛，野容秋外多。", "頹日忽返照，霎若春氣和。", "驚帆無落勢，又欲衝除過。", "水行本善利，一葦安如梭。", "却笑利名途，甚矣風中波。"]'),
('1ce75da7-68a4-49d2-a6cc-5a2af3b5e55d','和人憫道傍凍餒者','金君卿','宋','宋诗','song-poetry','','[]','天意正成物，民心猶怨寒。',48,'全唐诗/poet.song.23000.json','["天意正成物，民心猶怨寒。", "風霜草木死，田野稻粱乾。", "何謂耕桑者，而無衣褐完。", "因思餌胡費，把筆謾悲酸。"]'),
('69a30e38-26c7-4a50-8806-a69a5e065521','興慶池禊宴','宋宏','宋','宋诗','song-poetry','','[]','名臣臨俊域，和氣□芳春。',48,'全唐诗/poet.song.23000.json','["名臣臨俊域，和氣□芳春。", "禊飲傳佳節，時賢冠上賓。", "綠波浮畫舸，芳草染朱輪。", "行樂有仁政，歡聲沸水濱。"]'),
('33c08223-9927-4e0e-bb37-2802cf95a93f','遊嶽','羅道成','宋','宋诗','song-poetry','','[]','因思靈秀偶來遊，碧玉寒堆萬疊秋。',32,'全唐诗/poet.song.23000.json','["因思靈秀偶來遊，碧玉寒堆萬疊秋。", "直上太山高處望，根盤連接十餘州。"]'),
('6378e44e-d05f-4c0b-a857-c3634d4278af','自和','羅道成','宋','宋诗','song-poetry','','[]','水雲蹤跡自閒遊，夏谷陰寒冷勝秋。',32,'全唐诗/poet.song.23000.json','["水雲蹤跡自閒遊，夏谷陰寒冷勝秋。", "猿鳥性情猶戀舊，翻身却去海邊州。"]'),
('32df4b43-8f57-4543-8fef-add5809eaebf','投郭主簿','羅道成','宋','宋诗','song-poetry','','[]','白騾代步若奔雲，閑人所至留詩迹。',32,'全唐诗/poet.song.23000.json','["白騾代步若奔雲，閑人所至留詩迹。", "欲知名姓同源流，請看郴陽山下石。"]'),
('226449b1-def9-421f-9e44-b2739a0ff2ea','上巳日興慶池禊宴','楊初平','宋','宋诗','song-poetry','','[]','照坐壺冰寒凜凜，北斗揮漿均祓飲。',64,'全唐诗/poet.song.23000.json','["照坐壺冰寒凜凜，北斗揮漿均祓飲。", "興慶池頭春色濃，亂柳摇金花罩錦。", "雕章麗藻俱時才，落筆頌歌兩兩台。", "府公莫惜玉山醉，明日天綸鳳詔來。"]'),
('4477b36c-2bea-4979-8cc8-3d72ad23e55b','玉泉洞','黄非熊','宋','宋诗','song-poetry','','[]','百尺寒泉潄玉鳴，洞門斜入石廊橫。',64,'全唐诗/poet.song.23000.json','["百尺寒泉潄玉鳴，洞門斜入石廊橫。", "烟霞不改古今色，山水無閒朝暮聲。", "窺洞野猿懸樹立，驚人呦鹿上巖行。", "有時寫盡琴中趣，風定千林月正明。"]'),
('42a05b5f-97c3-4bf7-b3f3-6cb45ece5892','瑞松塢','黄非熊','宋','宋诗','song-poetry','','[]','誰種靈松近佛家，根盤深塢鬭獰蛇。',64,'全唐诗/poet.song.23000.json','["誰種靈松近佛家，根盤深塢鬭獰蛇。", "風吹碧落雙龍動，月照黄昏兩蓋斜。", "千里雨聲喧洞壑，半空清影浸雲霞。", "山僧長日頻來賞，只恐春來起爪牙。"]'),
('731dbe18-3ea7-48a3-8851-1888a1c47177','望仙臺','黄非熊','宋','宋诗','song-poetry','','[]','臺前高嶽宅神仙，疊石誅茅對碧巔。',64,'全唐诗/poet.song.23000.json','["臺前高嶽宅神仙，疊石誅茅對碧巔。", "雲霧不分人去路，管絃長動雨來天。", "彩鸞呼侶歸殘照，野鶴□□下紫烟。", "誰識蟠桃最深處，劉郎風骨已雙全。"]'),
('2a87bf3f-b960-4ae4-93f6-f1bd628e4d99','龍樹巖','黄非熊','宋','宋诗','song-poetry','','[]','碧巖孤立嘯□峯，高狀藤蘿十里松。',64,'全唐诗/poet.song.23000.json','["碧巖孤立嘯□峯，高狀藤蘿十里松。", "三面石山橫疊嶂，一株松樹倒蟠龍。", "風雷聒地濤聲烈，日月摩空翠影重。", "憑仗高僧好珍重，看他雷雨化靈蹤。"]'),
('13fee059-d20f-49d9-a04a-ff54db84783e','龍尾泉','黄非熊','宋','宋诗','song-poetry','','[]','龍頭何在尾猶存，定向天中飲漢源。',64,'全唐诗/poet.song.23000.json','["龍頭何在尾猶存，定向天中飲漢源。", "且注靈泉清洞府，未呵甘雨活乾坤。", "半空飛下珠千顆，平地澄來玉一盆。", "寂寞雲山非我宅，九霄高處是吾門。"]'),
('a6489162-2d7f-4fed-a0c0-5b5793c65eb6','鐘磬石','黄非熊','宋','宋诗','song-poetry','','[]','一雙鐘磬本天成，垂在雲中左右屏。',64,'全唐诗/poet.song.23000.json','["一雙鐘磬本天成，垂在雲中左右屏。", "平地望來分大小，上方敲處震雷霆。", "名從得後聲還異，景欲彰時物自靈。", "幾度夜深催月落，滿林妖怪立泉扃。"]'),
('10916cd9-1a3f-4490-8c3d-cb41c8882b73','聽泉巖','黄非熊','宋','宋诗','song-poetry','','[]','萬瀨澄空天地秋，清音不斷下悠悠。',64,'全唐诗/poet.song.23000.json','["萬瀨澄空天地秋，清音不斷下悠悠。", "山前一片月留影，石上幾番僧白頭。", "未必素琴方理性，何須芳草始忘憂。", "堪嗤朝市區區者，祗聽笙歌醉則休。"]'),
('1f24b3c4-64d8-42ae-a6b0-35bbeb11fe75','靈羊窟','黄非熊','宋','宋诗','song-poetry','','[]','靈羊別去幾何春，尚有懸巖舊窟存。',64,'全唐诗/poet.song.23000.json','["靈羊別去幾何春，尚有懸巖舊窟存。", "左右莫知歸穴路，高低惟見去蹄痕。", "千尋飛瀑垂峯頂，一洞寒雲鎖石門。", "好是月明羣籟寂，幾聲閒答樹頭猿。"]'),
('7442602e-5530-4b56-bec9-89a299880c94','清音洞','黄非熊','宋','宋诗','song-poetry','','[]','羣山如削水如澠，一洞清音氣味凝。',64,'全唐诗/poet.song.23000.json','["羣山如削水如澠，一洞清音氣味凝。", "風送松聲歸遠壑，日移猿影下垂藤。", "林僧倚杖看泉脈，野客橫琴坐石稜。", "回首碧巖鐘動處，雲臺猶在最高層。"]'),
('ce70694f-9e70-4bc2-9d1e-ce768edd7928','瀑布泉','黄非熊','宋','宋诗','song-poetry','','[]','萬丈巖頭瀑布垂，玉泉拖地雪霏霏。',64,'全唐诗/poet.song.23000.json','["萬丈巖頭瀑布垂，玉泉拖地雪霏霏。", "聽來如訝青天漏，望去還驚白練飛。", "一洞清音喧碧落，千巖寒色逗斜暉。", "終歸大海成波浪，權借山僧濯布衣。"]'),
('a60472f1-55f0-4f5a-b987-ff675d36505f','瓊花圖','陳孚','宋','宋诗','song-poetry','','[]','荒棘萋萋后土宮，芳根已逐彩雲空。',32,'全唐诗/poet.song.23000.json','["荒棘萋萋后土宮，芳根已逐彩雲空。", "男兒別有揚州淚，不爲瓊花滴曉風。"]'),
('006b2ab2-004d-42c8-b252-8e17268380f4','呂翁祠','陳孚','宋','宋诗','song-poetry','','[]','山形天矯蒼精劍，日氣曈曚紫磨丹。',32,'全唐诗/poet.song.23000.json','["山形天矯蒼精劍，日氣曈曚紫磨丹。", "度盡世人人不識，青煙起處是邯鄲。"]'),
('70ef597e-66f8-47b7-b289-ce5b296d8b1d','龍隠巖','張田','宋','宋诗','song-poetry','','[]','龍隠晦冥時莫考，龍驤拏攫迹堪驚。',64,'全唐诗/poet.song.23000.json','["龍隠晦冥時莫考，龍驤拏攫迹堪驚。", "孔明久卧養全德，老子忽飛歸太清。", "溪上一天常氣勝，洞中六月自寒生。", "至人不得無情處，甘澤年年酒百城。"]'),
('014b4a84-a0c6-4d18-98d8-2f0db4f12c35','垂虹亭','錢明逸','宋','宋诗','song-poetry','','[]','千里波平瑟瑟風，纖雲不解翳虛空。',32,'全唐诗/poet.song.23000.json','["千里波平瑟瑟風，纖雲不解翳虛空。", "素娥自有清光在，上下清明一鑑中。"]'),
('b428585a-8996-4c22-9813-cc5a30aa0bb8','奉別堯夫先生承見留數刻漬梅酒磨沈水飲別聊書代謝','李中師','宋','宋诗','song-poetry','','[]','磨湯漬酒重分携，景霽風和二月時。',32,'全唐诗/poet.song.23000.json','["磨湯漬酒重分携，景霽風和二月時。", "莫忘天津別君處，黄梅庭下半離披。"]'),
('5c98d21d-6ddc-4fbe-ba2b-1e5301a28d6b','送程給事知越州','李中師','宋','宋诗','song-poetry','','[]','出藩寵進白雲司，臺札仍欣得告歸。',194,'全唐诗/poet.song.23000.json','["出藩寵進白雲司，臺札仍欣得告歸。", "蘇子佩虎鈕，腰龜緺，列城旗鼓隨高牙。", "蘭亭一水近館娃，乃今衣繡先過家。", "秋風從此生蒹葭，舟五百里行荷花。", "西陵渡口曉㟏谺，飛樓想到期及瓜。", "恩先甘雨滿菑畬，訟逐筆止庭不譁。", "秦山千仞高無加，晝望蓬萊挹仙霞。", "鑑湖萬頃淼無涯，夜看牛斗乘星槎。", "平林摘筍崖擷茶，酒胾泉美而魚嘉。", "醒吟醉墨鬭天葩，此樂未可歲月賒。", "玉皇赭案香飄斜，匹馬赴召且復撾。", "民貧惠政空歎嗟，重見尨眉出若邪。"]'),
('59bec322-ca68-454d-a720-e0871de40ef4','遇便風','陳舜俞','宋','宋诗','song-poetry','','[]','舳艫泝隋堤，積潦涵楚甸。',204,'全唐诗/poet.song.23000.json','["舳艫泝隋堤，積潦涵楚甸。", "大帆挂長檣，薰飈借良便。", "氣張中軍旗，勢疾强弩箭。", "浪頭噴飛雪，波心落流電。", "或如春雷振，又若疾雨濺。", "天空文鷁歸，珠媚淵龍戰。", "久來去意切，幸此行色變。", "舟子嘯引項，挽夫喜盈面。", "揭篙無施勞，躍馬莫我先。", "行吁思景附，坐指交勇羨。", "日陰未頃刻，道里歷宇縣。", "津亭倏渡淮，官堠俄入汴。", "盛夏草樹齊，遠水蘋藻遍。", "晚景稍可愛，少瞬不再見。", "我非欲速者，疾目憎轉眩。", "衣袂聊虛凉，心焉獨安宴。", "向夕風少休，遲留樂幽睠。"]'),
('bd14fe6a-338d-4adf-861f-ba60c759548c','失題','陳舜俞','宋','宋诗','song-poetry','','[]','昔見淮水清，今見淮水渾。',204,'全唐诗/poet.song.23000.json','["昔見淮水清，今見淮水渾。", "問之何因爾，淮吏謂予言。", "此淮出桐柏，彼汴來崑崙。", "年年相合流，東望滄溟奔。", "汴入淮而清，有若淮水尊。", "風休一色靜，古鑒磨無痕。", "今年淮水小，僅能庇龜黿。", "黄河從春來，桃花注龍門。", "滔滔朝宗勢，巨浪日夕煩。", "小清納大濁，勢不得自存。", "崩騰一波走，磅礴泥沙噴。", "我聞吏之言，冥默竊自論。", "君子潔履操，小人爲詐謾。", "姦豪爍危行，烈火燎于原。", "譁言污正論，青蠅止于樊。", "中人可移性，鮮克始終惇。", "夙夜念淮水，清心大吾源。"]'),
('01bdbabe-5a05-4a5c-b8c6-64de49fdf431','中秋翫月宴友','陳舜俞','宋','宋诗','song-poetry','','[]','秋風清且勁，夜月澄無譁。',288,'全唐诗/poet.song.23000.json','["秋風清且勁，夜月澄無譁。", "月當澄清間，百倍常光華。", "金盤挂滉瀁，水鑒磨痕瑕。", "未離碧海久，漸到黄道斜。", "嫦娥瓊肌滑，羞死吳宮娃。", "蟾蜍銀窟寒，不穴死水蟆。", "依稀聞兔搗，髣像見桂花。", "豈止數千里，已照萬人家。", "都人尤侈盛，時節惜芳佳。", "樓臺延皓魄，簾幕去周遮。", "交錯宴子女，嘈雜鳴簫笳。", "清影落酒盞，爽氣侵巾紗。", "常明復置燭，擲果如散沙。", "而我旅其間，甚貧亦可嗟。", "遂召朋友云，可飲文字耶。", "客來俄滿堂，風稜森鏌鋣。", "主人出對客，衰病植蒹葭。", "所共天上景，能如富者奢。", "汙樽薦醅蟻，獠羞錯魚蝦。", "釋焉帽與带，果止柰與瓜。", "高言抗崢嶸，沖靈坦凹窊。", "情親弗委曲，論極成紛挐。", "寒稜入吟骨，歡意自天涯。", "不因斗柄轉，豈信漏刻賒。"]'),
('36c19789-5ea3-4f54-9325-32d51050cb19','種梅','陳舜俞','宋','宋诗','song-poetry','','[]','始我窺山中，早與梅花期。',156,'全唐诗/poet.song.23000.json','["始我窺山中，早與梅花期。", "低回遂四十，種樹計已遲。", "樵夫致遠枿，園官送新枝。", "故土謹包裹，深根屢培滋。", "連宵霢霂雨，迨此初陽時。", "繞徑一百樹，撫視如嬰兒。", "古來橫斜影，老去乃崛奇。", "嗟爾生也晚，笑我行且衰。", "世人非金石，或作千年資。", "轉眼共零落，較此不更癡。", "有情且寓賞，勿著喜與悲。", "青赤粲點白，一笑唱吾詩。", "百年霜雪過，好者知爲誰。"]'),
('1a8cb582-6fbb-446b-bf1e-404a8e7ac3e9','公署井詩','陳舜俞','宋','宋诗','song-poetry','','[]','老屋蔭大井，置綆百尺修。',132,'全唐诗/poet.song.23000.json','["老屋蔭大井，置綆百尺修。", "疏鑿不知年，人其古諸侯。", "源從卞山來，涓涓無時休。", "旱地千里赤，淵泉獨清浮。", "六月如焰火，寒冽冰雪侔。", "萬家濱雙溪，卓此名一州。", "纍纍挈瓶人，踵門日見投。", "賓至遽欲起，命酌輒復留。", "豈不敵醍醐，渴疾飲以瘳。", "庠序闕講問，闇淺誰予求。", "自反對井德，飲水良可羞。"]'),
('d7134099-3a88-4098-9013-dd7c3eeae722','桃花塢','陳舜俞','宋','宋诗','song-poetry','','[]','路轉青山曲，地暖留青春。',60,'全唐诗/poet.song.23000.json','["路轉青山曲，地暖留青春。", "昔聞千樹桃，香艷紅氤氳。", "遊子想神仙，花下啼鳥馴。", "于今空蔓草，况復種桃人。", "唯應塢中月，清光無故新。"]'),
('cf19b23d-fb16-4011-a9e2-d094c1b7354d','餞張郎中','陳舜俞','宋','宋诗','song-poetry','','[]','莫愛卞山色，莫羨苕水清。',120,'全唐诗/poet.song.23000.json','["莫愛卞山色，莫羨苕水清。", "山高天早寒，水深潛浪生。", "維此賢丈人，宇韵和且平。", "冷清窅無威，妍詞吐春英。", "衆人翫其華，君子挹中情。", "愷悌神所勞，假樂眉壽并。", "安車省家園，華艾立兒甥。", "邦君示尊禮，宴衎既豐盈。", "言還湖上居，載酒餞東城。", "賓醉可復訴，貴老事非輕。"]'),
('e52ef1f4-67fb-495e-b080-7c41ad95a38c','送詩僧惠師','陳舜俞','宋','宋诗','song-poetry','','[]','蕭然林下人，病骨霜松槁。',96,'全唐诗/poet.song.23000.json','["蕭然林下人，病骨霜松槁。", "若爲詩家流，力壓古人倒。", "琢句如琢玉，得之若得寶。", "有時到極摯，直可補元造。", "平生樂此樂，白頭不知老。", "數年吳楚游，詠遍泉石好。", "却懷鍾山隠，鄉思滿春草。", "橐中何以歸，篇篇有留藁。"]'),
('5a0f30ca-fb7b-4ea9-afa9-f66067ccde59','采芑詩','陳舜俞','宋','宋诗','song-poetry','','[]','采采原上芑，盈襜不知多。',72,'全唐诗/poet.song.23000.json','["采采原上芑，盈襜不知多。", "惜共藜藿稱，命與羹糝和。", "值此行役間，遺餘雜蓁莪。", "京洛誇肥甘，掇擷繄誰何。", "休官業已定，不待此首皤。", "年年春物繁，期爾山之阿。"]'),
('3cac3cb4-33ba-4c81-ade4-313c2cc5d97b','野燒','陳舜俞','宋','宋诗','song-poetry','','[]','急燒山上草，莫顧山下木。',84,'全唐诗/poet.song.23000.json','["急燒山上草，莫顧山下木。", "燒草得地美，欲種來歲粟。", "乘風縱巨燎，烈烈遍巖谷。", "既不問玉石，何暇愛麛鹿。", "寄謝種粟翁，乘時擇嘉穀。", "無俾稂莠俱，還見故草綠。", "棟材已灰燼，著意規飽腹。"]'),
('ffc02bc6-7bfe-4399-acd1-e6aa5313b819','廉溪','陳舜俞','宋','宋诗','song-poetry','','[]','豈無城中居，高牆圍大屋。',144,'全唐诗/poet.song.23000.json','["豈無城中居，高牆圍大屋。", "愛此原野間，山靜溪水綠。", "人家買良田，歲取十千穀。", "我耕山下土，所獲亦以足。", "藜羹佐淵魚，晨炊買樵木。", "客來好風日，濁酒醉籬菊。", "主人去微官，歸意常欲速。", "畫圖隨行李，林囿日在目。", "公卿爲之賦，佳句滿瑶軸。", "年來請便郡，旦暮戒童僕。", "乘霜歸荒徑，趁雨添新斸。", "應恨公未歸，公貧猶待祿。"]'),
('f2768d1f-878b-4022-8d75-053e7a214b79','寄揚州知府錢舍人','陳舜俞','宋','宋诗','song-poetry','','[]','歲月倏已逝，流光浩無涯。',120,'全唐诗/poet.song.23000.json','["歲月倏已逝，流光浩無涯。", "新陽達厚地，草木漸萌芽。", "禽鳥知時節，聲哢日夕嘉。", "人生獨何爲，不與物同華。", "齒髪俱摇落，唯有老大加。", "緬懷西垣客，事業紛天葩。", "三年辭帝右，士夫嘆聱牙。", "道大益不容，眇小固何嗟。", "聞有難老藥，沆瀣和丹砂。", "但願壽百歲，未能定龍蛇。"]'),
('8977b432-f2cf-48ee-890d-545e85bc454c','靈祐觀','陳舜俞','宋','宋诗','song-poetry','','[]','緬彼幽虛天，曾是衆仙囿。',156,'全唐诗/poet.song.23000.json','["緬彼幽虛天，曾是衆仙囿。", "宮祠宅來儀，紺瓦覆蒼甃。", "窗扉秘環佩，几席被文繡。", "傳聞祀禱神，祠宮燦如晝。", "樵蘇避山村，草木長疏秀。", "祥符聖天子，慕道比軒后。", "縣官典修完，錫名揭靈祐。", "星璫捧金龍，沉以玉簡副。", "邇來三十年，寂寞事非舊。", "黄冠守蕭堂，香火雜薪槱。", "神州祠太乙，司農治華構。", "休祥祚邦國，巖穴甘僻陋。", "游人獨何求，豐碑讀古籀。"]'),
('8216e642-008e-4ea5-8cbb-3b5c54f41ee7','保聖院','陳舜俞','宋','宋诗','song-poetry','','[]','門深鎖蒼苔，地靈育嘉樹。',36,'全唐诗/poet.song.23000.json','["門深鎖蒼苔，地靈育嘉樹。", "寂然烟雲宅，不接市朝路。", "苟能灰心居，即是古樂處。"]'),
('df051f94-d4ae-43f1-893a-0c1fd3bde103','贈孔經甫賢良兼簡許少張狀元','陳舜俞','宋','宋诗','song-poetry','','[]','晚泊姑孰浦，忽逢瀟湘人。',192,'全唐诗/poet.song.23000.json','["晚泊姑孰浦，忽逢瀟湘人。", "口稱丹邱客，面带湘江雲。", "此客骨不凡，九天之麒麟。", "新上紫烟頂，以頭觸天門。", "赤龍怒當路，夭矯驚百神。", "麒麟顧何力，牙爪勇踞蹲。", "既欲掎其角，又或批其鱗。", "此身甘萬死，齏粉不逡巡。", "帝曰汝無罪，濯濯良不群。", "輟吾黄金鋪，縱之赤城塵。", "收頭縮下土，別待風雷春。", "龍怒逐之去，四海波濤翻。", "顧我天一涯，遺下顔色溫。", "昔爲游天夢，嘗受一日恩。", "老來因對客，念往驚心魂。", "寄謝剡溪子，入朝可無言。"]'),
('5fa89767-d067-4410-8a80-0cc635f4e51d','寄虔州東禪惠長老','陳舜俞','宋','宋诗','song-poetry','','[]','山僧未識面，遠想何瀟灑。',96,'全唐诗/poet.song.23000.json','["山僧未識面，遠想何瀟灑。", "客從贛上來，肯可必儒雅。", "學詩擬柴桑，陳編長在把。", "冥搜得佳句，沖淡相上下。", "由來淵源遠，知解妙空假。", "史君固好善，公餘枉車馬。", "玄談閒清吟，至樂匪尊斝。", "借問歲早晚，重修遠公社。"]'),
('f1880793-3c07-40f6-9b58-def8dfce49e1','次韵酬郟郎中','陳舜俞','宋','宋诗','song-poetry','','[]','直道焉不黜，士生常苦貧。',288,'全唐诗/poet.song.23000.json','["直道焉不黜，士生常苦貧。", "此語聞則舊，今見賢丈人。", "三十取科第，初走州縣塵。", "清不受一毫，義或重萬鈞。", "四十雖宦達，五十已邅屯。", "有如車脫輻，挽之又埋輪。", "南棲窮山中，茅屋無比鄰。", "瘦田兩三稜，過半生荆榛。", "年豐苦不飽，况復水旱頻。", "予常訪其居，會合歡無垠。", "念此太幽獨，欲去彌傷神。", "勸君胡不歸，清霅多交親。", "旋聞理艅艎，送之彭蠡濱。", "今來復相過，三見汀洲春。", "雖云故鄉樂，還似枯池鱗。", "僧坊避風雨，所頼太守仁。", "隨衣度伏臘，計俸紓晡晨。", "無妻眠抱影，失子淚沾巾。", "穹蒼杳難知，善人獨不振。", "公懷自曠達，陶然樂天鈞。", "作詩擬淵明，委形任屈伸。", "所喜樽有酒，且樂圃有筠。", "我思得高義，列鼎鋪重茵。", "館之華堂上，歲與禾百囷。"]'),
('99520b13-0961-47e0-8774-5e70028fcfb5','東臺','陳舜俞','宋','宋诗','song-poetry','','[]','築臺俯園木，亦既覆華宇。',192,'全唐诗/poet.song.23000.json','["築臺俯園木，亦既覆華宇。", "主翁達生者，作詩牓門戶。", "謂臺乃主人，吾身同逆旅。", "臺還謂公言，無易浪稱與。", "天地猶大塊，况此一抔土。", "我昔未爲臺，蟻垤動欲雨。", "翁欲事畚築，金鎚莫論堵。", "軒陛因冠带，松筠漸儔侶。", "萬物固何常，今日乃前古。", "高岸化深谷，白波起桑圃。", "短長雖有間，相去能幾許。", "翁閒賓客至，只此見芳醑。", "翁仁妻孥樂，且以饌肥羜。", "高明照圖史，啟塞順寒暑。", "鄙夫不能此，蟋蟀賦其除。", "臺公默相忘，勿復問賓主。"]'),
('db1439b6-95dc-4525-b053-33a802cdd7c1','贈劉道原','陳舜俞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','三年江湖上，得友唯道原。',228,'全唐诗/poet.song.23000.json','["三年江湖上，得友唯道原。", "少小負英特，誦書日萬言。", "長好史氏學，執筆以專門。", "廢興數千載，抵掌洪河翻。", "潔身比夷齊，見義勇育賁。", "唯不善玄解，惡佛如仇冤。", "我雖異于此，知有學行尊。", "就之同霧露，貴之如瑶琨。", "共爲廬山游，移宿窮林園。", "水石最好處，盡日流清尊。", "所願聞高談，美若嘗熊蹯。", "夫子之故人，公台既調元。", "聞初學問時，幽蘭并芳蓀。", "及今議論乖，良弓對驚猿。", "雲泥成睽離，治亂空自論。", "古來用才者，如梓匠輪轅。", "短長無棄遺，同異非仇恩。", "何不付國史，置子西掖垣。", "我語雖鄙賤，幾欲叫天閽。"]'),
('79d1a881-9479-4492-bed8-e3610e96a409','湖州李使君聞予遊廬山寄書云爲我一謝清絕','陳舜俞','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u6d1e\u5ead\u6e56"]','道微本一致，喧靜偶殊轍。',120,'全唐诗/poet.song.23000.json','["道微本一致，喧靜偶殊轍。", "眷言朝廷士，何必山水悅。", "李侯稟靈氣，家園鄰大別。", "廬峰五千仞，曾上捫日月。", "一隨青雲友，久仕金馬闕。", "茲爲東南守，雙溪對寒潔。", "因將洞庭客，寄使謝清絕。", "想君惜不往，搔首厭符節。", "澤民固重事，逸興聊可輟。", "已告林屋天，金庭錫期耋。"]'),
('2721d3ff-78f6-4f9a-b12a-94544ec0601b','初入太湖','陳舜俞','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','東南有具區，三萬六千頃。',228,'全唐诗/poet.song.23000.json','["東南有具區，三萬六千頃。", "百川之雄偉，咸池借溟涬。", "玉堂在其下，莫知日月永。", "鴟夷昔不返，肯顧市朝請。", "素懷邈已勞，孤泛此方逞。", "刺沙出林荒，度淺動蘋荇。", "漸盡行漸遠，灣轉勢彌迥。", "疑非地可載，直與天作鏡。", "青空四垂幙，亂山不能屏。", "淼茫白鳥行，浩漾好雲影。", "邏呼十槳急，罛橫九帆並。", "霽中波有光，風後浪猶猛。", "澎湃聞乍愜，拋磕內還省。", "我量覺蹄涔，此身實萍梗。", "淵神慄寒肌，浸氣飄素領。", "觀瀾念往術，濯纓悼前眚。", "未能追高謝，且以卒流景。", "吟非誇獨清，濟乃仗中靜。", "寄謝洞庭君，終來老魚艇。"]'),
('989374ed-7684-47e6-8d82-a5fad6fcba76','霅溪','陳舜俞','宋','宋诗','song-poetry','','[]','吳王城下溪，疏鑿自開闢。',192,'全唐诗/poet.song.23000.json','["吳王城下溪，疏鑿自開闢。", "潭潭無涯岸，但見浸垂碧。", "氣增宇宙寬，勢吞江湖窄。", "樓臺照清影，河州多嘉植。", "紅鱗生霞朝，金鑒沉月夕。", "恍如神仙國，遠與塵土隔。", "怪說稔傳聞，真源探圖籍。", "天目據西南，兩地瀉峻極。", "其傍數百壑，奔走爲附益。", "及茲淵渟處，深不可計尺。", "稻粱活萬家，世無原田瘠。", "魚蝦孕千石，日見網罟獲。", "陰陰風雨夜，多爲蛟龍宅。", "少遊溪上學，長作幕下客。", "觀瀾無前志，平世耻吟澤。", "度量方潢汙，臨流重慚惜。"]'),
('40bb9493-38e1-4e7c-81c1-5dab71b55ec7','林屋洞','陳舜俞','宋','宋诗','song-poetry','','[]','洞天三十六，第九曰林屋。',204,'全唐诗/poet.song.23000.json','["洞天三十六，第九曰林屋。", "神仙固難名，瓌怪存記錄。", "曠歲懷尋賞，茲辰幸臨矚。", "馳神在真游，豈復惴深谷。", "解襪納芒履，燃松命光燭。", "初行已傴僂，漸入但匍匐。", "顧瞻避衝磕，渾淖沒手足。", "如此百餘步，始可立寓目。", "或垂若鐘簴，或植若旌纛。", "有如案而平，有類几而曲。", "鎸刻非人工，晶瑩粲黄玉。", "遥知竅穴外，定有金庭籙。", "凡肌不可往，叩擊安敢黷。", "鸞鳳無消息，但見白蝙蝠。", "却還望微明，既出猶喘促。", "沾衣憐石髓，孰悔泥塗辱。", "庶幾達微慕，養生相吾福。"]'),
('e11bc6b6-5fd7-4215-91eb-7303c854a32f','毛公壇','陳舜俞','宋','宋诗','song-poetry','','[]','古壇疊亂石，草木何參差。',180,'全唐诗/poet.song.23000.json','["古壇疊亂石，草木何參差。", "黄衣宇其傍，陳蹟刊豐碑。", "曰初劉真人，齒髮不可訾。", "但見紺綠毛，被體鬖鬖垂。", "雲軿一日去，空山留庭壝。", "弟子散巖谷，荆榛蔽荒基。", "晚有周息元，探訪親斬披。", "白鹿忽跪前，靈符見葳蕤。", "地勝人既偶，凝嚴起寶祠。", "束帛下幽聘，良馬維素絲。", "前朝揖高風，有美皮陸詩。", "迨今三百年，事去物亦隳。", "喬松委樵蘇，野蔓號狐狸。", "惟有鍊丹井，甘冽無等夷。", "一酌匪消渴，欽慕尚神禧。"]'),
('b10bb2a1-c99f-4984-b731-6dd5836c118c','松梢詩','陳舜俞','宋','宋诗','song-poetry','','[]','朽屋延暗暝，鑿明快吾魄。',180,'全唐诗/poet.song.23000.json','["朽屋延暗暝，鑿明快吾魄。", "西墉偶面勢，開牖遂生白。", "茲焉玩圖史，亦以置床簀。", "豈能來清風，猶苦對殘赫。", "炎天適暵旱，永暮坐燔炙。", "賓客何可處，兒女哀不獲。", "咨諏或獻詩，蓋覆乃其策。", "架木湊檐瓦，鋪竹施葦席。", "聊且紓暴酷，未足爲佳適。", "北山多喬松，倚天不知尺。", "綢繆星日暗，轇輵鬼神宅。", "棟梁尚匪材，枝葉固何益。", "敢告持利斧，斬伐遵指畫。", "束縛如見遺，無使曲傅直。", "此身得餘庇，陰德佩無斁。"]'),
('588bf220-d2d2-4d52-985b-b39bf48dba9c','楓橋詩','陳舜俞','宋','宋诗','song-poetry','','[]','二十送上鄉老書，白髮堂上懽愉愉。',208,'全唐诗/poet.song.23000.json','["二十送上鄉老書，白髮堂上懽愉愉。", "岐亭酒罷不忍別，二百餘里來姑蘇。", "楓橋古岸冬十月，霜風切骨草木枯。", "拜起欲去更付囑，携手泫然雙淚珠。", "明年偶中崇政第，赤城山下欣迎扶。", "穹蒼不與奪榮養，星霜未周罹明誅。", "顔色不見已三歲，肝血泣盡留形軀。", "隠淪無業養慈老，骫骳又作卑官圖。", "還道楓橋舊別地，依依風物春陽敷。", "人烟山色一如昨，齒髪獨改親則無。", "萬杵入心交落涕，水邊且欲留行艫。", "平生一天已無戴，縱得寸祿何爲娛。", "時乎窮達又未决，行矣願報生前劬。"]'),
('f698e174-2f32-470e-8d7d-7a1b55b3df64','貧女曲','陳舜俞','宋','宋诗','song-poetry','','[]','貧女四十無人問，不傅鉛華水梳鬢。',64,'全唐诗/poet.song.23000.json','["貧女四十無人問，不傅鉛華水梳鬢。", "非關顔色不如人，不肯出門羞失身。", "零落床頭舊機杼，池水漚麻還織布。", "布成不賣市中兒，金刀剪雪自裁衣。"]'),
('e72fb197-c18d-4b1f-a9bf-eed2cb25e88d','太湖一首和姚子張','陳舜俞','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖可漁山可樵，漁樵隠者非一朝。',128,'全唐诗/poet.song.23000.json','["太湖可漁山可樵，漁樵隠者非一朝。", "醉拍溟渤摩穹霄，歌詠周孔追松喬。", "故磯人歸今寂寥，秋空浪穩蘭爲橈。", "何爲不去走市朝，况無一策陳虞堯。", "嗟哉生事垂簞瓢，母齒豁豁群兒齠。", "啼寒悲饑如鴟鴞，古人以此嘗折腰。", "敢不歡喜祿下僚，滄浪有景直不遼。", "西風起時心摇摇，異日掉臂君可招。"]'),
('324bc9a5-cfd2-4f35-bf58-46e7fcd3e64b','三峽橋','陳舜俞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','銀河源源天上流，新秋織女望牽牛。',161,'全唐诗/poet.song.23000.json','["銀河源源天上流，新秋織女望牽牛。", "洪波欲渡渡不得，以鵲爲橋誠拙謀。", "胡不見廬山三峽水，此源亦接明河底。", "擘崖裂嶂何其雄，崩雷泄雲勢披靡。", "飛鳥難過虎豹愁，四時白雲吹不收。", "燭龍此地無行迹，六月遊子披貂裘。", "誰將巨斧鑿大石，突兀長橋跨蒼壁。", "行車走馬安如山，下視龍門任淙激。", "寄言牛女勿相疑，地下神工猶更奇。", "喚取河邊作橋棟，一年不必一佳期。"]'),
('7a696cec-06ef-4e37-9f9b-8457e6d93b86','騎牛歌','陳舜俞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我騎牛，君莫笑，人間萬事從吾好。',214,'全唐诗/poet.song.23000.json','["我騎牛，君莫笑，人間萬事從吾好。", "千金市骨駿馬來，乘肥大躍須年少。", "蒲爲韉，草爲轡，瀑布山前松徑裏。", "看山聽水要行遲，駐策緩驅塵不起。", "布袍葛带烏接䍦，山家裝束不時宜。", "匏樽注酒就背飲，縹囊貯書當角垂。", "吟或狂，醉欲倒，同醉同吟白雲老。", "此老不可天下人，一住廬山三十春。", "聲如鐘，目如電，七十神光射人面。", "上牛下牛不要扶，合與山中作畫圖。", "汴州馬上竟何如，春泥沒腹雨濺帽，夜半歸來人已痡。", "天真喪盡百憂集，衣食毛髪歸妻孥。", "爭如來騎牛，水光山色同悠悠。"]'),
('af0d2917-143b-41ca-96a4-80bb4d01b847','和部使者騎牛歌','陳舜俞','宋','宋诗','song-poetry','','[]','君平山前白雲老，五十休官何太早。',244,'全唐诗/poet.song.23000.json','["君平山前白雲老，五十休官何太早。", "咄哉官卑莫行道，鸞鳳豈肯爭粱稻。", "愛山愛水去無時，漸老更買黄牛騎。", "長髯老奴挈榼隨，白紵皎皎山人衣。", "因憐湖邊有逐客，也解忘形樂泉石。", "不使執轡從翁遊，翁自出錢爲買牛。", "山中酒美數醑我，醉裏詩成要我和。", "市兒指點應不識，底不輕裘走快馬。", "毛夫子，真國士，出問風謠宣直指。", "瀟灑本是神仙人，功名强爲蒼生起。", "聞說騎牛不詆訶，手擘紅箋爲作歌。", "英詞百卉鋪錦繡，雄辯三峽傾銀河。", "我牛入山路漸熟，好歌吟聲易成曲。", "明年恩亦當放還，直入深雲無管束。", "欠却劉家買牛黄金錢，又得毛公騎牛碧玉篇。"]'),
('223ad5c7-8fe4-4062-8c85-0a5dc60cbf9c','和劉道原騎牛歌','陳舜俞','宋','宋诗','song-poetry','','[]','陳子無能久棄廢，騎牛入山學遁世。',157,'全唐诗/poet.song.23000.json','["陳子無能久棄廢，騎牛入山學遁世。", "劉子有道憂天下，欲取相印乘駟馬。", "二子相逢湖水頭，進退兩忘俱未酬。", "長歌對市人，聞者應揶揄。", "君不見蔡澤不相終躍馬，甯戚未遇先飯牛。", "腰懸六黄印，廩食萬戶侯。", "人生顧何常，古來海水生柔桑。", "少華一峰已爲谷，白日西出明朝陽。", "男兒蓋棺事乃了，目睫榮悴空悲凉。", "水之曲，山之傍。", "歲窮且飲酒，富貴無相忘。"]'),
('408f8070-1b5f-476c-8add-9ac2195d2e25','送南康劉道純秀才起應新詔','陳舜俞','宋','宋诗','song-poetry','','[]','太平天子厭弊舊，盡解綱條重結紐。',160,'全唐诗/poet.song.23000.json','["太平天子厭弊舊，盡解綱條重結紐。", "一朝進士各名經，五百年來病聲偶。", "弟子增員巖穴空，博士獻書車馬走。", "鴻薄青冥昔在籠，魚憶滄浪今脫笱。", "乘時得志君其人，平生好學氣撞斗。", "詆訶毛鄭爲低眉，辨說儀秦不容口。", "本需束帛賁圭衡，勉應新書辭畎畝。", "時髦往往出江南，解褐須期居帝右。", "藏珍韜櫝元待價，搦矢撫弦須應手。", "勿學迂疏魯兩生，是古非今空白首。"]'),
('5b234a25-f5c7-480b-9c16-0c8b86d03ad5','贈通慧大師凈務','陳舜俞','宋','宋诗','song-poetry','','[]','鄱陽江頭逢道人，昔我先子遊從親。',234,'全唐诗/poet.song.23000.json','["鄱陽江頭逢道人，昔我先子遊從親。", "口誦先子詩，別來三十春。", "我悲不忍聽，泫然淚沾巾。", "道人見我少小日，嗟我老大空埃塵。", "我謂道人言，姑願有所陳。", "公孫希世董生逐，子貢結駟原憲貧。", "伯夷采薇避周粟，許由洗耳爲堯民。", "道雖有用舍，天實爲屈伸。", "子誠空門士，胡爲甘隠淪。", "邇來拔士到屠販，圈牢往往生麒麟。", "延英賜對不膜拜，下視羅什來姚秦。", "方袍騎馬使絕域，賀蘭山前無縉紳。", "如子固不羈，何不自化青雲身。", "今我迂疏不知返，悠悠如海空迷津。", "無錢買山廬峰下，行欲東來長水濱。", "子如厭世欲已矣，來寄瓶錫爲吾鄰。"]'),
('14529a32-ccc9-4e27-903d-f58b884c35d3','贈湖州使君李公擇','陳舜俞','宋','宋诗','song-poetry','','[]','李侯車騎匆匆出，前騶不鳴隨者急。',304,'全唐诗/poet.song.23000.json','["李侯車騎匆匆出，前騶不鳴隨者急。", "不遊臺沼不尋山，獨向城隅小蓬蓽。", "城隅蓬蓽謂誰家，太學先生賢已卒。", "老妻猶在八十餘，侯來爲問夫人疾。", "當時弟子猶五六，連袂追隨慎倉卒。", "手調湯藥進盂盤，勞問有無極纖悉。", "巷人來觀相歡喜，門外牆頭聞唧唧。", "我思康定慶曆間，天下文章極蕭瑟。", "讀書不復問義理，破碎幺麽入聲律。", "先生始出治庠序，輔養學者尊經術。", "自茲道義及生民，晚具纁黄起遺逸。", "先生今來骨爲土，名儒大義非前日。", "朝登壠坂暮高官，舊學前功付幽黜。", "往往昔遊苕霅人，詆諱不敢對以實。", "李侯自是江南士，不預吾徒舊堂室。", "尊德樂道乃精誠，念老嗟貧固其秩。", "魏文伏軾過西河，鄭公名鄉論高密。", "古來如君顧無幾，于今走利尤非匹。", "人言侯政如此多，試聽風謠百之一。"]'),
('367d3f98-9b51-4dce-af1d-fe198dcbc231','雙溪行','陳舜俞','宋','宋诗','song-poetry','','[]','星郎休官兩鬢白，慣作五侯堂上客。',278,'全唐诗/poet.song.23000.json','["星郎休官兩鬢白，慣作五侯堂上客。", "半入人家鎖深宅。", "偶來花幕雙溪頭，聞有侍兒舊相識。", "五馬情多載酒過，主人猶須屏障隔。", "黄昏移燭背重簾，初度清歌響疏拍。", "宛轉別是京洛聲，中有離愁千萬尺。", "曲中復作孤吹笛，玉龍一吟群籟寂。", "金罍不酌四座聽，淡月朦朧挂空碧。", "更將餘意寫琵琶，手抹鳳槽鳴歷歷。", "梁州欲徹幺絃斷，應恐外人知怨抑。", "主人不許傅青翼，獨聽星郎語近壁。", "小聲嗚咽話當年，公子樽前最憐惜。", "朱門出後身轉輕，往事消沉無處覓。", "星郎日有流落恨，回向玳筵雙淚滴。", "勸君收淚聽我歌，聚散有命可奈何。", "君不見隴頭水，入海不知幾千里。", "又不見風中花，吹向千家復萬家。", "人生莫作等閒別，事去老大空咨嗟。"]'),
('96a4f5e1-fc8a-43ba-acec-5c50803fb4d6','示諸弟','陳舜俞','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','吾家崛起蓬蒿間，先君爲學良苦艱。',160,'全唐诗/poet.song.23000.json','["吾家崛起蓬蒿間，先君爲學良苦艱。", "典衣買書教我讀，平生貧窶不此慳。", "歲晚纔霑寸祿養，天禍無何頹泰山。", "况時汝輩各少小，不及見汝學燕閒。", "逮今孤露歷歲月，漸覺長大成疏頑。", "詩書堆積有素業，文章體要亦易攀。", "固須仁義力造詣，慎擇朋友少往還。", "偏親堂上待甘旨，况已齒齔雙鬢班。", "更可踟躕忽榮養，不如烏鳥鳴關關。", "官家公道祿寒畯，勉旃進取歡慈顔。"]'),
('af9d44bc-e0f4-4519-b901-5474dda3c4c4','淮陰阻風讒風伯','陳舜俞','宋','宋诗','song-poetry','','[]','滔滔淮水，溢楚之疆。',256,'全唐诗/poet.song.23000.json','["滔滔淮水，溢楚之疆。", "原田其潴，城郭爲防。", "浸以廣兮不可涉，浩乎險兮不可航。", "粵有行者，欲泝其央。", "編莞爲帆，植木爲檣。", "幸飄風以憑乘，遂吾歸而徜徉。", "爾風謂何，不自西北，阻我攸往。", "維伯是職，悠悠水濱，奚獨予留。", "有百其役，若千其艘。", "粟麥兮中都之餉饋，布帛兮赤縣之衣裘。", "府臣引領以僂指，挽夫坐糧而寢餱。", "伯復不知，天子聖神，以民爲憂。", "聞此方國，常墊橫流。", "分筆舌于嚴署，咨瘡痏于諸侯。", "有淑使者，仁豐義脩。", "體上所囑，同辭合謀。", "今此欲往，會于道周。", "倡和出話，下民以休。", "風之不遂，非伯誰尤。", "上帝可訴，讒言孔庶。", "將伯是怒，不如風兮命之去。"]'),
('658d54f5-a362-4dac-bc3d-1ba2a78d8d8d','明日北風尤甚不可行再讒','陳舜俞','宋','宋诗','song-poetry','','[]','我行楚濱，洪波是涵。',140,'全唐诗/poet.song.23000.json','["我行楚濱，洪波是涵。", "飄風不惠，停舳相銜。", "我實有辭，將伯是讒。", "越明日作，若怒弗咸。", "大吹振蕩，厥聲唬喊。", "龍憑虎借，播谷摇巖。", "止莫能維，行不可帆。", "誰令其然，維伯所監。", "我名有讒，實意以禱。", "終使不往，寧弗之報。", "泛泛行者，有游有漕。", "罔不衣食，或俱幼老。", "出其孔艱，仁者攸好。", "吹而順之，毋忽予告。"]'),
('085e2f27-7d22-4ed8-b51d-065b52a45796','謝風伯','陳舜俞','宋','宋诗','song-poetry','','[]','晨風飄兮，弗疾弗暴。',100,'全唐诗/poet.song.23000.json','["晨風飄兮，弗疾弗暴。", "我舟汎兮，以安且蹈。", "云誰之賜，神伯予報。", "莫阻乎淮，如彼行奡。", "莫遠乎泗，曾不日到。", "我讒不淑，我辭靡好。", "伯其憐汝，其還壽考。", "伯實神聖，善人是悼。", "鼓動萬物，永輔有昊。", "我歌我詩，以薦行潦。"]'),
('74900406-3c8c-4cab-88ac-f62a21f4fcc9','題婁億墓','陳舜俞','宋','宋诗','song-poetry','','[]','彼何人之門兮，雁行馬車。',201,'全唐诗/poet.song.23000.json','["彼何人之門兮，雁行馬車。", "老夫懷金兮，童子紆朱。", "其取萬鍾兮，不差毫銖。", "庖有粱肉兮，腹無圖書。", "天之生此兮，何罪何辜。", "句讀其話言兮，節文其步趨。", "抱筆而宵吟兮，鋪楮而晝塗。", "天子招其以仕兮，鄉人勉呼。", "衆肩相煦摩兮，疾駕爭馳驅。", "有司五上吾名兮，禮部曾不一知。", "退將羸其角兮，進且跋其胡。", "行年幾六十兮，僅免爲白徒。", "一秩不能勝兮，朝强而暮殂。", "考妣其謂我何兮，遑悼妻與孥。", "高者我難諏兮，厚者行難語。", "諸百恨寂默兮，秋草之墟。"]'),
('aa95b8a2-b642-40b3-9daf-d5bacce2ebc5','宿靈源院','陳舜俞','宋','宋诗','song-poetry','','[]','山家皆種橘，古寺獨栽松。',48,'全唐诗/poet.song.23000.json','["山家皆種橘，古寺獨栽松。", "林靜時棲鶴，泉靈合有龍。", "何年人捨宅，今日我携筇。", "寓所留僧話，未眠聞打鐘。"]'),
('9dc216cc-ce27-4ddf-84f2-e689d2fd69c8','閱日堂僧橘','陳舜俞','宋','宋诗','song-poetry','','[]','閱日堂前橘，山僧手自移。',48,'全唐诗/poet.song.23000.json','["閱日堂前橘，山僧手自移。", "爲迎林下客，旋拄路邊枝。", "結實曾防蟻，盈箱不禁兒。", "他年應記得，蠟屐過門時。"]'),
('2bb232b3-7ef6-4ef4-9513-949957ad7c91','落葉','陳舜俞','宋','宋诗','song-poetry','','[]','風露入林阿，紛紛奈落何。',48,'全唐诗/poet.song.23000.json','["風露入林阿，紛紛奈落何。", "滿庭添野景，開戶覺明多。", "未逐滄浪遠，堪憐腐草和。", "無由遮醉眼，歸思滿烟波。"]'),
('f100fc0d-4926-4f16-8d3a-8eb81ec0d380','中夜','陳舜俞','宋','宋诗','song-poetry','','[]','强寢夜何永，通宵夢不成。',48,'全唐诗/poet.song.23000.json','["强寢夜何永，通宵夢不成。", "曉燈寒有暈，跳蚤靜聞聲。", "宦拙宜身退，家貧長道情。", "自憐前計失，半世慕虛名。"]'),
('8512eee0-50d9-448d-bbc6-19cff71c9eac','客意五首  其一','陳舜俞','宋','宋诗','song-poetry','','[]','客意久不適，攬衣臨暮舂。',48,'全唐诗/poet.song.23000.json','["客意久不適，攬衣臨暮舂。", "烟長藏野闊，雲斷漏天空。", "酒置千愁裏，詩成一望中。", "黄花無限好，底事憶江東。"]'),
('60ea2816-acb2-4dde-97af-3e41b4d5f626','客意五首  其二','陳舜俞','宋','宋诗','song-poetry','','[]','行役意匆匆，淹留計已窮。',48,'全唐诗/poet.song.23000.json','["行役意匆匆，淹留計已窮。", "夢歸無奈曉，病覺不禁風。", "憶橘園垂枳，沉魚夜聽鴻。", "悲秋成白髪，頼未作衰翁。"]'),
('4453b8f8-865f-4876-9a7e-d235ca308f99','客意五首  其三','陳舜俞','宋','宋诗','song-poetry','','[]','高岸聳如陵，秋光著處清。',48,'全唐诗/poet.song.23000.json','["高岸聳如陵，秋光著處清。", "遥山照眼碧，黄葉逐人行。", "莫怪新烟火，曾經古戰爭。", "深林茅屋小，氣象亦豪英。"]'),
('51b69e2c-efea-4abf-afa1-ca5849a69147','客意五首  其四','陳舜俞','宋','宋诗','song-poetry','','[]','水濁不見面，安能照膽明。',48,'全唐诗/poet.song.23000.json','["水濁不見面，安能照膽明。", "還因送流梗，所得計歸程。", "日落西風急，秋聲積潦并。", "清江前約在，頼爾濯吾纓。"]'),
('864a13aa-a367-4ef3-9a1a-6886b4264026','客意五首  其五','陳舜俞','宋','宋诗','song-poetry','','[]','况復淹旅泊，情多秋亦悲。',48,'全唐诗/poet.song.23000.json','["况復淹旅泊，情多秋亦悲。", "寒雲欲垂野，疏葉不藏梨。", "斷梗逐流水，歸禽投好枝。", "徘徊古原上，應有夕陽知。"]'),
('61ba54cb-26ad-41ae-b9d8-0a7e02c66b07','阻風還泊舊浦','陳舜俞','宋','宋诗','song-poetry','','[]','已作淹留計，行艫豈恨遲。',48,'全唐诗/poet.song.23000.json','["已作淹留計，行艫豈恨遲。", "却投前浦宿，還似始來時。", "寥泬鱸鄉遠，飄零鶴髪悲。", "猶欣有隠者，度景覆殘棋。"]'),
('26e9fa3f-6160-4a7f-882c-ddc309a87562','題秋浦亭','陳舜俞','宋','宋诗','song-poetry','','[]','牢落真秋浦，江山滯客舟。',48,'全唐诗/poet.song.23000.json','["牢落真秋浦，江山滯客舟。", "身同雁南去，心似水東流。", "鷗鳥荒烟裏，漁人古渡頭。", "只因山色好，來上九華樓。"]'),
('7298be38-5194-44c1-ac66-90ed99e84065','彭澤縣','陳舜俞','宋','宋诗','song-poetry','','[]','古來彭澤縣，應有折腰人。',48,'全唐诗/poet.song.23000.json','["古來彭澤縣，應有折腰人。", "百里昔猶重，先生豈不貧。", "菊花還在否，柳色爲誰新。", "白髪南遷客，凄凉問水濱。"]'),
('1b562958-f42e-4b57-8943-da9bec5660ef','題東林寺','陳舜俞','宋','宋诗','song-poetry','','[]','凈社清談盡，高名野史傳。',48,'全唐诗/poet.song.23000.json','["凈社清談盡，高名野史傳。", "空山留舊寺，老檜識當年。", "殿古應藏璧，僧閒學種蓮。", "徘徊二林月，猶照虎溪泉。"]'),
('65636646-da0e-4557-9b61-7b3500525fa1','以橘贈湖州李公擇','陳舜俞','宋','宋诗','song-poetry','','[]','去著登山屐，夢歸清霅門。',48,'全唐诗/poet.song.23000.json','["去著登山屐，夢歸清霅門。", "親嘗霜後橘，思侑府中樽。", "爲問林間路，曾過水畔村。", "人言封境近，往往被公恩。"]'),
('0a1df53b-51fc-427a-9a0a-7796c78ae93a','送可則上人還京師開講','陳舜俞','宋','宋诗','song-poetry','','[]','善作空王子，能探佛祖心。',48,'全唐诗/poet.song.23000.json','["善作空王子，能探佛祖心。", "浮雲無定住，流水度光陰。", "糲食開盂慣，飛塵壞衲禁。", "國城傳法後，倚錫舊山林。"]'),
('c4e2612b-a897-47b6-a0d2-2b720f0b98cb','過下方祇園入上方看經院遇八十老僧','陳舜俞','宋','宋诗','song-poetry','','[]','因過下方院，更指上方登。',48,'全唐诗/poet.song.23000.json','["因過下方院，更指上方登。", "偃蓋杉松路，包金橘柚層。", "清灣從古好，孤榜復誰曾。", "八十年前事，凄凉欲問僧。"]'),
('749992dd-6799-4f1a-88eb-27dd1bd9b243','次韵吳少卿致政自詠','陳舜俞','宋','宋诗','song-poetry','','[]','掛冠歸故里，尋壑具巾車。',48,'全唐诗/poet.song.23000.json','["掛冠歸故里，尋壑具巾車。", "蘭蕙庭階茂，交游世路疏。", "一壺新漏箭，千姓舊囊書。", "寄問從公客，家金有幾餘。"]'),
('7df5b086-b556-46db-970b-4f7e3395b4f6','奉酬長文舍人出城見示之句','陳舜俞','宋','宋诗','song-poetry','','[]','春分臘雪未全消，凜冽春寒氣尚驕。',64,'全唐诗/poet.song.23000.json','["春分臘雪未全消，凜冽春寒氣尚驕。", "攝事初忻迎社燕，尋芳因得過溪橋。", "清浮蟻酒醅初撥，暖入鶑簧舌漸調。", "興味愛君年尚少，莫嫌齋禁暫無憀。"]'),
('c8faa18f-a3d8-4672-aaba-07205b7d3d3b','贈徐道士游京師','陳舜俞','宋','宋诗','song-poetry','','[]','有客人形善鑒觀，過門聊肯駐征鞍。',64,'全唐诗/poet.song.23000.json','["有客人形善鑒觀，過門聊肯駐征鞍。", "知予謾失江湖約，笑我甘爲簿領官。", "卜隠日邊龍闕近，去程霜裏鶴衣寒。", "京師車馬飛騰速，別把金波洗眼看。"]'),
('4e9564a1-8172-426b-8d62-7d5fe18b8d4e','將至嘉禾先寄諸兄弟','陳舜俞','宋','宋诗','song-poetry','','[]','半年西走若飛蓬，得祿無多計屢窮。',64,'全唐诗/poet.song.23000.json','["半年西走若飛蓬，得祿無多計屢窮。", "驥足寒孤甘伏皁，雁群驚迸苦傷弓。", "家貧不易新堂構，天幸猶能遇歲豐。", "且待歸來都講論，一篙烟水趁霜風。"]'),
('2dc9dace-e995-49ec-91e9-5bd0c7b48bf1','送劉吏部得請三茅崇禧觀','陳舜俞','宋','宋诗','song-poetry','','[]','老臣連上皂囊封，去訪三茅駕鶴翁。',64,'全唐诗/poet.song.23000.json','["老臣連上皂囊封，去訪三茅駕鶴翁。", "曾爲蒼生論敝事，因從紫府得仙風。", "收身物外光陰好，回首人間寵辱空。", "果滿丹成家法在，應携鷄犬入雲中。"]'),
('92e36787-1641-454b-bd11-57722a1ec953','和王介甫寄安豐知縣修芍陂','陳舜俞','宋','宋诗','song-poetry','','[]','雩婁陂水舊風烟，可喜斯民得繼傳。',64,'全唐诗/poet.song.23000.json','["雩婁陂水舊風烟，可喜斯民得繼傳。", "萬頃稻粱追漢日，五門疏鑿似齊年。", "才高欲獻營田策，公暇還來泛酒船。", "稱與淮南誇好事，耕歌漁唱已相連。"]'),
('fd4ecf19-41be-428a-a178-ef35dbd52c7b','和知郡王職方韵同前','陳舜俞','宋','宋诗','song-poetry','','[]','邑陂增築更淵沉，所喜詩筒賞嘆深。',64,'全唐诗/poet.song.23000.json','["邑陂增築更淵沉，所喜詩筒賞嘆深。", "楚國老臣千古意，廬江賢守一家心。", "淮邊野史添新事，壠上春犁誦好音。", "興利勸農真政術，可知爲吏得喉襟。"]'),
('cf494d41-1156-4383-baed-cbe2845b84d3','南陽春日十首  其一','陳舜俞','宋','宋诗','song-poetry','','[]','城頭古木未知春，官柳柔條日日新。',64,'全唐诗/poet.song.23000.json','["城頭古木未知春，官柳柔條日日新。", "門巷旋開沽酒市，郊原便有踏青人。", "風烟乍入禽初好，網罟猶多雉肯馴。", "擬爲芳時對樽斝，愧無心事樂天均。"]'),
('a4338e73-7e48-41bb-b21e-7b26cb32fca3','南陽春日十首  其二','陳舜俞','宋','宋诗','song-poetry','','[]','惓懷春晚脫征驂，官况喧卑昔未諳。',64,'全唐诗/poet.song.23000.json','["惓懷春晚脫征驂，官况喧卑昔未諳。", "敲扑豈甘忘素業，琴樽猶可助清談。", "窗燈耿耿書開卷，衙鼓鼕鼕吏放參。", "唯有登樓心不愜，亂雲堆霧鎖東南。"]'),
('34b74a39-057c-4aaf-8f00-269c48781636','南陽春日十首  其三','陳舜俞','宋','宋诗','song-poetry','','[]','山川隨處有芳菲，老大情懷與舊非。',64,'全唐诗/poet.song.23000.json','["山川隨處有芳菲，老大情懷與舊非。", "已恨鶑聲驚曉夢，豈堪花氣著人衣。", "家蔬未省添新斸，宰木應曾長舊圍。", "終向畏塗無所得，好風佳月不如歸。"]'),
('5dc63042-48c5-4ee2-9495-a2bd3ca28c16','南陽春日十首  其四','陳舜俞','宋','宋诗','song-poetry','','[]','花前惆悵轉難平，屈指光陰已半生。',64,'全唐诗/poet.song.23000.json','["花前惆悵轉難平，屈指光陰已半生。", "猶把此身嘗患難，不知何日得功名。", "未安去住千絲亂，已去悲歡一夢驚。", "擬入醉鄉銷此恨，快風無故析春酲。"]'),
('f61f80da-f0f0-4a07-bb0e-36d9cf36fcae','南陽春日十首  其五','陳舜俞','宋','宋诗','song-poetry','','[]','壯懷摧折復何言，齒髪今年老去年。',64,'全唐诗/poet.song.23000.json','["壯懷摧折復何言，齒髪今年老去年。", "念遠片心飛鳥外，感時雙淚落花前。", "琴逢遏密生難理，詩擬離騷怨不傳。", "家在五湖明月裏，夢隨春水宿漁船。"]'),
('446a1577-ae4c-4495-addc-1a2f38e28a05','南陽春日十首  其六','陳舜俞','宋','宋诗','song-poetry','','[]','客宦逢春病眼開，紫荆花下也徘徊。',64,'全唐诗/poet.song.23000.json','["客宦逢春病眼開，紫荆花下也徘徊。", "謾勞人力書千卷，聊寄天真酒一杯。", "明代本期無棄物，孤臣何敢自論才。", "且欣腐鼠同烏喙，不怕丹山有鳳猜。"]'),
('a47cea3e-bd5e-4352-b240-aa0e8c858e9e','南陽春日十首  其七','陳舜俞','宋','宋诗','song-poetry','','[]','簿書堆裏得天真，謾爲浮名役此身。',64,'全唐诗/poet.song.23000.json','["簿書堆裏得天真，謾爲浮名役此身。", "門柳偶同陶靖節，君羹空羨潁封人。", "沙鷗舊許爲吾侶，巢燕何曾厭我貧。", "已共東風有歸約，且從桃李笑今春。"]'),
('80e483e4-1047-4ee8-8747-bf7d8e33f2e2','南陽春日十首  其八','陳舜俞','宋','宋诗','song-poetry','','[]','故園春物有誰同，地盡天垂杳藹中。',64,'全唐诗/poet.song.23000.json','["故園春物有誰同，地盡天垂杳藹中。", "杏火柳烟燒白晝，茶槍筍槊戰東風。", "橋橫酒市青帘出，門對魚磯小艇通。", "誰信南陽樓上客，翩翩歸羽欲飛空。"]'),
('4b639ddc-6972-49ed-acc8-dc4ef745b803','南陽春日十首  其九','陳舜俞','宋','宋诗','song-poetry','','[]','澤國生涯有釣舟，此身隨分狎群鷗。',64,'全唐诗/poet.song.23000.json','["澤國生涯有釣舟，此身隨分狎群鷗。", "非關利祿成羈縶，爲學文章作贅疣。", "病眼看花空濺淚，客顔臨鏡復包羞。", "江東父老應相憶，燕子來時語不休。"]'),
('7673541b-2ca3-4cca-8367-c263e4affac1','南陽春日十首  其一○','陳舜俞','宋','宋诗','song-poetry','','[]','半生名宦是塗顔，菽水當年尚可歡。',64,'全唐诗/poet.song.23000.json','["半生名宦是塗顔，菽水當年尚可歡。", "鐘鼎未能光祖妣，牛羊雖美愧杯盤。", "五千强誦誰云補，四十無聞得自安。", "不覺尋春上臺榭，東風吹淚落闌干。"]'),
('17757fbc-81c4-4326-84c2-229ac9e6e405','和開祖丹陽別子瞻後寄','陳舜俞','宋','宋诗','song-poetry','','[]','仙舟繫柳野橋東，會合情多勞謫翁。',64,'全唐诗/poet.song.23000.json','["仙舟繫柳野橋東，會合情多勞謫翁。", "相對一樽浮蟻酒，輕寒二月小桃風。", "羈懷散誕謳歌裏，世事縱橫醉笑中。", "莫恨明朝又離索，人生何處不匆匆。"]'),
('75a776a1-2636-4e7c-89da-06ed9ed60900','和章子厚聞子瞻買田陽羨却寄','陳舜俞','宋','宋诗','song-poetry','','[]','罨畫春流藻荇長，吳門菰米鱖鱸鄉。',64,'全唐诗/poet.song.23000.json','["罨畫春流藻荇長，吳門菰米鱖鱸鄉。", "謀田問舍拙者事，尋壑買山君底忙。", "出處兩忘同旅寓，濁清一種付滄浪。", "故人詩酒如驅使，別有甘泉綠野堂。"]'),
('fa355024-704e-40a0-aa56-acab25c24751','次韵酬余彥翔','陳舜俞','宋','宋诗','song-poetry','','[]','我慚希世就窮儒，甚矣謀身子更迂。',64,'全唐诗/poet.song.23000.json','["我慚希世就窮儒，甚矣謀身子更迂。", "不共梟狐倚城社，合隨魚鳥樂江湖。", "古來只有風猷重，事去情知氣味殊。", "髀肉縱消吾舌在，任從兒女暗揶揄。"]'),
('c3d2364d-6c9d-4293-a1d2-e8e32e4ed1a9','次韵酬白天覺','陳舜俞','宋','宋诗','song-poetry','','[]','人生自致真非策，歲晚無成可復論。',64,'全唐诗/poet.song.23000.json','["人生自致真非策，歲晚無成可復論。", "鈍駕謾思追驥躍，病巢何敢慕鴻騫。", "傲如中散人多疾，辯付南華盡不言。", "聊謝高情白夫子，爲攄騷興慰王孫。"]'),
('5995a174-8e45-4243-a243-2f1fef664a1e','謝楊都官見惠錦鷄','陳舜俞','宋','宋诗','song-poetry','','[]','珍禽流品可褒題，天與文章五色齊。',64,'全唐诗/poet.song.23000.json','["珍禽流品可褒題，天與文章五色齊。", "羽翮已堪攀鳳翼，稻粱爭合在鷄栖。", "應思舊侶雌雄舞，耻學凡群旦暮啼。", "好向彩衣堂下養，名郎從此樂持齎。"]'),
('058cfd74-fd01-47ca-9b46-a47abfec9d17','送李戶曹官滿還江寧','陳舜俞','宋','宋诗','song-poetry','','[]','去程牢落且徘徊，聽我高吟侑一杯。',64,'全唐诗/poet.song.23000.json','["去程牢落且徘徊，聽我高吟侑一杯。", "皦日心胸無愧耻，青衫顔色任塵埃。", "秦淮形勝多人物，晉室風流入草萊。", "歸到江山聊洗眼，下僚應不久沉才。"]'),
('b66a9f6e-4c08-42e4-a09a-f39caafbbd9d','鳳凰臺','陳舜俞','宋','宋诗','song-poetry','','[]','鳳去臺存碧草濃，遊人來此問遺蹤。',64,'全唐诗/poet.song.23000.json','["鳳去臺存碧草濃，遊人來此問遺蹤。", "故巢風月已千載，好景闌干空數重。", "府坐循良黄太守，輿乘仁聖漢高宗。", "竹花生子梧桐老，底事丹山信未逢。"]'),
('8befaa32-2ea7-43c9-add8-227178ee4518','十八賢臺','陳舜俞','宋','宋诗','song-poetry','','[]','臺下衣冠已化塵，臺前顔色尚如新。',64,'全唐诗/poet.song.23000.json','["臺下衣冠已化塵，臺前顔色尚如新。", "林泉合是修行社，巖穴誰非避世人。", "好鳥豈知當日事，幽花何似昔時春。", "老僧不解論今古，應笑徘徊問隠淪。"]'),
('dd00ea64-8168-423c-bc27-6bd81bb2bfe8','淵明醉石','陳舜俞','宋','宋诗','song-poetry','','[]','聒聒飛泉清遶石，悠悠天幕翠鋪空。',64,'全唐诗/poet.song.23000.json','["聒聒飛泉清遶石，悠悠天幕翠鋪空。", "是非分付千鍾裏，日月消磨一醉中。", "柳絮狂飄荒徑畔，菊花仍在舊籬東。", "水聲山色年年好，堪使遊人耻素風。"]'),
('579382da-87a9-475d-9bd2-d63176cd4b77','東庵','陳舜俞','宋','宋诗','song-poetry','','[]','已憐門巷林中出，况復軒窗水畔開。',64,'全唐诗/poet.song.23000.json','["已憐門巷林中出，况復軒窗水畔開。", "冷淡山光明枕簟，動摇波影上樽罍。", "坐看天際孤舟失，慣見桑陰五馬來。", "長恨夕陽吟不足，闌干留共月徘徊。"]'),
('f2e15c3b-df41-4cb6-81e6-9d1c47f79cdd','太平觀','陳舜俞','宋','宋诗','song-poetry','','[]','繞繞峰巒玉案圍，重重樓殿紫烟飛。',64,'全唐诗/poet.song.23000.json','["繞繞峰巒玉案圍，重重樓殿紫烟飛。", "青籐素簡天門近，絳節霓旌夜半歸。", "鶴使每傳三島信，鳳書頻送九霞衣。", "放臣於世慚無補，金萼樓前拜不祈。"]'),
('81e623be-7c6a-4b0f-8318-39352a08ea54','東林寺','陳舜俞','宋','宋诗','song-poetry','','[]','白髪老僧安住處，青衫司馬愛閒來。',64,'全唐诗/poet.song.23000.json','["白髪老僧安住處，青衫司馬愛閒來。", "松嫌天近株株短，花待春歸款款開。", "堪信壺中藏日月，誰知雲外有樓臺。", "官卑合是尋山客，不見芳菲意懶回。"]'),
('d95e1971-816a-4756-861a-44c21d434c9c','西林寺','陳舜俞','宋','宋诗','song-poetry','','[]','東林移宿過西林，風靄蕭蕭結暝陰。',64,'全唐诗/poet.song.23000.json','["東林移宿過西林，風靄蕭蕭結暝陰。", "隨處水聲喧屐齒，傍人山色上衣襟。", "道於塵土知無用，樂在雲泉亦損心。", "擬付離騷與猿鳥，樵蘇應怪久登臨。"]'),
('c9207e79-22be-4634-9152-38d201351ba2','棲賢寺','陳舜俞','宋','宋诗','song-poetry','','[]','辟蛇行者應開寺，拭眼高僧尚有墳。',64,'全唐诗/poet.song.23000.json','["辟蛇行者應開寺，拭眼高僧尚有墳。", "龍带雨歸三峽水，鳥銜花出五峰雲。", "樓臺屹屹天宮近，鐘磬疏疏俗界聞。", "遊客不嫌車騎遠，巖扃無計長苔紋。"]'),
('d24c40b6-2068-45bb-af0d-d581c85df9fe','萬杉院仁宗御書寺額','陳舜俞','宋','宋诗','song-poetry','','[]','銀鈎金榜佛家園，屐齒初來骨髪寒。',64,'全唐诗/poet.song.23000.json','["銀鈎金榜佛家園，屐齒初來骨髪寒。", "天上星辰留翰墨，人閒陵寢閟衣冠。", "虬龍擁護神如在，雲霧遮藏色未乾。", "四十二年蒙雨露，草茅猶解泣汍瀾。"]'),
('b9b6a898-f553-4438-8b12-3c93e6d77f11','開先寺','陳舜俞','宋','宋诗','song-poetry','','[]','山門屹屹橫青嶂，巖屋霏霏带紫烟。',64,'全唐诗/poet.song.23000.json','["山門屹屹橫青嶂，巖屋霏霏带紫烟。", "千尺老松當大道，一條飛瀑落中天。", "重來覽物應相識，此地尋僧似有緣。", "自謂讀書非俗客，謫官猶得近林泉。"]'),
('fff3461e-4890-4854-9e65-8b8591f9d4d1','新羅巖','陳舜俞','宋','宋诗','song-poetry','','[]','萬疊青山與世違，一巖雲物倚天危。',64,'全唐诗/poet.song.23000.json','["萬疊青山與世違，一巖雲物倚天危。", "僧開峭石難行路，猿叫枯松最上枝。", "藥鼎施人寒種火，菜畦行虎宿無籬。", "此中別有忘年事，擾擾紅塵死不知。"]'),
('7920c319-b409-4969-ab44-7faa7043755b','竹雲洞','陳舜俞','宋','宋诗','song-poetry','','[]','長干龍老長龍孫，竹裏陰陰鎖晝雲。',64,'全唐诗/poet.song.23000.json','["長干龍老長龍孫，竹裏陰陰鎖晝雲。", "莫問何年初入洞，由來一日可無君。", "清圍欄檻喧難入，翠滴衣裾靜欲聞。", "會得歲寒看苦節，憑誰吟對雪繽紛。"]'),
('ae11a28d-f7fd-4c05-a12e-b9522c288424','峰頂院','陳舜俞','宋','宋诗','song-poetry','','[]','自憐隨分有仙蹤，曾宿金庭第九重。',64,'全唐诗/poet.song.23000.json','["自憐隨分有仙蹤，曾宿金庭第九重。", "誰謂謫官真俗吏，還登廬阜最高峰。", "坐頭平揖千巖月，枕底微聞二寺鐘。", "歸去林泉緣更熟，定應春夢却過從。"]'),
('a602e880-7835-4411-afe5-396eaa263fbf','雪','陳舜俞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','老來惟有看山癖，踏雪來尋洞府春。',64,'全唐诗/poet.song.23000.json','["老來惟有看山癖，踏雪來尋洞府春。", "已愛匡廬無俗骨，更逢姑射露天真。", "參差玉樹千巖裏，高下藍田一水濱。", "乘興去留人莫怪，風流元是剡中人。"]'),
('6b2632a0-a90b-46a6-94be-1a2561d47900','靈溪觀','陳舜俞','宋','宋诗','song-poetry','','[]','靈溪流水碧潺湲，溪上清輝弟子園。',64,'全唐诗/poet.song.23000.json','["靈溪流水碧潺湲，溪上清輝弟子園。", "白叟荷鋤春採藥，黄冠敲磬夜朝元。", "山中松葉堪爲酒，路口桃花似有源。", "自是遊人無道骨，長生何必五千言。"]'),
('3d0258be-590b-4d2f-ba04-b54de38c7206','落星寺','陳舜俞','宋','宋诗','song-poetry','','[]','何年翠麓浮彭蠡，云是寒星落斗牛。',64,'全唐诗/poet.song.23000.json','["何年翠麓浮彭蠡，云是寒星落斗牛。", "遠水拍天圍凈界，野僧依石起朱樓。", "闌干白日風吹雁，簾幕黄昏月近鷗。", "安住自成難老藥，不須乘海覓蓬邱。"]'),
('dd7c7ccf-74b8-4807-9d6b-656d309d342b','承天院','陳舜俞','宋','宋诗','song-poetry','','[]','建昌門外小禪居，竹檻松窗靜有餘。',64,'全唐诗/poet.song.23000.json','["建昌門外小禪居，竹檻松窗靜有餘。", "全近江湖添悵望，乍離城市易清虛。", "人思求友聽啼鳥，僧愛忘筌看得魚。", "不爲山南多勝處，便堪從此駐巾車。"]'),
('29812a05-12f2-4fb6-b4d7-8e3fb7cd00c4','寄星子令柯季立','陳舜俞','宋','宋诗','song-poetry','','[]','慣見江湖賤逐臣，去尋巖穴或相親。',64,'全唐诗/poet.song.23000.json','["慣見江湖賤逐臣，去尋巖穴或相親。", "不知金馬曾爲客，猶得銅章肯借人。", "夜夜水聲隨枕簟，時時林色上衣巾。", "題詩半在山南寺，請戒巖僧掃隙塵。"]'),
('85d84ac7-1d81-40c4-b8e5-9109713fa4a1','寄郟景仁郎中','陳舜俞','宋','宋诗','song-poetry','','[]','早歲交情淡已親，相逢羈旅白頭新。',64,'全唐诗/poet.song.23000.json','["早歲交情淡已親，相逢羈旅白頭新。", "雖慚管鮑論高誼，欲慕陳雷卜近鄰。", "客舍每羅門外雀，歸來還滿甑中塵。", "明年相逐東林去，未必鱸魚駐得人。"]'),
('288b8b9d-6c32-4606-9627-b4fee49cbfee','中秋佳月獨遊垂虹亭有懷胡完夫蘇子瞻錢安道  其一','陳舜俞','宋','宋诗','song-poetry','','[]','五湖人住覺天寬，有月清秋似廣寒。',64,'全唐诗/poet.song.23000.json','["五湖人住覺天寬，有月清秋似廣寒。", "玉鑒光中數毛髪，長虹背上倚闌干。", "棲鴉誤曉啼還住，白露沾衣濕又乾。", "借問姑蘇胡別駕，簿書燈火共誰看。"]'),
('d02e4137-96e3-474d-a236-fea4013cfcf5','中秋佳月獨遊垂虹亭有懷胡完夫蘇子瞻錢安道  其二','陳舜俞','宋','宋诗','song-poetry','','[]','月光清極向中秋，千古松陵此夜遊。',64,'全唐诗/poet.song.23000.json','["月光清極向中秋，千古松陵此夜遊。", "寥泬更無雲礙眼，滄浪合是我維舟。", "浮生未有明年約，淺酌聊資到眼留。", "辜負金波三萬頃，詩豪草聖在杭州。"]'),
('eb1413c4-2ac0-4889-b279-4d93579da936','中秋佳月獨遊垂虹亭有懷胡完夫蘇子瞻錢安道  其三','陳舜俞','宋','宋诗','song-poetry','','[]','玉兔光中繫小桅，長虹影裏倒樽罍。',64,'全唐诗/poet.song.23000.json','["玉兔光中繫小桅，長虹影裏倒樽罍。", "一年此夜清秋半，萬里無雲霽色開。", "月女嬋娟如有舊，波神安穩亦憐才。", "合須豪飲酬佳賞，不共烏臺御史來。"]'),
('fa856115-37f4-4950-bdff-849688a9c995','留槎閣','陳舜俞','宋','宋诗','song-poetry','','[]','聞說歐川似沃洲，一溪分作兩溪流。',64,'全唐诗/poet.song.23000.json','["聞說歐川似沃洲，一溪分作兩溪流。", "長橋跨岸虹垂地，高閣淩空蜃吐樓。", "浩蕩乾坤供醉眼，凄凉風雨送行舟。", "憑誰爲問乘槎客，未必無人犯斗牛。"]'),
('d9c20b31-0eab-493c-945b-0acafc992f87','禹穴','陳舜俞','宋','宋诗','song-poetry','','[]','百尺蒼堅穴翠嵐，天痕非擘亦非鑱。',64,'全唐诗/poet.song.23000.json','["百尺蒼堅穴翠嵐，天痕非擘亦非鑱。", "先王圖史誰分掌，後世疏慵不復探。", "定有龍虬蟠寂寂，何如苔蘚亂鬖鬖。", "老師更說神靈事，只讀高碑去未甘。"]'),
('96a35cc6-c0d6-48f1-a3fb-79e5bab7126b','谷簾泉','陳舜俞','宋','宋诗','song-poetry','','[]','玉簾鋪水半天垂，行客尋山到此稀。',64,'全唐诗/poet.song.23000.json','["玉簾鋪水半天垂，行客尋山到此稀。", "陸羽品題真黼黻，黄州吟詠盡珠璣。", "重來一酌非無分，未挈吾缾可忍歸。", "終欲窮源登絕頂，带雲和月弄清暉。"]'),
('bd0cf4c7-407c-4034-af74-4450602947b2','若耶溪','陳舜俞','宋','宋诗','song-poetry','','[]','十里澄溪溪上山，溪光無際照山顔。',64,'全唐诗/poet.song.23000.json','["十里澄溪溪上山，溪光無際照山顔。", "天嫌俗眼尋常見，地惜群峰左右關。", "蓬島也應非海外，瓊臺爭合貯人間。", "維舟正欲踟躕飲，坐見蒼烟罩翠灣。"]'),
('62a910d2-0d04-454b-b59f-897070519ebf','天池院','陳舜俞','宋','宋诗','song-poetry','','[]','此峰巉絕與霄干，峰頂泓澄旱不乾。',64,'全唐诗/poet.song.23000.json','["此峰巉絕與霄干，峰頂泓澄旱不乾。", "天下定應添沆瀣，山頭信亦有泥洹。", "等閒雲出千巖雨，取次龍歸六月寒。", "一勺自堪流萬古，何須低處羨波瀾。"]'),
('10c6b383-acf6-46b0-81ba-312ec348c2ff','題翠峰院','陳舜俞','宋','宋诗','song-poetry','','[]','借問鴟夷與季鷹，五湖珍賞復誰曾。',64,'全唐诗/poet.song.23000.json','["借問鴟夷與季鷹，五湖珍賞復誰曾。", "慣看銷夏灣頭月，唯有莫釐山上僧。", "晚渡浪痕沾壞衲，上方雲液灑枯藤。", "游人欲趁沙鷗去，更伴禪公上翠層。"]'),
('ea372cdc-bb75-4385-81d9-5ed02b04880f','青龍江醉眠亭','陳舜俞','宋','宋诗','song-poetry','','[]','酒擔長輕六印腰，醉中一枕敵千朝。',64,'全唐诗/poet.song.23000.json','["酒擔長輕六印腰，醉中一枕敵千朝。", "興亡藐比榮枯柳，聚散看同旦暮潮。", "清興本應塵外得，香魂徒向水邊招。", "已聞佳士過從約，不爲東風返畫橈。"]'),
('fbc27412-1657-4b0e-8691-67ef8077710f','水月院','陳舜俞','宋','宋诗','song-poetry','','[]','興隨白鳥汀洲立，步入青林臺殿出。',64,'全唐诗/poet.song.23000.json','["興隨白鳥汀洲立，步入青林臺殿出。", "湖脈來通方士泉，山顔分入幽人室。", "自苦扁舟每訪尋，何年空谷無遺逸。", "一夜霜風穿客衣，二十六房皆採橘。"]'),
('e39e2c9e-db18-47a8-9a06-3e295c187e92','題碧蘚亭','陳舜俞','宋','宋诗','song-poetry','','[]','瀟灑闌干碧玉叢，頻來游賞似兒童。',64,'全唐诗/poet.song.23000.json','["瀟灑闌干碧玉叢，頻來游賞似兒童。", "縈迴修竹撩清影，刻畫新詩繞翠筒。", "十載雪霜林色改，幾翻風月酒尊空。", "子猷老去心嘗在，終擬爲鄰作醉翁。"]'),
('3f57a925-b251-4fb1-9c21-50a674ce8ffb','送喜長老游四明','陳舜俞','宋','宋诗','song-poetry','','[]','釣竿無竹月空船，事去朱涇不記年。',64,'全唐诗/poet.song.23000.json','["釣竿無竹月空船，事去朱涇不記年。", "一句弗由他物得，此心知與麽人傳。", "無鬚王老長垂地，掉臂胡僧仰託天。", "去問玲瓏巖上石，*中誰是我師禪。"]'),
('57022433-377b-4a7a-884e-c5b4774b8083','寄姑蘇智肱錢塘文捷二上人','陳舜俞','宋','宋诗','song-poetry','','[]','釋子紛紛奈汝何，傳聞右繞益乖訛。',64,'全唐诗/poet.song.23000.json','["釋子紛紛奈汝何，傳聞右繞益乖訛。", "南山述作那堪毀，西竺師徒果有魔。", "群蟻固應隨轉石，一杯焉可當頹波。", "青銅瓦礫皆稱鑒，乞與光明歲月磨。"]'),
('40835adb-ff95-412a-922e-589f4a6cb9c2','傳神悅躬上人','陳舜俞','宋','宋诗','song-poetry','','[]','倦轡曾投林下宿，短篷重見越江邊。',64,'全唐诗/poet.song.23000.json','["倦轡曾投林下宿，短篷重見越江邊。", "人歸河岳儀型在，事隔桑溟物色傳。", "弟子共談庭際柏，公卿多識社中蓮。", "高風自出空王侶，馳譽丹青是可憐。"]'),
('07ac80af-dc15-4e22-b516-8dddbe36cad8','山中寄姑蘇守倅','陳舜俞','宋','宋诗','song-poetry','','[]','莫釐山頭萬家橘，震澤閒人一葉舟。',64,'全唐诗/poet.song.23000.json','["莫釐山頭萬家橘，震澤閒人一葉舟。", "林裊金丸出籬落，浪噴雪陣上汀洲。", "雲生縹緲吟魂遠，日入穹窿醉望收。", "不禁五湖容小隠，爲傳篇什謝蘇州。"]'),
('f67d63e2-2b11-4b6c-81e6-58b71b5fbdd0','過平望驛有懷湖州李使君二首  其一','陳舜俞','宋','宋诗','song-poetry','','[]','柳色陰陰平望橋，春流西受霅溪潮。',64,'全唐诗/poet.song.23000.json','["柳色陰陰平望橋，春流西受霅溪潮。", "玉樓有月清光遠，蘋渚生風麗思飄。", "寧使簿書堆几案，已聞歌詠滿漁樵。", "酒船欲訪烏程去，愁費金龜返畫橈。"]'),
('1d52ba63-c9bb-467d-9e82-9892612c1c24','過平望驛有懷湖州李使君二首  其二','陳舜俞','宋','宋诗','song-poetry','','[]','憑熊飛隼兩溪頭，人似冰壺住玉樓。',64,'全唐诗/poet.song.23000.json','["憑熊飛隼兩溪頭，人似冰壺住玉樓。", "事逐歡謠入漁釣，詩隨秋思滿汀洲。", "茶收顧渚旗猶卷，酒貰烏程蟻半浮。", "去路無多平望驛，客魂秋雨宿扁舟。"]'),
('beda3669-9d0c-43bc-a831-af39affb5889','晚秋田間','陳舜俞','宋','宋诗','song-poetry','','[]','重到田園草木零，鬢毛蕭颯白綸巾。',64,'全唐诗/poet.song.23000.json','["重到田園草木零，鬢毛蕭颯白綸巾。", "謾誇孺子能分肉，堪笑書生尚負薪。", "靜與禽魚何物我，懶因鷄黍記晡晨。", "東籬已有黄金蕊，只欠白衣送酒人。"]'),
('86561dbc-a5be-4dfa-8a6d-297b569a7e18','挽邵夫人詞','陳舜俞','宋','宋诗','song-poetry','','[]','丹陽門第三朝貴，樂壽絲綸五色開。',64,'全唐诗/poet.song.23000.json','["丹陽門第三朝貴，樂壽絲綸五色開。", "有助清郎終盛譽，得憐諸子盡高才。", "蘭彫北畹香猶在，水向東溟逝不回。", "原上送車無數目，日西風雨轉徘徊。"]'),
('aee235ac-51c3-45c1-aa26-1e6685a7f5a0','挽劉夫人詞二首  其一','陳舜俞','宋','宋诗','song-poetry','','[]','籍籍家聲起草萊，詵詵子舍奉蘭陔。',64,'全唐诗/poet.song.23000.json','["籍籍家聲起草萊，詵詵子舍奉蘭陔。", "翩翻三鳳皆英物，蹭蹬雙駒亦駿才。", "憶昔綵衣環几舄，于今清血灑棬杯。", "何年盛事聯簪組，別有絲綸薦夜臺。"]'),
('e4ec129e-69b7-4001-bb9b-b5ebfe906c31','挽劉夫人詞二首  其二','陳舜俞','宋','宋诗','song-poetry','','[]','卜鄰早效三遷教，負米方休百里勞。',64,'全唐诗/poet.song.23000.json','["卜鄰早效三遷教，負米方休百里勞。", "樂事難留同逝水，孝思無盡入伊蒿。", "萬家原上開新塚，舊館人來奠濁醪。", "况有銘詩傳不朽，長城千古白雲高。"]'),
('8490d511-c65a-4e3e-b038-d3a4c2e58cea','挽侍講先生王夫人詩二首  其一','陳舜俞','宋','宋诗','song-poetry','','[]','蘭陔堂上此歸全，松柏山頭有舊阡。',64,'全唐诗/poet.song.23000.json','["蘭陔堂上此歸全，松柏山頭有舊阡。", "我得遐齡幾九十，人依絳帳昔三千。", "病時太守和湯藥，沒後諸生侍几筵。", "善化群材同草木，先生恩德重如天。"]'),
('5213b62a-0847-4489-a09c-d77000449cb1','挽侍講先生王夫人詩二首  其二','陳舜俞','宋','宋诗','song-poetry','','[]','師牆童稚被陶鈞，穴鳳仍同桂籍春。',64,'全唐诗/poet.song.23000.json','["師牆童稚被陶鈞，穴鳳仍同桂籍春。", "豈獨慈良尊有道，就論恩分即吾親。", "生前未許升堂拜，原上空陪執紼人。", "一曲薤歌難寫恨，哀榮千古付蒼珉。"]'),
('8665ee32-7013-420c-bc2f-74f303e9adac','山中咏橘長咏','陳舜俞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','包橘古云美，揚州地所宜。',288,'全唐诗/poet.song.23000.json','["包橘古云美，揚州地所宜。", "名存夏后貢，頌見楚人辭。", "雲夢分膏沃，璇星散陸離。", "洞庭仙壤接，震澤水烟被。", "柚酢徒然早，柑黄豈厭遲。", "封君千戶等，老囿萬奴隨。", "秀萼瑶瓊綴，青陰幄幕垂。", "朱衣霜傅采，素裏露含滋。", "弱幹金丸重，繁條火齊纍。", "瓜生先作瓣，蠶老不成絲。", "爽味鍾寒律，殷姿照夕曦。", "清香掩蘭杜，真液賤楂梨。", "揀選收藏日，辛勤種接時。", "壤須來處美，移怕樹同知。", "朱綠爭珍旨，荆湘辨等差。", "蹊深比桃靜，歲晚與松期。", "壇甃龜黿石，園裁枳棘籬。", "討蟲煩鑽鑿，科冗付蒸炊。", "穿井防天旱，禳瘟甚歲饑。", "向陽刪密葉，伐木樹低枝。", "有義曾分客，無偷不禁兒。", "㲏嫌連雨長，老要勁風吹。", "滿把留長蔕，盈箱藉短茨。", "入倉寧愧稻，出汗僅同醫。"]'),
('4aeb6efa-ad15-4d75-96b5-8774a75fe5cd','銷暑樓','陳舜俞','宋','宋诗','song-poetry','','[]','溪上樓臺似玉壺，樂郊春物剩昭蘇。',128,'全唐诗/poet.song.23000.json','["溪上樓臺似玉壺，樂郊春物剩昭蘇。", "賢侯好士簪裾集，暇日開筵錦綉敷。", "擘水膾鱸堆白雪，撥醅釀酒滴真珠。", "香飄沈穗縈欄角，歌沸梁塵落坐隅。", "約略十洲仙界景，依稀九老洛川圖。", "席中蘭語薰相襲，望裏蓮娃貌亦都。", "狂客笑吟聊自若，丈人强健不須扶。", "送歸千騎堂前月，猶照簾蝦一半鬚。"]'),
('52537174-0eb9-46fe-94ee-cfae2ee4503b','弄水亭','陳舜俞','宋','宋诗','song-poetry','','[]','未識貴池好，嘗聞弄水名。',24,'全唐诗/poet.song.23000.json','["未識貴池好，嘗聞弄水名。", "白鳥鑒中立，畫船天上行。"]'),
('10e15f29-7f36-4926-917d-0e7765064dbe','壽陽僧房見橘詩','陳舜俞','宋','宋诗','song-poetry','','[]','地過長淮種橘難，僧房今見鎖朱欄。',32,'全唐诗/poet.song.23000.json','["地過長淮種橘難，僧房今見鎖朱欄。", "秋來頼有黄金實，幾被行人作枳看。"]'),
('6eff7cb1-8d55-485b-9a48-b5b5410ef5a5','次韵六安魏明府三首  其一','陳舜俞','宋','宋诗','song-poetry','','[]','故人方信落江東，開解愁顔與病悰。',32,'全唐诗/poet.song.23000.json','["故人方信落江東，開解愁顔與病悰。", "自笑漫生湖海上，略無豪氣似元龍。"]'),
('a3da2db7-fcbe-461b-82fb-6557b76309ed','次韵六安魏明府三首  其二','陳舜俞','宋','宋诗','song-poetry','','[]','少年心志欲摩空，漸老卑飛悔滿悰。',32,'全唐诗/poet.song.23000.json','["少年心志欲摩空，漸老卑飛悔滿悰。", "早悟割鷄堪飽腹，不須辛苦學屠龍。"]'),
('657a0e6a-2b52-4f0a-b062-7c84eb3a28e5','次韵六安魏明府三首  其三','陳舜俞','宋','宋诗','song-poetry','','[]','幾慕功名逐轉蓬，既無成就苦爲悰。',32,'全唐诗/poet.song.23000.json','["幾慕功名逐轉蓬，既無成就苦爲悰。", "不如歸聽華亭鶴，耆舊於今憶二龍。"]'),
('36a40e1a-c40c-43c2-84f1-e3062bbdaa28','寶慶院','陳舜俞','宋','宋诗','song-poetry','','[]','小招提在白雲層，古殿深龕鎖晝燈。',32,'全唐诗/poet.song.23000.json','["小招提在白雲層，古殿深龕鎖晝燈。", "山北遠公曾結社，至今猶有種蓮僧。"]'),
('d6a07e8c-2742-4706-a57b-df409c4a0c59','題鑪峰閣','陳舜俞','宋','宋诗','song-poetry','','[]','爲愛鑪烟拂畫檐，小欄今日捲朱簾。',32,'全唐诗/poet.song.23000.json','["爲愛鑪烟拂畫檐，小欄今日捲朱簾。", "不須更踏山前路，可是人間看得厭。"]'),
('d8222c08-e36c-4062-bd57-2ee47a6c96a7','再經太平觀訪沈道士不遇二首  其一','陳舜俞','宋','宋诗','song-poetry','','[]','行客尋山去又回，羽人依舊未歸來。',32,'全唐诗/poet.song.23000.json','["行客尋山去又回，羽人依舊未歸來。", "洞門不鎖清風入，黄葉無言下翠苔。"]'),
('17d2eeb9-ac9f-417b-a703-e3f5e272d690','再經太平觀訪沈道士不遇二首  其二','陳舜俞','宋','宋诗','song-poetry','','[]','不見芝巖駕鶴翁，抱琴歸去悄無蹤。',32,'全唐诗/poet.song.23000.json','["不見芝巖駕鶴翁，抱琴歸去悄無蹤。", "黄花似有東籬舊，山後山前取次逢。"]'),
('9dcd73cd-7fdd-4a32-af37-1155339933c1','興福院僧房','陳舜俞','宋','宋诗','song-poetry','','[]','東西遊遍兩山村，梔子黄時橘滿園。',32,'全唐诗/poet.song.23000.json','["東西遊遍兩山村，梔子黄時橘滿園。", "唯有小軒臨小澗，病僧欹枕聽潺湲。"]'),
('980e2776-9165-4645-ae36-0143d5477a9b','宿上真宮贈朱道士','陳舜俞','宋','宋诗','song-poetry','','[]','栖真必是朱癡後，結宇元因法善孫。',32,'全唐诗/poet.song.23000.json','["栖真必是朱癡後，結宇元因法善孫。", "人在地靈治病速，山村討藥夜敲門。"]'),
('32dbd508-502d-4d91-97b3-f42da36a27f9','書通濟僧壁','陳舜俞','宋','宋诗','song-poetry','','[]','丹包赤實破蒼顔，冬至都無十日閒。',32,'全唐诗/poet.song.23000.json','["丹包赤實破蒼顔，冬至都無十日閒。", "剩選黄柑留過客，天寒誰肯更尋山。"]'),
('d10c6d6e-34c0-45dd-880a-d040b4adb3a1','上方僧京師識面短句二首  其一','陳舜俞','宋','宋诗','song-poetry','','[]','亂雲峰頂紫田翁，二十年前輦寺逢。',32,'全唐诗/poet.song.23000.json','["亂雲峰頂紫田翁，二十年前輦寺逢。", "怪我無成頭白早，千金散盡學屠龍。"]'),
('0f76038f-3b64-4e4e-9612-6c7dd4230abf','上方僧京師識面短句二首  其二','陳舜俞','宋','宋诗','song-poetry','','[]','老僧曾住日邊寺，慣識金鞍馬上人。',32,'全唐诗/poet.song.23000.json','["老僧曾住日邊寺，慣識金鞍馬上人。", "雲外不知人易老，從頭相問盡埃塵。"]'),
('287d96de-020b-4d3d-8d98-1617bf03d0cb','贈華嚴院玉真上人','陳舜俞','宋','宋诗','song-poetry','','[]','青蘿翠竹鎖禪關，門對松林第一灣。',32,'全唐诗/poet.song.23000.json','["青蘿翠竹鎖禪關，門對松林第一灣。", "白髪老禪應有道，等閒隨客過前山。"]'),
('3b6a4067-af09-4ae9-a798-5798a848ed40','上方化成院','陳舜俞','宋','宋诗','song-poetry','','[]','琅函密鎖君王字，石壁仍刊宰相詩。',32,'全唐诗/poet.song.23000.json','["琅函密鎖君王字，石壁仍刊宰相詩。", "無限幽光動巖谷，山深惟有白雲知。"]'),
('a459c6bb-5545-43cf-a655-02e3052fd50d','虎溪','陳舜俞','宋','宋诗','song-poetry','','[]','紫霄道士貪雲鶴，五柳先生泥酒杯。',32,'全唐诗/poet.song.23000.json','["紫霄道士貪雲鶴，五柳先生泥酒杯。", "不爲清風與明月，道人何事過溪來。"]'),
('4c136afb-f1c5-4e30-98d4-7f64268ec972','遊天章寺','陳舜俞','宋','宋诗','song-poetry','','[]','峻嶺崇巔千古在，好風佳月逐時新。',64,'全唐诗/poet.song.23000.json','["峻嶺崇巔千古在，好風佳月逐時新。", "簿書偶是山陰長，觴詠聊同曲水人。", "林雀不驚筇竹杖，谿雲欲傍接䍦巾。", "官粗合有登臨分，更待巖花爛漫春。"]'),
('e1a9f022-dac7-46c7-835a-7cb9c2370ecb','衆樂亭','陳舜俞','宋','宋诗','song-poetry','','[]','湖光野色著人衣，衆樂開亭此處宜。',64,'全唐诗/poet.song.23000.json','["湖光野色著人衣，衆樂開亭此處宜。", "擊櫂高歌山自響，踏青紅影岸相隨。", "消除矰繳容鷗鳥，改換風烟入柳絲。", "荇菜藕花應見憶，短蓬孤榜獨來時。"]'),
('8c3c6b6e-4105-420a-828c-6567857318b8','西湖','陳舜俞','宋','宋诗','song-poetry','','["\u897f\u6e56"]','古山瀉仙源，坤輿鑿虛境。',60,'全唐诗/poet.song.23000.json','["古山瀉仙源，坤輿鑿虛境。", "寶勢相回環，穴闌清倒影。", "群冰人無驚，泛泛華槳并。", "山上放歌行，不少有遺景。", "誰意注靈波，溉田三萬頃。"]'),
('6ed83651-66e0-4b6e-8510-dc6934513375','蛙齋','陳舜俞','宋','宋诗','song-poetry','','[]','渴飲嘗不足，鑿井偶清疏。',156,'全唐诗/poet.song.23000.json','["渴飲嘗不足，鑿井偶清疏。", "井邊舊牆屋，塗塈爲我居。", "念彼作者勞，容膝已有餘。", "開窗近檐楹，天光滿圖書。", "汲水屢灑掃，塵去延空虛。", "外潔內亦清，體胖氣加舒。", "緬懷埳中蛙，樂豈羨蝦魚。", "相君宅新府，文木森周廬。", "侯門多結駟，賜金每論車。", "身外無我親，儻來物固疏。", "日食夜以息，大小則皆如。", "况無百歲人，貴賤同丘墟。", "但可蔽風雨，且以永居諸。"]'),
('96687124-b634-4ab1-9762-3a22829eefd9','初見廬山','陳舜俞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','泝洄江上山，千里皆可愛。',120,'全唐诗/poet.song.23000.json','["泝洄江上山，千里皆可愛。", "忽見匡廬峰，氣勢一何大。", "崔嵬青天屏，靉靆白雲蓋。", "藤蘿拂金繩，瀑水挂玉带。", "未雨龍穴藏，摩空鳥飛礙。", "疑非紅塵間，邈在萬物外。", "聞有高世士，眠雲不知載。", "飲露餐朝霞，嘯月下天籟。", "軒冕何足道，天地乃投芥。", "吾能與之遊，無庸去浮海。"]'),
('39c4462a-7bfc-4a7b-93c5-5b6ab79685d7','詩二首  其一','陳舜俞','宋','宋诗','song-poetry','','[]','石磴梯山一里高，荒烟源處稅漁樵。',32,'全唐诗/poet.song.23000.json','["石磴梯山一里高，荒烟源處稅漁樵。", "官粗事冷人應笑，免對青苗强折腰。"]'),
('ae720161-fe41-4295-907e-170339468e8a','詩二首  其二','陳舜俞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','自古匡廬是勝遊，謫臣何敢計淹留。',32,'全唐诗/poet.song.23000.json','["自古匡廬是勝遊，謫臣何敢計淹留。", "城中未有看山處，客館僧坊謾舉頭。"]'),
('3ed4185c-215c-4fb6-beaf-94d7cc22355f','慮獄江州晚出潯陽門','陳舜俞','宋','宋诗','song-poetry','','[]','淺深秋色看紅葉，高下人烟入翠微。',64,'全唐诗/poet.song.23000.json','["淺深秋色看紅葉，高下人烟入翠微。", "過嶺已憐雲滿𩍐，穿林寧恨露沾衣。", "自慚訪道來何晚，便好尋真去不歸。", "本迕朝廷無補報，名山猶幸許相依。"]'),
('4eb8277f-c6d0-4968-b5af-f379731762bf','黄陵廟','陳舜俞','宋','宋诗','song-poetry','','[]','明月輝在天，落日光轉地。',84,'全唐诗/poet.song.23000.json','["明月輝在天，落日光轉地。", "天維地軸千萬年，粉篁尚有春風淚。", "蒼梧茫茫九疑高，湘江之水多怒濤。", "袗衣不御琴弦絕，黄陵廟前碑已裂。", "春禽啼，秋葉飛。", "行人舟楫去復返，虞舜南巡胡不歸。"]'),
('0820a661-91db-4989-ba42-0e8aaadf25cd','圓通行','陳舜俞','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山之西形勢聚，無位真人依位住。',208,'全唐诗/poet.song.23000.json','["廬山之西形勢聚，無位真人依位住。", "地祇掣鎖金城開，石龍噴水銀潢注。", "峰巒約勒萬馬回，杉松自作千兵護。", "寶殿崢嶸跨碧霄，圓容麗服微西顧。", "江南妃子親施田，香飯供僧無億數。", "法焰相傳十二人，師泛鐵船楊子渡。", "楊子渡頭秋風高，霹靂駕雪翻驚濤。", "中有漁家妙絕手，一釣三山連六鰲。", "縱時大地悉震恐，收來塵剎無纖毫。", "當年曾許心莫逆，今朝又作圓通客。", "挂冠已脫塵俗緣，一心願住清凉國。", "清凉之國進能知，日長馬倦人多迷。", "從來聞說曹溪路，只今踏斷廬山西。"]'),
('d9084977-3540-4cf7-bf76-389130919923','詩一首','陳舜俞','宋','宋诗','song-poetry','','[]','把酒謂山語，行人亦大孤。',48,'全唐诗/poet.song.23000.json','["把酒謂山語，行人亦大孤。", "滿朝無骨肉，白髪厭江湖。", "寒苦諳冰雪，艱難識道途。", "相看幸相似，可惜便風無。"]'),
('62b7e0a6-5682-4d8b-9a3d-a21859594c9b','子隠堂爲蕭寺題','陳舜俞','宋','宋诗','song-poetry','','[]','東城蕭寺荒烟內，底事旌旗與客來。',64,'全唐诗/poet.song.23000.json','["東城蕭寺荒烟內，底事旌旗與客來。", "六代豪華歸茂草，少年風節有高臺。", "門前好鳥鳴佳木，徑裏閒僧掃綠苔。", "强爲登臨一懷古，懦夫蕪句兩非才。"]'),
('4db83375-979f-439c-80b1-7064cae64507','奉慈禪寺','陳舜俞','宋','宋诗','song-poetry','','[]','一宿禪關萬慮空，明朝更上十餘峰。',64,'全唐诗/poet.song.23000.json','["一宿禪關萬慮空，明朝更上十餘峰。", "山依碧落不多遠，人在白雲無數重。", "木末疏鐘驚虎兕，門前潴水穴蛟龍。", "勞生正負林泉約，猶喜官閒此處逢。"]'),
('7833cecd-7bc9-4476-8b40-0d2a05eb7028','句  其一','陳舜俞','宋','宋诗','song-poetry','','[]','石間圓影疊金波。',8,'全唐诗/poet.song.23000.json','["石間圓影疊金波。"]'),
('f4e5f78f-b2b9-40dc-9684-a7479e827959','句  其二','陳舜俞','宋','宋诗','song-poetry','','[]','澗含蒼壁隠青蘿。',8,'全唐诗/poet.song.23000.json','["澗含蒼壁隠青蘿。"]'),
('16076723-63e0-4aa1-a0dc-532418cb9f32','公安縣','陶弼','宋','宋诗','song-poetry','','[]','門沿大堤入，路趁淺莎行。',48,'全唐诗/poet.song.23000.json','["門沿大堤入，路趁淺莎行。", "樹短雲根拔，山窮地勢傾。", "孤舟難泊岸，遠水欲沈城。", "半夜求津濟，煙中荻火明。"]'),
('003a0d3c-7f50-444b-badf-898a3839eb57','丁香','陶弼','宋','宋诗','song-poetry','','[]','萬枝千葉遞相親，內結花心外結身。',32,'全唐诗/poet.song.23000.json','["萬枝千葉遞相親，內結花心外結身。", "草木至微猶有合，悲哉父子與君臣。"]'),
('3af4ad12-2e31-42ad-88b7-1e2e50c5ea62','桐','陶弼','宋','宋诗','song-poetry','','[]','老桐休斲爲琴瑟，胡部新翻格調清。',32,'全唐诗/poet.song.23000.json','["老桐休斲爲琴瑟，胡部新翻格調清。", "試聽琵琶采蓮曲，一般弦上數般聲。"]'),
('f9d8e1b7-46a8-4fad-ac85-a617534189e0','柳','陶弼','宋','宋诗','song-poetry','','[]','楊子江頭流水澌，長安陌上暖風吹。',64,'全唐诗/poet.song.23000.json','["楊子江頭流水澌，長安陌上暖風吹。", "黄金瓔珞雪晴後，碧玉瓏璁春盡時。", "端的園林俱不及，等閒臺榭便相宜。", "思量也是多情物，占與人間贈別離。"]'),
('6536a66d-5877-4b09-8aa2-4c6a4ea199b0','鷄頭','陶弼','宋','宋诗','song-poetry','','[]','三伏池塘沸，鷄頭美可烹。',48,'全唐诗/poet.song.23000.json','["三伏池塘沸，鷄頭美可烹。", "香囊連錦破，玉指剝珠明。", "葉皺非蓮蓋，根甘似竹萌。", "不應徒適口，炎帝亦曾名。"]'),
('e08e7522-85f4-4e9c-9d13-19444be84276','桃','陶弼','宋','宋诗','song-poetry','','[]','樹正含芳酒正醅，熙熙爲爾醉春臺。',32,'全唐诗/poet.song.23000.json','["樹正含芳酒正醅，熙熙爲爾醉春臺。", "一花五出尚可飲，何况重重疊疊開。"]'),
('f9687bb0-68f3-4146-b207-1a401aadd444','李','陶弼','宋','宋诗','song-poetry','','[]','春晝暖風熏翠幄，暑天凉氣暗朱闌。',32,'全唐诗/poet.song.23000.json','["春晝暖風熏翠幄，暑天凉氣暗朱闌。", "主人肝膽無猜忌，果下游人但整冠。"]'),
('b4b2e3dc-3c89-4ce3-9cea-d88c726d54d1','兵器','陶弼','宋','宋诗','song-poetry','','[]','五代乏真主，奸雄紛僭僞。',288,'全唐诗/poet.song.23000.json','["五代乏真主，奸雄紛僭僞。", "橫磨闊刀劍，白日相篡弒。", "我宋有神祖，潛德動天意。", "故天意若曰，往爲我之嗣。", "神祖拜稽首，乃即皇帝位。", "不惠兆民樂，不怒諸侯畏。", "顛倒執玉帛，奔走恐後至。", "大商國三分，一朝有其二。", "太宗以義撫，真宗以仁治。", "王道竹箭直，誦聲金鼎沸。", "獨有陰山戎，時時寇邊地。", "天子赫斯怒，大警巡澶衛。", "射殺右賢王，遂斬匈奴臂。", "狼心帖然服，結好同昆弟。", "自此兩河間，寂寂無戎備。", "卒閑喜夜歌，將老貪春睡。", "自此爲太平，恍逾三十歲。", "戎昊乘我間，南馳賀蘭騎。", "陽關久夜開，樞朽不可閉。", "陣雲起秦雍，殺氣橫涇渭。", "使臣股栗奏，宰相瞋目議。", "僉曰亟發兵，豎子坑甚易。", "倉皇築邊壘，未戰力先瘁。", "遇迫開庫兵，土蝕鋒芒脆。"]'),
('412137ab-a833-4dad-a6a6-e86c07d02b50','食楊梅','陶弼','宋','宋诗','song-poetry','','[]','嶺北土寒無荔子，人言形味似楊梅。',32,'全唐诗/poet.song.23000.json','["嶺北土寒無荔子，人言形味似楊梅。", "翠條丹實休相學，不願紅塵一騎來。"]'),
('fb5455d4-16ec-438a-a7aa-04c1e691beae','滴露花','陶弼','宋','宋诗','song-poetry','','[]','九天瑞露滴成芽，不是榆花即桂花。',32,'全唐诗/poet.song.23000.json','["九天瑞露滴成芽，不是榆花即桂花。", "星女月娥宮不鎖，天風吹落野人家。"]'),
('5c620bdf-93bc-4de9-a5f8-5cb6936f03aa','送趙樞寺丞宰虔化縣','陶弼','宋','宋诗','song-poetry','','[]','路入虔雲去，如何輕解携。',48,'全唐诗/poet.song.23000.json','["路入虔雲去，如何輕解携。", "人煙五嶺北，星斗大江西。", "暖雪梅花樹，晴雷贛石溪。", "青衫欲無淚，不奈鷓鴣啼。"]'),
('7c30858b-9c72-4516-8db7-93c99a6698bc','荔支','陶弼','宋','宋诗','song-poetry','','[]','五月南游渴，欣逢荔子丹。',120,'全唐诗/poet.song.23000.json','["五月南游渴，欣逢荔子丹。", "殻勻仙鶴頂，肉露白晶丸。", "色映離爲火，甘殊木作酸。", "枝繁恐相染，樹重欲成團。", "赤蚌遺珠顆，紅犀露角端。", "爽能消內熱，潤可濯中乾。", "桂嶺無霜處，梅天暴雨殘。", "□□□□□，□□□□□。", "一簇冰蠶繭，千苞火鳳冠。", "隔瓤銀葉嫩，透膜玉漿寒。"]'),
('17e874e6-d760-493c-9d62-4092f96bb657','出嶺題石灰鋪','陶弼','宋','宋诗','song-poetry','','[]','馬度嚴關口，生歸喜復嗟。',48,'全唐诗/poet.song.23000.json','["馬度嚴關口，生歸喜復嗟。", "天文離卷舌，人影背含沙。", "江勢一兩曲，梅梢三四花。", "登高休問路，雲下是吾家。"]'),
('3693c182-fdb0-4a52-bf74-ffd93c3e0a03','山茶花二首  其一','陶弼','宋','宋诗','song-poetry','','[]','淺爲玉茗深都勝，大曰山茶小樹紅。',32,'全唐诗/poet.song.23000.json','["淺爲玉茗深都勝，大曰山茶小樹紅。", "名譽漫多朋援少，年年身在雪霜中。"]'),
('af766927-f927-4cca-85ea-e6619a476fd1','山茶花二首  其二','陶弼','宋','宋诗','song-poetry','','[]','江南池館厭深紅，零落空山煙雨中。',32,'全唐诗/poet.song.23000.json','["江南池館厭深紅，零落空山煙雨中。", "却是北人偏愛惜，數枝和雪上屏風。"]'),
('88e9bd6d-c5d4-4397-83f6-cebe675b299e','途次葉縣觀千葉桃花','陶弼','宋','宋诗','song-poetry','','[]','三月宮桃滿上林，百花千萼費春心。',32,'全唐诗/poet.song.23000.json','["三月宮桃滿上林，百花千萼費春心。", "葉公城外襄河北，一樹無人色更深。"]'),
('c9fcb432-a719-4010-8e01-fc5d24b17a9f','登潮月亭','陶弼','宋','宋诗','song-poetry','','[]','渡頭人語知潮上，下看南江東北流。',32,'全唐诗/poet.song.23000.json','["渡頭人語知潮上，下看南江東北流。", "試引輕帆學歸去，茶山溪淺却回舟。"]'),
('b4576e1d-10b0-4b99-b222-8a6664928f3a','對花有感','陶弼','宋','宋诗','song-poetry','','[]','得莫欣欣失莫悲，古今人事若花枝。',32,'全唐诗/poet.song.23000.json','["得莫欣欣失莫悲，古今人事若花枝。", "桃紅李白薔薇紫，問著春風總不知。"]'),
('1533beaf-bdb3-4ec1-b668-fa0ffe2e9563','紫薇花','陶弼','宋','宋诗','song-poetry','','[]','人言清禁紫薇郎，草詔紫薇花影旁。',32,'全唐诗/poet.song.23000.json','["人言清禁紫薇郎，草詔紫薇花影旁。", "山木不知官况別，也隨紅白上東廊。"]'),
('e4138b1e-72d9-4553-88ce-14eb5a021200','園居','陶弼','宋','宋诗','song-poetry','','[]','篁韵松濤入耳清，誅茅欣見徑初成。',32,'全唐诗/poet.song.23000.json','["篁韵松濤入耳清，誅茅欣見徑初成。", "更添蒼柏兩三輩，相伴高枝作雨聲。"]'),
('1de6651b-a38f-4f64-8e3a-39bad684caf7','題陽朔縣舍','陶弼','宋','宋诗','song-poetry','','[]','石壁高深繞縣衙，不離床衽自煙霞。',64,'全唐诗/poet.song.23000.json','["石壁高深繞縣衙，不離床衽自煙霞。", "民耕紫芋爲朝食，僧煮黄精代晚茶。", "瀑布聲中窺案牘，女蘿陰裏勸桑麻。", "欲知言偃弦歌化，水墨屏風數百家。"]'),
('a23ad5be-7f76-41ef-86ed-e1a6749343c3','天涯亭','陶弼','宋','宋诗','song-poetry','','[]','雨色絲絲風色嬌，天涯亭上覺魂消。',64,'全唐诗/poet.song.23000.json','["雨色絲絲風色嬌，天涯亭上覺魂消。", "一家生意付秋瘴，萬里歸心隨暮潮。", "兵送遠人還海界，吏申遷客入津橋。", "山公對此聊酣飲，怕見醒來兩鬢凋。"]'),
('9b212651-4f48-410b-8878-4fc22d923958','題烟霞驛','陶弼','宋','宋诗','song-poetry','','[]','歌聲野色中，人樂歲時豐。',48,'全唐诗/poet.song.23000.json','["歌聲野色中，人樂歲時豐。", "暑雨陰陽雜，秋田早晚同。", "嶺雲無烈日，江樹足凉風。", "自指香山語，前村有路通。"]'),
('051e8fc6-1236-4a79-9d58-33d22c3216ef','登崑崙臺','陶弼','宋','宋诗','song-poetry','','[]','落照古城隅，邊風動隼旟。',48,'全唐诗/poet.song.23000.json','["落照古城隅，邊風動隼旟。", "久閒忘戰略，多病熟醫書。", "白髪隨年短，新情與世疏。", "桃花春水起，還釣舊溪漁。"]'),
('8955c3ac-a396-4724-920c-0cf3e76e3930','秋日登南城臺','陶弼','宋','宋诗','song-poetry','','[]','江國家書少，秋臺寒草生。',48,'全唐诗/poet.song.23000.json','["江國家書少，秋臺寒草生。", "無人來遠渡，盡日上高城。", "落照懸漁市，孤烟起戍營。", "東籬故園菊，又向酒中傾。"]'),
('827665fe-efd4-4aa2-bc01-6621af82a025','過思明','陶弼','宋','宋诗','song-poetry','','[]','幾年來瘴外，此夜宿溪中。',48,'全唐诗/poet.song.23000.json','["幾年來瘴外，此夜宿溪中。", "照枕殘鷄月，吹燈落葉風。", "盧循猶僞國，楊僕已衰翁。", "起戴寒星去，前村燒影紅。"]'),
('20547660-3028-4ccf-ae33-14e45d180935','閣皁','陶弼','宋','宋诗','song-poetry','','[]','萬仞天然皁閣形，陰陽不似衆山青。',64,'全唐诗/poet.song.23000.json','["萬仞天然皁閣形，陰陽不似衆山青。", "一區海上神仙宅，數曲人間水墨屏。", "華表鶴歸春谷響，玉京龍起夜潭腥。", "可憐張葛無人繼，三級高壇拂杳冥。"]'),
('96938b3b-4d96-4fa5-b5d5-de7871136dee','東湖','陶弼','宋','宋诗','song-poetry','','[]','寧越佳山水，東湖带郡城。',48,'全唐诗/poet.song.23000.json','["寧越佳山水，東湖带郡城。", "月天高寺影，春雨一橋聲。", "石上青蒲合，沙中白鳥橫。", "天涯正寥落，獨往若爲情。"]'),
('c06a3936-0151-4963-add5-78c199c1286f','西湖','陶弼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寧越佳山水，西湖似浙城。',48,'全唐诗/poet.song.23000.json','["寧越佳山水，西湖似浙城。", "桂多天竺子，潮欠海門聲。", "路向林梢轉，天隨野色橫。", "從茲棲泊者，無復渡江情。"]'),
('5a69f464-ac7f-4b42-a2bf-788388777caa','柑子堂','陶弼','宋','宋诗','song-poetry','','[]','子厚才名甲有唐，謫官分得荔支鄉。',32,'全唐诗/poet.song.23000.json','["子厚才名甲有唐，謫官分得荔支鄉。", "羅池水盡黄柑死，獨有空碑在畫堂。"]'),
('d76b0e7a-9845-42d7-b295-76ce101fc58a','邕州','陶弼','宋','宋诗','song-poetry','','[]','南極諸蠻傲典刑，斗門時復見飛星。',32,'全唐诗/poet.song.23000.json','["南極諸蠻傲典刑，斗門時復見飛星。", "君王仁恕將軍老，五十溪州六萬丁。"]'),
('ac534ce1-f20a-4153-907c-ef04835b0bb6','廉州石','陶弼','宋','宋诗','song-poetry','','[]','使君合浦來，示我海濱石。',24,'全唐诗/poet.song.23000.json','["使君合浦來，示我海濱石。", "千巖秀掌上，大者不盈尺。"]'),
('d316d2e7-5a96-4494-b6ad-8ce2caba37ce','合浦還珠亭','陶弼','宋','宋诗','song-poetry','','[]','合浦還珠舊有亭，使君方似古人清。',32,'全唐诗/poet.song.23000.json','["合浦還珠舊有亭，使君方似古人清。", "沙中蚌蛤胎常滿，潭底蛟龍睡不驚。"]'),
('038563c9-421d-4a2a-8e14-cac198d4e87a','送呂濤典獄之梧州','陶弼','宋','宋诗','song-poetry','','[]','峽口蒼梧縣，城依南斗魁。',48,'全唐诗/poet.song.23000.json','["峽口蒼梧縣，城依南斗魁。", "江渾海潮上，地熱火山來。", "草沒嘉魚穴，雲封拜表臺。", "到應無獄訟，豆蔻酒頻開。"]'),
('2bbd7101-d108-445d-bfb1-2a10f8a92e86','融州仙巖','陶弼','宋','宋诗','song-poetry','','[]','溪僧過此說山公，遊遍真仙洞府中。',32,'全唐诗/poet.song.23000.json','["溪僧過此說山公，遊遍真仙洞府中。", "乳石巖邊得靈草，可能封裹寄衰翁。"]'),
('3ea16e78-100c-4946-afe6-8d42ae212869','賓州仙影山','陶弼','宋','宋诗','song-poetry','','[]','月氅星冠七丈夫，遠看雖有近還無。',32,'全唐诗/poet.song.23000.json','["月氅星冠七丈夫，遠看雖有近還無。", "瑶池侍女雙成道，遺下群仙聚影圖。"]'),
('3043fee8-d6c7-45da-9b8e-f5abfd78ffbd','安城即事二首  其一','陶弼','宋','宋诗','song-poetry','','[]','南嶠風雲久肅清，壞溝殘壘號昇平。',64,'全唐诗/poet.song.23000.json','["南嶠風雲久肅清，壞溝殘壘號昇平。", "官曹惟識簿書字，民俗不知金鼓聲。", "往歲傳聞南詔檄，近時方築伏波城。", "安城太守知邊計，菡萏花中閱水兵。"]'),
('38ed39a7-3ee0-470e-b52d-76ed1eb144a0','安城即事二首  其二','陶弼','宋','宋诗','song-poetry','','[]','金鼓聲闌劍戟收，使君回上雅歌樓。',32,'全唐诗/poet.song.23000.json','["金鼓聲闌劍戟收，使君回上雅歌樓。", "樽前一節清商曲，銷盡窮邊萬里愁。"]'),
('d23422ea-318d-432a-b9a2-ba4a0e64ac79','容管','陶弼','宋','宋诗','song-poetry','','[]','一年勾漏守，尋盡洞中天。',48,'全唐诗/poet.song.23000.json','["一年勾漏守，尋盡洞中天。", "佛記盧藏用，仙壇葛稚川。", "醒心西驛水，燒眼碧池蓮。", "我豈無新事，詩碑與酒泉。"]'),
('6ca92762-e432-4455-9faf-36cd27c47c68','送臨桂令戴若納出嶺','陶弼','宋','宋诗','song-poetry','','[]','五嶺生還少，無辭酒滿觴。',48,'全唐诗/poet.song.23000.json','["五嶺生還少，無辭酒滿觴。", "共經邊寇事，先出瘴煙鄉。", "楚樹蟬聲早，湖天日影凉。", "此行休問路，宮闕斗杓旁。"]'),
('ff66ce65-d835-467b-8374-f7d0cf35e067','陽朔縣','陶弼','宋','宋诗','song-poetry','','[]','五管新多事，輕車屢往還。',48,'全唐诗/poet.song.23000.json','["五管新多事，輕車屢往還。", "勤勞成白髪，故舊是青山。", "樹色纔分楚，江聲未出蠻。", "自慚迎候少，無惠及孤鰥。"]'),
('e4851d9b-4acf-43b0-92b0-d9489fea5cc1','贈章使君','陶弼','宋','宋诗','song-poetry','','[]','善戰無如新息侯，漢兵纔度綠蘿州。',32,'全唐诗/poet.song.23000.json','["善戰無如新息侯，漢兵纔度綠蘿州。", "愛君挽我陶溪粟，直到牂牁水口頭。"]'),
('369226b4-aed0-467d-9c10-371a2470dad6','宜陽','陶弼','宋','宋诗','song-poetry','','[]','孤城溪洞裏，聞說已堪哀。',48,'全唐诗/poet.song.23000.json','["孤城溪洞裏，聞說已堪哀。", "蠻水如鮮血，瘴天已死灰。", "吏憂民置毒，巫幸鬼爲災。", "風土如斯惡，吾來胡爲哉。"]'),
('bd43f0df-8dda-47fd-8fe0-012362ee7cfd','寄鬰林郡守姚道源','陶弼','宋','宋诗','song-poetry','','[]','越裳濟海喜天晴，五葉戈船不度兵。',32,'全唐诗/poet.song.23000.json','["越裳濟海喜天晴，五葉戈船不度兵。", "堯舜遠方皆樂國，漢唐諸將本書生。"]'),
('3a1392a2-eea1-468b-b393-83c867f6d3d3','膏澤峰','陶弼','宋','宋诗','song-poetry','','[]','石壁含天澤，南山第一重。',48,'全唐诗/poet.song.23000.json','["石壁含天澤，南山第一重。", "旱時先出雨，陰穴又乘龍。", "雲影摇諸壑，雷聲起半空。", "何當大滂沛，盡活四方農。"]'),
('1c710c9d-0088-484d-9856-9f915cc6b731','登邕州城','陶弼','宋','宋诗','song-poetry','','[]','夜半孤城百尺臺，亂蟲聲裏一樽開。',32,'全唐诗/poet.song.23000.json','["夜半孤城百尺臺，亂蟲聲裏一樽開。", "憂邊日繞南雲下，戀闕心隨北斗迴。"]'),
('0fd6aad4-6595-4bdc-8c6b-981b5c68979c','丹竈山','陶弼','宋','宋诗','song-poetry','','[]','羽客朝元地，遺壇古寺中。',24,'全唐诗/poet.song.23000.json','["羽客朝元地，遺壇古寺中。", "煉成丹竈在，騎去鶴巢空。"]'),
('f1e78c70-fac6-4fcf-ac58-4e26893c44f1','思柳亭','陶弼','宋','宋诗','song-poetry','','[]','羅池刺史寡塵緣，畫戟牆頭築望仙。',32,'全唐诗/poet.song.23000.json','["羅池刺史寡塵緣，畫戟牆頭築望仙。", "黄鶴與誰同一去，碧桃無主又千年。"]'),
('4c01e704-cac8-4495-ae2c-c3107ff69498','鬰林鼓角樓','陶弼','宋','宋诗','song-poetry','','[]','去歲同登畫角城，諸蠻未滅夜論兵。',32,'全唐诗/poet.song.23000.json','["去歲同登畫角城，諸蠻未滅夜論兵。", "五更將吏知人意，吹作梅花塞外聲。"]'),
('3919a0b0-0d00-49a5-bdf7-7ee6580894a7','春野亭','陶弼','宋','宋诗','song-poetry','','[]','二紀看花瘴霧中，野園今日又東風。',64,'全唐诗/poet.song.23000.json','["二紀看花瘴霧中，野園今日又東風。", "人心有感時時別，春色無私處處同。", "長笛一聲諸曲盡，巨觥雙飲百愁空。", "風清水暖群魚上，誰向荆溪占釣筒。"]'),
('ef87de1e-978d-44a1-b7ad-5a526551b3cc','會仙巖','陶弼','宋','宋诗','song-poetry','','[]','寂寂長冥洞，涓涓漱玉泉。',48,'全唐诗/poet.song.23000.json','["寂寂長冥洞，涓涓漱玉泉。", "鳳笙聞夜半，鶴馭認雲邊。", "煮茗尋安老，披莎訪稚川。", "于中得消息，何用買山錢。"]'),
('7807a7d5-c663-4c42-94de-a073b80b77bb','羅秀山','陶弼','宋','宋诗','song-poetry','','[]','尋山入羅秀，旋結草堂居。',48,'全唐诗/poet.song.23000.json','["尋山入羅秀，旋結草堂居。", "花露生瓶水，松風落架書。", "聞猿得句後，見月出行初。", "此夕雲林下，無因夢使車。"]'),
('77eea8f0-6ec5-4888-9671-a7743c7a1977','莫鋣關','陶弼','宋','宋诗','song-poetry','','[]','三任邊州六往還，此時纔入莫鋣關。',32,'全唐诗/poet.song.23000.json','["三任邊州六往還，此時纔入莫鋣關。", "訪僧莫道無閑事，手指青天口說山。"]'),
('47dc774d-08ae-4022-8b95-fff2612b3be0','那霸泉','陶弼','宋','宋诗','song-poetry','','[]','昔年觀地志，此水出牂牁。',48,'全唐诗/poet.song.23000.json','["昔年觀地志，此水出牂牁。", "斷岸深無底，平流暗起波。", "感恩來客少，射影短狐多。", "未老諸蠻在，樓船空再過。"]'),
('7da243cd-f73b-45c3-9292-4cf971d5530b','又','陶弼','宋','宋诗','song-poetry','','[]','路下牂牁水石閒，三分纔過二分山。',64,'全唐诗/poet.song.23000.json','["路下牂牁水石閒，三分纔過二分山。", "年光欲盡家猶遠，嵐氣雖疏鬢已斑。", "賓從談笑機獨進，兒曹音信喜生還。", "南風一夜吹鄉夢，數刻飛過五嶺間。"]'),
('ca4dc5f0-f242-42c1-b328-21cb2ccf596c','碧湘門','陶弼','宋','宋诗','song-poetry','','[]','城中烟樹綠波漫，幾萬樓臺樹影間。',64,'全唐诗/poet.song.23000.json','["城中烟樹綠波漫，幾萬樓臺樹影間。", "天闊鳥行疑沒草，地卑江勢欲沉山。", "人過鹿死尋僧去，船自新康載酒還。", "聞說耕桑漸蘇息，嶺頭今歲不征蠻。"]'),
('4b316d89-6fe9-40b5-a07b-d7f4033a02c7','黄陵廟','陶弼','宋','宋诗','song-poetry','','[]','溪上龍蛇屋，蕭條帝子祠。',48,'全唐诗/poet.song.23000.json','["溪上龍蛇屋，蕭條帝子祠。", "竹痕當日淚，山色後人疑。", "仙服霞留綺，新裝月印眉。", "楚民亡水旱，簫鼓謝神禧。"]'),
('0b76da96-e057-407b-9900-9d7361a2856e','司馬錯城','陶弼','宋','宋诗','song-poetry','','[]','北設長城陷敵塵，更來勞力武陵民。',32,'全唐诗/poet.song.23000.json','["北設長城陷敵塵，更來勞力武陵民。", "我疑洞裏栽桃者，便是當時築版人。"]'),
('1a41a5e1-42b6-4ec8-8969-451efe20b860','辰州','陶弼','宋','宋诗','song-poetry','','[]','詔條符節古連今，王澤漸濡豈不深。',64,'全唐诗/poet.song.23000.json','["詔條符節古連今，王澤漸濡豈不深。", "賦役未行中國法，謳歌猶带遠人音。", "採金戶簇青莎岸，射虎兵圍黄葉林。", "寄語湖南灘上客，預將忠信待浮沉。"]'),
('0372aa3d-d8ca-4bf3-a737-62d75d9f1eb7','寄沅州新守謝麟','陶弼','宋','宋诗','song-poetry','','[]','險盡天開溪路平，詩書新將典新城。',64,'全唐诗/poet.song.23000.json','["險盡天開溪路平，詩書新將典新城。", "三千戍卒今無幾，十萬屯田古未耕。", "屬縣乞除防虎檻，生蠻願獻採砂坑。", "從茲預擬風塵息，盡是仁威下旆旌。"]'),
('a0a5d4c6-8afb-47a4-a9ac-465c4e019937','白霧驛','陶弼','宋','宋诗','song-poetry','','[]','一曲青溪一曲山，鳥飛魚躍白雲閒。',32,'全唐诗/poet.song.23000.json','["一曲青溪一曲山，鳥飛魚躍白雲閒。", "溪山豈要行人到，自是行人到此間。"]'),
('43c9d6a7-9bda-4c51-816d-eea93845d376','三山亭','陶弼','宋','宋诗','song-poetry','','[]','諸峰不及此三峰，翠影多年路未通。',192,'全唐诗/poet.song.23000.json','["諸峰不及此三峰，翠影多年路未通。", "野老傳來無地主，神仙留待與山翁。", "琱弓射滅虎狼迹，長劍劈開荆棘叢。", "吏引旌旗先險阻，匠營樓閣出虛空。", "藤蘿葉暗初無日，松桂枝新漸有風。", "下瀨將軍微舉職，安南都護遠輸忠。", "商誇合浦珠胎賤，民樂占城稻穀豐。", "火炬影沉山岸北，潮聲流過郡城東。", "四時收印來無定，終日開尊望不窮。", "玉版淡魚千片白，金膏鹽蟹一團紅。", "雲臺志節悲歌外，銅柱封疆醉眼中。", "所惜溪頭好崖石，只書詩句不書功。"]'),
('8a1e4d0d-d317-41cb-ae05-3e8313f30bc6','祝融峰','陶弼','宋','宋诗','song-poetry','','[]','曾過祝融峰頂上，步隨明月宿禪關。',32,'全唐诗/poet.song.23000.json','["曾過祝融峰頂上，步隨明月宿禪關。", "夜深一陣打窗雨，卧聽風雷在半山。"]'),
('74e0ad03-83f5-4732-acb3-4c0c36887fae','辰州','陶弼','宋','宋诗','song-poetry','','[]','東海舊場屋，南江新塞垣。',48,'全唐诗/poet.song.23000.json','["東海舊場屋，南江新塞垣。", "璽書行絕域，銅柱入中原。", "草暖聞鳴鹿，江清對飲猿。", "何時一樽酒，重上謝公軒。"]'),
('7a51f0b1-8c91-4d84-93f5-46bcb3f93050','武陵','陶弼','宋','宋诗','song-poetry','','[]','曲臺風月德山雲，夢想中間有幾春。',32,'全唐诗/poet.song.23000.json','["曲臺風月德山雲，夢想中間有幾春。", "臣葬江魚終愛楚，民逃花洞不思秦。"]'),
('1b3f675f-6f88-4a37-82d2-b7463113bc50','五溪','陶弼','宋','宋诗','song-poetry','','[]','六月五溪邊，溪深氣象偏。',48,'全唐诗/poet.song.23000.json','["六月五溪邊，溪深氣象偏。", "晝陰疑雨後，久冷覺秋先。", "棧倚臨崖石，竿通隔嶺泉。", "片帆雲裏現，知是貢賨船。"]'),
('78a3ef12-3a0e-481f-8189-549b777091b1','寄蘇州徐處士弁','陶弼','宋','宋诗','song-poetry','','[]','平南無策鬢如霜，七十峰前隠舊鄉。',32,'全唐诗/poet.song.23000.json','["平南無策鬢如霜，七十峰前隠舊鄉。", "相約祝融孤頂上，借君吟筆畫瀟湘。"]'),
('46e14cb2-e638-4a34-bfa8-3778ba591fb0','畬田','陶弼','宋','宋诗','song-poetry','','[]','畬田過雨小溪渾，遠近雲峰互吐吞。',64,'全唐诗/poet.song.23000.json','["畬田過雨小溪渾，遠近雲峰互吐吞。", "殊俗易昏三里霧，陽崖忽露一家村。", "桂花香裏尋僧寺，榕葉陰中掩縣門。", "井稅未輸兵甲後，心勤撫字且休論。"]'),
('3b11c96f-ba4d-422f-9e83-8ec069295b8b','桂林','陶弼','宋','宋诗','song-poetry','','[]','青羅江水碧連山，城在山光水色間。',32,'全唐诗/poet.song.23000.json','["青羅江水碧連山，城在山光水色間。", "盡道宜人惟桂郡，驂鸞客至只思還。"]'),
('cf83acee-8dd5-4d7b-b0af-ee524ad80af5','木芙蓉','陶弼','宋','宋诗','song-poetry','','[]','孤芳托寒木，一曉一翻新。',48,'全唐诗/poet.song.23000.json','["孤芳托寒木，一曉一翻新。", "春色不爲主，天香難動人。", "丹楓見流落，黄菊坐因循。", "莫訝偏相愛，衰遲似我身。"]'),
('08fb29df-8878-43e5-ad27-57a552b66472','端研詩贈王欲','陶弼','宋','宋诗','song-poetry','','[]','端石如池狀，潤疑雲雨通。',24,'全唐诗/poet.song.23000.json','["端石如池狀，潤疑雲雨通。", "粗官不識字，好去伴詩翁。"]'),
('8a5a03bc-a879-4caf-a64d-d5b155ce92d9','銅雀研','陶弼','宋','宋诗','song-poetry','','[]','得自銅雀臺，收晚稜角摧。',36,'全唐诗/poet.song.23000.json','["得自銅雀臺，收晚稜角摧。", "四方綠琉璃，一片青玫瑰。", "煉盡沙石滓，陶成金玉胚。"]'),
('05556359-6a4b-4ed6-81b8-a6599cde12f7','衡州三首  其一','陶弼','宋','宋诗','song-poetry','','[]','七十峰前敞縣扉，湘雲湘樹滿郊圻。',32,'全唐诗/poet.song.23000.json','["七十峰前敞縣扉，湘雲湘樹滿郊圻。", "衡陽春暖雁飛過，兜率雨昏龍戰稀。"]'),
('2c691397-961d-4249-919c-41604813ba33','衡州三首  其二','陶弼','宋','宋诗','song-poetry','','[]','秀邑八百里，古今題畫難。',48,'全唐诗/poet.song.23000.json','["秀邑八百里，古今題畫難。", "望高三楚近，影轉七州寒。", "北拆知蠻盡，南低見斗寬。", "路盡祝融寺，江傾兜率灘。"]'),
('a312dcf8-e326-4a70-9931-a0e33af4318c','衡州三首  其三','陶弼','宋','宋诗','song-poetry','','[]','兜率一峰旁，林開見寶幢。',24,'全唐诗/poet.song.23000.json','["兜率一峰旁，林開見寶幢。", "鳥行高避縣，山骨下連江。"]'),
('5e32bb8f-8c55-4d56-ac30-94f129c540b7','希靜堂','陶弼','宋','宋诗','song-poetry','','[]','二江明月九峰雲，雲月堂中希靜人。',32,'全唐诗/poet.song.23000.json','["二江明月九峰雲，雲月堂中希靜人。", "芙蕖池淺蛙迎雨，鈷鉧潭空草送春。"]'),
('3008d2b6-4d52-4d75-9fb8-44113ef084f3','全州','陶弼','宋','宋诗','song-poetry','','[]','南北東西幾萬峰，郡城如在畫屏中。',32,'全唐诗/poet.song.23000.json','["南北東西幾萬峰，郡城如在畫屏中。", "何人截斷湘妃竹，半蘸秋江作釣筒。"]'),
('34d7a328-619a-41ff-b407-eec9013335c2','岳州','陶弼','宋','宋诗','song-poetry','','[]','平湖七百里，四望白波圍。',24,'全唐诗/poet.song.23000.json','["平湖七百里，四望白波圍。", "影觸吳天闊，寒吞楚澤微。"]'),
('90ae20f7-4460-4a9e-af70-6fdf7f0fa4ad','沅州','陶弼','宋','宋诗','song-poetry','','[]','使介直登雙御閣，州符就領五蠻溪。',32,'全唐诗/poet.song.23000.json','["使介直登雙御閣，州符就領五蠻溪。", "爭雄白鵲臨崖鬥，憶子玄猿遶澗啼。"]'),
('6a492ce3-8647-459a-a079-b5642a074032','九日登群山樓','陶弼','宋','宋诗','song-poetry','','[]','節逢重九日，郡占五溪間。',24,'全唐诗/poet.song.23000.json','["節逢重九日，郡占五溪間。", "止水痕依岸，行雲影過山。"]'),
('30a26801-cd61-48b9-b3a1-d46fc86b8b3d','題凈因寺','陶弼','宋','宋诗','song-poetry','','[]','歌吹深秋節，香燈古佛園。',24,'全唐诗/poet.song.23000.json','["歌吹深秋節，香燈古佛園。", "細泉初落石，遠岫正當門。"]'),
('6020d94e-3c67-4dd9-8176-42a534a2f82a','題武溪龍書廟壁','陶弼','宋','宋诗','song-poetry','','[]','路到龍棲處，陰森覺有靈。',24,'全唐诗/poet.song.23000.json','["路到龍棲處，陰森覺有靈。", "山腰過雲黑，石眼出泉腥。"]'),
('aff5109d-6839-4bf0-9501-5c1e92113e51','辰州  其一','陶弼','宋','宋诗','song-poetry','','[]','草市人朝醉，畬田夜火明。',24,'全唐诗/poet.song.23000.json','["草市人朝醉，畬田夜火明。", "瀧江入地瀉，棧道出雲行。"]'),
('0decc8bd-f9c8-4ec2-ab4d-bf886cba468a','辰州  其二','陶弼','宋','宋诗','song-poetry','','[]','槃溪何代有蘭叢，暇日移根郡閣東。',32,'全唐诗/poet.song.23000.json','["槃溪何代有蘭叢，暇日移根郡閣東。", "此後辰沅圖籍上，栽培新法自山公。"]'),
('400251e2-d376-4f0d-b01d-96403956e28d','廣州  其一','陶弼','宋','宋诗','song-poetry','','[]','地窮山亦斷，煙水是封圻。',24,'全唐诗/poet.song.23000.json','["地窮山亦斷，煙水是封圻。", "外國衣裝盛，中原氣象非。"]'),
('8dc8330e-8af2-45af-85cf-75ab196fd1b2','廣州  其二','陶弼','宋','宋诗','song-poetry','','[]','石門見月隨潮早，洸口聞猿上峽遲。',32,'全唐诗/poet.song.23000.json','["石門見月隨潮早，洸口聞猿上峽遲。", "新酒滿篘蠻嫗店，古碑當道海神祠。"]'),
('9100f907-c75f-47e3-83e4-dfcb4760f9c4','連州天際嶺','陶弼','宋','宋诗','song-poetry','','[]','南來未見此高峰，下際滄溟上際空。',32,'全唐诗/poet.song.23000.json','["南來未見此高峰，下際滄溟上際空。", "辛苦限蠻成底事，坐看嵩華作三公。"]'),
('d5c566b1-ad37-4969-b163-f240b3793076','桂州  其一','陶弼','宋','宋诗','song-poetry','','[]','冷逐江梅使，先春下桂林。',24,'全唐诗/poet.song.23000.json','["冷逐江梅使，先春下桂林。", "湖平三楚出，嶺盡百蠻深。"]'),
('0c8c3d95-e897-4af2-be16-1472f33feec0','桂州  其二','陶弼','宋','宋诗','song-poetry','','[]','亂草藏邊路，寒禽下戍樓。',24,'全唐诗/poet.song.23000.json','["亂草藏邊路，寒禽下戍樓。", "伏波渠水淺，難載濟川舟。"]'),
('35c06b2a-64f1-42b5-b356-70a1f7c57d6c','桂州  其三','陶弼','宋','宋诗','song-poetry','','[]','朝夕雲山滿縣郛，削成犀笋幾千株。',32,'全唐诗/poet.song.23000.json','["朝夕雲山滿縣郛，削成犀笋幾千株。", "遊人借筆抄詩板，遠客投書乞畫圖。"]'),
('22bd6cb4-b648-495c-ab97-d180f99075ac','桂州  其四','陶弼','宋','宋诗','song-poetry','','[]','舊策掃開浪泊霧，新詩裝就桂林春。',32,'全唐诗/poet.song.23000.json','["舊策掃開浪泊霧，新詩裝就桂林春。", "相離水色秋前老，獨秀嵐光霽後勻。"]'),
('f9364121-e098-4ee0-a2d1-2bd955a0b043','題陽朔山','陶弼','宋','宋诗','song-poetry','','[]','名山愛陽朔，平陸遍峰巒。',36,'全唐诗/poet.song.23000.json','["名山愛陽朔，平陸遍峰巒。", "郡境尖中拆，人家缺處安。", "穿青入梧峽，載影下昭灘。"]'),
('caecdd0d-cb13-4de8-a6bd-3dbb3d2c8ddf','登桂州永寧閣','陶弼','宋','宋诗','song-poetry','','[]','五代浮屠閣，危層不易攀。',24,'全唐诗/poet.song.23000.json','["五代浮屠閣，危層不易攀。", "曉光諸寺塔，晴露別州山。"]'),
('bc1b62d4-f4a9-40ca-8074-ed69fe698d20','修仁縣禪定寺','陶弼','宋','宋诗','song-poetry','','[]','民歸新邑去，古寺靜寥寥。',24,'全唐诗/poet.song.23000.json','["民歸新邑去，古寺靜寥寥。", "僧映水遮戶，客隨雲過橋。"]'),
('da9fe5bd-3346-40fd-933f-8b2e711c6b93','北池','陶弼','宋','宋诗','song-poetry','','[]','句漏城中菡萏池，池邊臺榭半空基。',32,'全唐诗/poet.song.23000.json','["句漏城中菡萏池，池邊臺榭半空基。", "頻年太守多新額，異代思賢有舊碑。"]'),
('bd91ee33-3fdb-42d2-b1a5-5489a5cb7d64','詩一首','陶弼','宋','宋诗','song-poetry','','[]','有唐曾宿萬家兵，節制東南十一城。',32,'全唐诗/poet.song.23000.json','["有唐曾宿萬家兵，節制東南十一城。", "此若得人無寇盜，昔之爲守盡公卿。"]'),
('30081b4c-eea9-44c3-aba9-b642a1c75037','遊龍洞訪僧不遇留詩','陶弼','宋','宋诗','song-poetry','','[]','一錫遊何處，巖端靜掩扃。',48,'全唐诗/poet.song.23000.json','["一錫遊何處，巖端靜掩扃。", "獨尋危石坐，閑把細泉聽。", "野鼠緣齋鉢，山花落靜瓶。", "斜陽過溪去，回首亂峰青。"]'),
('1c32d69d-d2cb-4e03-8409-7d0e9e1378f8','邕州  其一','陶弼','宋','宋诗','song-poetry','','[]','絕塞多秋色，孤城易夕陽。',24,'全唐诗/poet.song.23000.json','["絕塞多秋色，孤城易夕陽。", "此間饒寵辱，還我水雲鄉。"]'),
('5ee66f40-3b15-41e8-8725-90f92f1ce0a1','邕州  其二','陶弼','宋','宋诗','song-poetry','','[]','出撫驩兜俗，親提季子軍。',24,'全唐诗/poet.song.23000.json','["出撫驩兜俗，親提季子軍。", "隨人兩關月，迎馬二溪雲。"]'),
('c0954794-cc01-451d-bcd5-0ec424e78023','邕州  其三','陶弼','宋','宋诗','song-poetry','','[]','漢節護諸蠻，徘徊瘴癘間。',24,'全唐诗/poet.song.23000.json','["漢節護諸蠻，徘徊瘴癘間。", "少希銅馬式，老厭玉門關。"]'),
('38b604ac-8fb8-4618-a557-00d54054027b','昭州  其一','陶弼','宋','宋诗','song-poetry','','[]','假守昭平郡，偷閑少送迎。',24,'全唐诗/poet.song.23000.json','["假守昭平郡，偷閑少送迎。", "亭標梅句老，堂識敬公名。"]'),
('35ef4d57-7ca8-4ac7-9278-8b6e903eaa7a','昭州  其二','陶弼','宋','宋诗','song-poetry','','[]','假守昭平郡，當門桂水清。',24,'全唐诗/poet.song.23000.json','["假守昭平郡，當門桂水清。", "海遥稀蚌迹，峽近足灘聲。"]'),
('1f8e110d-2e21-457c-8562-05d90a69f0e2','昭州  其三','陶弼','宋','宋诗','song-poetry','','[]','假守昭平郡，詩情比閬仙。',24,'全唐诗/poet.song.23000.json','["假守昭平郡，詩情比閬仙。", "蟬聲風葉外，鳥影月池邊。"]'),
('0e7bc807-c80f-4877-9b54-da840fbe6ea2','昭州  其四','陶弼','宋','宋诗','song-poetry','','[]','峽束江盤天影隨，輕船雙下幾危機。',48,'全唐诗/poet.song.23000.json','["峽束江盤天影隨，輕船雙下幾危機。", "初晴古木猿三叫，未晚陰崖日半規。", "篁竹數家何處縣，清溪一曲幾篇詩。"]'),
('51fd0310-ee5a-4836-91b2-cfbe3ea07c85','過龍平','陶弼','宋','宋诗','song-poetry','','[]','數家深峽裏，燈火似漁村。',48,'全唐诗/poet.song.23000.json','["數家深峽裏，燈火似漁村。", "客夢稀星外，蟲聲短草根。", "髪疏憐枕軟，意倦覺燈昏。", "待曉酤蠻酒，蒼梧奠舜魂。"]'),
('fd969b30-ced4-43f3-9fca-d2971bac0b78','送吳利見主簿之蒼梧','陶弼','宋','宋诗','song-poetry','','[]','南極蒼梧郡，江山號勝遊。',24,'全唐诗/poet.song.23000.json','["南極蒼梧郡，江山號勝遊。", "海天晴動水，峽月夜隨舟。"]'),
('ef22438c-e41d-47d0-9f2b-22c8e72c47c9','寄梧守','陶弼','宋','宋诗','song-poetry','','[]','川流八桂末，地勢九疑餘。',24,'全唐诗/poet.song.23000.json','["川流八桂末，地勢九疑餘。", "不憚勤酬唱，江通丙穴魚。"]'),
('1329a198-42bf-45a3-b874-351d6586ecf1','柳州  其一','陶弼','宋','宋诗','song-poetry','','[]','唐室衣冠四百秋，元和臺省盡名流。',32,'全唐诗/poet.song.23000.json','["唐室衣冠四百秋，元和臺省盡名流。", "誰人肯爲交朋死，乞以羅池換播州。"]'),
('b3788f1d-2f50-4633-9308-10da62a79b86','柳州  其二','陶弼','宋','宋诗','song-poetry','','[]','黄柑無樹井無泉，思柳亭中兩愴然。',32,'全唐诗/poet.song.23000.json','["黄柑無樹井無泉，思柳亭中兩愴然。", "蠻越至今猶畫像，聖唐何事獨遺賢。"]'),
('b2a973e1-af13-49e5-b94d-37be40c1ec38','屏山','陶弼','宋','宋诗','song-poetry','','[]','一峰高起塞天關，堪作皇家外屏山。',32,'全唐诗/poet.song.23000.json','["一峰高起塞天關，堪作皇家外屏山。", "可惜化工安著遠，半遮中國半遮蠻。"]'),
('61999d8e-fa47-4cd6-855c-0ae4cbe2c3e5','龍壁','陶弼','宋','宋诗','song-poetry','','[]','曾看柳侯山水記，信知龍壁好煙霞。',32,'全唐诗/poet.song.23000.json','["曾看柳侯山水記，信知龍壁好煙霞。", "誰能寫作新屏障，寄與長安富貴家。"]'),
('1faf7b06-9ebd-41cd-a1df-98ffe02804af','賓州二首  其一','陶弼','宋','宋诗','song-poetry','','[]','廣右開炎服，思剛置縣衙。',48,'全唐诗/poet.song.23000.json','["廣右開炎服，思剛置縣衙。", "羈縻唐世及，正朔聖朝加。", "鄉分今賀水，邑隸古琅琊。", "泉脈通明鏡，封鄰接鏌鋣。"]'),
('eddb1831-c85b-40dc-847e-88121b2ad80e','賓州二首  其二','陶弼','宋','宋诗','song-poetry','','[]','何處登臨好，城樓對萬山。',48,'全唐诗/poet.song.23000.json','["何處登臨好，城樓對萬山。", "新青上孤壘，遠黑落諸蠻。", "竹引風穿壁，苔隨雨上階。", "有時寧免俗，銀燭間金釵。"]'),
('9a38366b-416f-402b-a21e-81a295efad6b','寄欽州洪邇侍禁','陶弼','宋','宋诗','song-poetry','','[]','僧憐海石爲棋子，客懼蠻螺作酒杯。',32,'全唐诗/poet.song.23000.json','["僧憐海石爲棋子，客懼蠻螺作酒杯。", "自笑平生喜韜略，此時何計上金臺。"]'),
('02f0a208-4ced-419e-9805-74724bf7911e','三山亭','陶弼','宋','宋诗','song-poetry','','[]','紅螺紫蟹新鱸鱠，白藕黄柑晚荔枝。',32,'全唐诗/poet.song.23000.json','["紅螺紫蟹新鱸鱠，白藕黄柑晚荔枝。", "酒盡月斜潮半落，山翁不省上船時。"]'),
('2f328e69-072a-449a-9ad8-bce825129d3c','欽州書事','陶弼','宋','宋诗','song-poetry','','[]','海供地寶華中國，日助天恩暖外夷。',32,'全唐诗/poet.song.23000.json','["海供地寶華中國，日助天恩暖外夷。", "三石禊橋春會永，五湖吟舫夜歸遲。"]'),
('f0011d8f-a57c-4f74-9d07-044af08cc727','題廉州孟太守祠堂','陶弼','宋','宋诗','song-poetry','','[]','昔時孟太守，忠信行海隅。',24,'全唐诗/poet.song.23000.json','["昔時孟太守，忠信行海隅。", "不賊蚌蛤胎，水底多還珠。"]'),
('a75f124b-038a-43f5-a674-eff46b560b88','寄石康縣曹元道','陶弼','宋','宋诗','song-poetry','','[]','屢與南僧談瘴溪，獨推君縣好封圻。',32,'全唐诗/poet.song.23000.json','["屢與南僧談瘴溪，獨推君縣好封圻。", "不同合浦人民衆，雖接交州寇盜稀。"]'),
('a0c3ab26-14c5-44c4-b6e0-4b07e21dc5dc','賀州','陶弼','宋','宋诗','song-poetry','','[]','捨轡歷天險，身疑出鳥群。',24,'全唐诗/poet.song.23000.json','["捨轡歷天險，身疑出鳥群。", "罅開蠻俗合，脊盡瘴江分。"]'),
('4a6dccdc-6df0-49ba-980b-d83895b5f5d2','茉莉花  其一','陶弼','宋','宋诗','song-poetry','','[]','重譯新離越裳國，一枝都掩桂林香。',32,'全唐诗/poet.song.23000.json','["重譯新離越裳國，一枝都掩桂林香。", "養成崖谷黄蜂蜜，羞死江湖白藕房。"]'),
('298d7ac7-7f83-484d-a240-a26a66e67387','茉莉花  其二','陶弼','宋','宋诗','song-poetry','','[]','海客園林珠樹木，水仙賓從玉簪裳。',32,'全唐诗/poet.song.23000.json','["海客園林珠樹木，水仙賓從玉簪裳。", "錦桃每用紅絲縷，蜂採須成白蜜房。"]'),
('e2050f51-960e-4b50-8c04-fec382e0b474','芡','陶弼','宋','宋诗','song-poetry','','[]','三伏池塘沸，雞頭美可烹。',48,'全唐诗/poet.song.23000.json','["三伏池塘沸，雞頭美可烹。", "香囊聯錦破，玉指剝珠明。", "葉皺非蓮蓋，根甘似竹萌。", "不應徒適口，炎帝亦曾名。"]'),
('274ffb7b-19a9-45a1-8c6a-847210acd474','菊','陶弼','宋','宋诗','song-poetry','','[]','九月嚴霜殺草根，獨開黄菊伴金樽。',32,'全唐诗/poet.song.23000.json','["九月嚴霜殺草根，獨開黄菊伴金樽。", "東籬故事何重疊，醉倒花前是遠孫。"]'),
('09a656c1-63ba-4c1c-ad12-3cd69fdaefe1','咏藕','陶弼','宋','宋诗','song-poetry','','[]','萬頃金沙裏，誰將玉節栽。',96,'全唐诗/poet.song.23000.json','["萬頃金沙裏，誰將玉節栽。", "絲應鮫乞與，津是蚌分來。", "盤貯冰猶結，刀侵雪易摧。", "防風骨外折，混沌竅中開。", "月寺僧家鉢，風亭酒客杯。", "胸中秋氣入，牙角雨聲回。", "自愧塵泥賤，得蒙尊俎陪。", "與君消酷暑，瓜李莫相猜。"]'),
('b666bf5d-eeb0-41b9-983c-78b7fefea59e','蝶','陶弼','宋','宋诗','song-poetry','','[]','暖翅玉羅薄，香鬚金綫微。',48,'全唐诗/poet.song.23000.json','["暖翅玉羅薄，香鬚金綫微。", "青春二三月，白日一雙飛。", "露重休深入，風高且暫歸。", "南園芳樹下，燕雀最多機。"]'),
('834d4690-b41d-41b4-b08b-7bcdad552673','塞上','陶弼','宋','宋诗','song-poetry','','[]','星落胡王死，河窮漢使歸。',24,'全唐诗/poet.song.23000.json','["星落胡王死，河窮漢使歸。", "雪山經夏冷，天馬入秋肥。"]'),
('47a94c12-94a8-4ae5-82fe-135101e19fa7','繼老堂','陶弼','宋','宋诗','song-poetry','','[]','冷酒十分無客送，輕國一兩有民攀。',32,'全唐诗/poet.song.23000.json','["冷酒十分無客送，輕國一兩有民攀。", "將老未聞金作印，師寒猶用鐵爲衣。"]'),
('9a74e338-3b48-46d8-bedf-39247059201b','過蒼梧','陶弼','宋','宋诗','song-poetry','','[]','近海江聲急，孤舟下杳冥。',48,'全唐诗/poet.song.23000.json','["近海江聲急，孤舟下杳冥。", "峽泉飛暴雨，灘石走群星。", "水有瀟湘色，猿同巴蜀聽。", "令人思舜德，一望九嶷青。"]'),
('6ce20ea5-4f63-43d8-83b1-594be046a2c6','題鬼門關','陶弼','宋','宋诗','song-poetry','','[]','朝過鬼門關，虎迹印玄室。',96,'全唐诗/poet.song.23000.json','["朝過鬼門關，虎迹印玄室。", "暮過鬼門關，猿聲嘯蒼壁。", "朝暮悲行人，森然增慘慄。", "駐馬看飛雲，蠻煙不見日。", "回首望江南，萬里心何極。", "美人天一方，雙魚莫能覓。", "遥望天涯亭，相逢不相識。", "令我思古人，興懷感今昔。"]'),
('1e5d8829-9694-468a-90d0-b84010815c81','再過陽朔寄人','陶弼','宋','宋诗','song-poetry','','[]','昔日儒衫今武車，重來耆老尚奔趨。',64,'全唐诗/poet.song.23000.json','["昔日儒衫今武車，重來耆老尚奔趨。", "後人相繼皆清德，小吏迴看半白鬚。", "條教謾爲新楷法，官資猶作舊稱呼。", "里門不閉田疇闢，好買丹青別畫圖。"]'),
('e10fecfd-6665-4180-8a9d-442fa660266f','南嶽','陶弼','宋','宋诗','song-poetry','','["\u8861\u5c71"]','祝融何峻極，下看白雲根。',36,'全唐诗/poet.song.23000.json','["祝融何峻極，下看白雲根。", "絕頂人稀到，諸峰勢獨尊。", "闊能遮日域，高不避天閽。"]'),
('fc25af67-deaa-4a5d-b2b7-d7ce84f45967','題獻花鋪','陶弼','宋','宋诗','song-poetry','','[]','德裕南遷瘴海涯，路逢山女獻山花。',32,'全唐诗/poet.song.23000.json','["德裕南遷瘴海涯，路逢山女獻山花。", "平泉公子傷春處，唯有東風吹草芽。"]'),
('f4e58f74-084c-47b0-956d-309365d42317','寄桃源管明菩','陶弼','宋','宋诗','song-poetry','','[]','野鶴孤雲無定蹤，桃花流水合相容。',32,'全唐诗/poet.song.23000.json','["野鶴孤雲無定蹤，桃花流水合相容。", "夜來月滿群山閣，知在秦人第幾峰。"]'),
('70ff41b3-6025-4513-b39e-0a1fd749504e','望海嶺','陶弼','宋','宋诗','song-poetry','','[]','望海樓高目力寬，海潮來處是天根。',64,'全唐诗/poet.song.23000.json','["望海樓高目力寬，海潮來處是天根。", "日邊市舶程途遠，水外亭臺景象昏。", "巨鱷出時防患害，大鵰當北各飛翻。", "將軍有意還銅柱，俯看南溟氣欲吞。"]'),
('6c45374f-7cfb-4a39-8a18-64d77eadf5a8','釣石','陶弼','宋','宋诗','song-poetry','','[]','守邊無一事，坐石釣東橋。',48,'全唐诗/poet.song.23000.json','["守邊無一事，坐石釣東橋。", "水色連山疊，泥痕上海潮。", "餌經沙日暖，綸動水風飄。", "客正思新繪，鰌鯨氣莫驕。"]'),
('c3a9ef2d-0cf8-4dfe-b945-acd0ba3c8ab6','醉石','陶弼','宋','宋诗','song-poetry','','[]','守邊無一事，載酒翠崖東。',48,'全唐诗/poet.song.23000.json','["守邊無一事，載酒翠崖東。", "几穩平沙上，杯流醉石中。", "野蔬沿澗綠，林果映江紅。", "休把鼓鍾動，此歡魚亦同。"]'),
('b152364e-5f3c-46e3-a488-9310edb08a13','南湖','陶弼','宋','宋诗','song-poetry','','[]','寧越佳山水，南湖水淺清。',48,'全唐诗/poet.song.23000.json','["寧越佳山水，南湖水淺清。", "暗泉通古廟，凉氣入軍城。", "有禁魚常樂，無機鳥不驚。", "遠蕃𦨴舶至，海角暮潮平。"]'),
('4d8a9a08-998a-45da-8d02-ec96ecc539e5','中湖','陶弼','宋','宋诗','song-poetry','','[]','寧越佳山水，中湖賞稱心。',48,'全唐诗/poet.song.23000.json','["寧越佳山水，中湖賞稱心。", "環流隨郡塹，倒影動禪林。", "夏簟一般冷，春瓶相對深。", "使君少仁智，頼得會高吟。"]'),
('dd46a8be-d95c-47ff-8058-be6bc5b24b8d','北湖','陶弼','宋','宋诗','song-poetry','','[]','寧越佳山水，城樓枕北湖。',48,'全唐诗/poet.song.23000.json','["寧越佳山水，城樓枕北湖。", "丘陵助形勢，溝洫借膏腴。", "晚景群峰會，春流衆壑趨。", "自知千載後，歌調有農夫。"]'),
('7783ad1f-d7c4-44ec-aad7-37df7f83dee5','三海巖','陶弼','宋','宋诗','song-poetry','','[]','靈邑西南古洞天，我來方信海爲田。',64,'全唐诗/poet.song.23000.json','["靈邑西南古洞天，我來方信海爲田。", "無名不入州圖載，有路空聞野老傳。", "此日登山人採蚌，當時飲馬客留錢。", "顔公昔記麻姑說，三變柔桑事果然。"]'),
('7d43528d-66a0-4b90-9cec-74bea0b0a180','三山亭','陶弼','宋','宋诗','song-poetry','','[]','三山亭下水悠悠，山聳潮平地欲浮。',64,'全唐诗/poet.song.23000.json','["三山亭下水悠悠，山聳潮平地欲浮。", "草木秀多窮海角，棟梁高處壓鰲頭。", "莫辭樽俎金船夜，曾駐旌旗玉帳秋。", "好景眼前題不盡，恍然神鬼在瀛洲。"]'),
('3a99027b-4241-4e1b-ad63-8cac11c74542','直釣亭','陶弼','宋','宋诗','song-poetry','','[]','半載持竿野水東，山翁心不類漁翁。',64,'全唐诗/poet.song.23000.json','["半載持竿野水東，山翁心不類漁翁。", "何須巧餌懸鈎上，會使姦鱗落鼎中。", "西伯道高來呂望，文宗才短失盧仝。", "縱人能取鱗中意，南海波瀾一夜空。"]'),
('875f788b-25b3-4eab-a2ca-1d08fd68c590','五湖亭','陶弼','宋','宋诗','song-poetry','','[]','七隄環遶四城隅，限隔烟波作五湖。',64,'全唐诗/poet.song.23000.json','["七隄環遶四城隅，限隔烟波作五湖。", "書吏寫供都水帳，畫工描入職方圖。", "東流滿郭湖相似，塞氣侵人瘴自無。", "日際諸蠻盡冠带，將軍何計學朱陶。"]'),
('ddf83241-4b05-41b1-88a7-28fbb1b6c933','南湖亭','陶弼','宋','宋诗','song-poetry','','[]','山城春晝橘花開，祓禊相將上古臺。',64,'全唐诗/poet.song.23000.json','["山城春晝橘花開，祓禊相將上古臺。", "一片晚雲含落照，數分殘酒伴新梅。", "談高綺席終無况，詩落金牋謾有才。", "多謝南亭湖與月，醉中相送畫船回。"]'),
('20908d14-6aad-4353-8f63-3fe9912b4cc5','野香亭','陶弼','宋','宋诗','song-poetry','','[]','野香亭下新開萼，半是夭桃半是梅。',64,'全唐诗/poet.song.23000.json','["野香亭下新開萼，半是夭桃半是梅。", "舊說武陵源上去，今疑大庾嶺邊來。", "人閑亭上醒還醉，夭暖牆頭落又開。", "賓客笑談民鼓舞，不知何者號春臺。"]'),
('a4062d77-e94e-41dd-9c51-1aa7ee31be08','使光亭','陶弼','宋','宋诗','song-poetry','','[]','亭上三峰臂五湖，皇華人到此躇躕。',64,'全唐诗/poet.song.23000.json','["亭上三峰臂五湖，皇華人到此躇躕。", "鄉民看取黄龍節，郡吏聽宣赤鳳書。", "南下威如霜落後，撫邊恩似雨來初。", "離筵何用銀燈燭，自有雙星照使車。"]'),
('8cee6cb8-3ea0-40b4-812d-e4bf20aeb340','潮月亭','陶弼','宋','宋诗','song-poetry','','[]','角聲吹送小單于，薄霧稀星乍有無。',32,'全唐诗/poet.song.23000.json','["角聲吹送小單于，薄霧稀星乍有無。", "坐看月從潮上出，水晶盤裏夜明珠。"]'),
('023550ed-f067-4cd2-972f-6f14686323ad','茶溪亭','陶弼','宋','宋诗','song-poetry','','[]','茶溪亭上綠沿迴，溪上孤城照水開。',64,'全唐诗/poet.song.23000.json','["茶溪亭上綠沿迴，溪上孤城照水開。", "誰趁落潮離晚渡，自尋芳草上春臺。", "年華有限忙中去，人事無涯暗裏來。", "安得病軀開病眼，碧雲瞻拱帝星回。"]'),
('00d0f395-8bc2-4eaa-b5bc-97309698ca0a','桂風亭','陶弼','宋','宋诗','song-poetry','','[]','新亭序立郡城樓，樽酒登樓未免愁。',64,'全唐诗/poet.song.23000.json','["新亭序立郡城樓，樽酒登樓未免愁。", "家住斗星天北野，路隨潮水海南頭。", "古憂蛟蜃今思濟，衆說魚蝦不直鈎。", "民俗不知官况薄，上書重把寇君留。"]'),
('d4e24935-7ede-439d-a24a-b9fd0151e40a','望安南海口','陶弼','宋','宋诗','song-poetry','','[]','喜逢晴日破陰霾，望極西南瘴海涯。',64,'全唐诗/poet.song.23000.json','["喜逢晴日破陰霾，望極西南瘴海涯。", "夷狄古今常反覆，朝廷終始務綏懷。", "何時良將收銅柱，不日孱王棄𧀎街。", "惆悵藤橋兵死鬼，年年沙上哭墳骸。"]'),
('ae082f3f-2105-499a-9556-ef4909526493','過清湘','陶弼','宋','宋诗','song-poetry','','[]','嶺開蠻壤斷，此地下湘川。',48,'全唐诗/poet.song.23000.json','["嶺開蠻壤斷，此地下湘川。", "綠水文如染，丹楓色欲然。", "瘴消還愛酒，我醉尚憂邊。", "故里誰相訪，孤帆出曉烟。"]'),
('ffa4cb2e-3cc9-41e8-97e2-92134cce6cce','攔蠻山','陶弼','宋','宋诗','song-poetry','','[]','西去萬重山，茲峰獨限蠻。',48,'全唐诗/poet.song.23000.json','["西去萬重山，茲峰獨限蠻。", "天生賊多計，民頼汝爲關。", "設險數州地，防危一日間。", "守邊須以道，絕頂可躋攀。"]'),
('736c0ec9-b068-4089-bbf2-c630274394f4','南寧崑崙關','陶弼','宋','宋诗','song-poetry','','[]','關路下崑崙，蠻封迤邐分。',48,'全唐诗/poet.song.23000.json','["關路下崑崙，蠻封迤邐分。", "春光偏著草，雨意不離雲。", "俗異君修德，時平將用文。", "臨溪照綠水，老鬢雪紛紛。"]'),
('1510b1ba-d445-44d6-b39f-6cf388bc293d','三公亭落成','陶弼','宋','宋诗','song-poetry','','[]','北原喬木外，三將舊屯營。',48,'全唐诗/poet.song.23000.json','["北原喬木外，三將舊屯營。", "草沒金鎚蹟，山應玉管聲。", "路隨關地迥，江背瘴天輕。", "異日誰相繼，來書第四名。"]'),
('9b0e1073-5d44-476e-9d0d-47bae7976559','入桂林','陶弼','宋','宋诗','song-poetry','','[]','滿耳洋洋分嶺泉，早秋時候晚凉天。',64,'全唐诗/poet.song.23000.json','["滿耳洋洋分嶺泉，早秋時候晚凉天。", "稻花斑白初經雨，竹色青蒼薄带烟。", "安得孤臣能慮患，不勞明主更憂邊。", "東坡故老知誰在，望我車塵若望仙。"]'),
('c8a11427-992a-499c-9e54-43fe6b943d4f','龍州秀嶺','陶弼','宋','宋诗','song-poetry','','[]','路隨雲磴石梯行，限隔華夷天意明。',64,'全唐诗/poet.song.23000.json','["路隨雲磴石梯行，限隔華夷天意明。", "自與大君爲外屏，何勞諸將作長城。", "福民可拜三公爵，壽聖能呼萬歲聲。", "海國未疆崖石老，待誰來此勒功名。"]'),
('c3b32f93-6919-4b05-bdb8-664b23fe4ba9','桂林府淪漪閣','陶弼','宋','宋诗','song-poetry','','[]','談笑淪漪閣，藤花竹葉間。',24,'全唐诗/poet.song.23000.json','["談笑淪漪閣，藤花竹葉間。", "易醒江上酒，難畫雨中山。"]'),
('55992a04-ccbc-4faf-a0fb-e249e8413438','順應廟','陶弼','宋','宋诗','song-poetry','','[]','白崖山下古松青，暫捲牙旗謁廟靈。',32,'全唐诗/poet.song.23000.json','["白崖山下古松青，暫捲牙旗謁廟靈。", "見說崑崙關北畔，曾將草木作人形。"]'),
('b8513fe3-6b60-48bb-9bb1-a56579dfb86a','芙蓉亭','陶弼','宋','宋诗','song-poetry','','[]','邊柝無聲獄訟疏，芙蓉池上避金烏。',64,'全唐诗/poet.song.23000.json','["邊柝無聲獄訟疏，芙蓉池上避金烏。", "民收果實充田賦，匠寫空形入畫圖。", "白鳥知機遠冠蓋，紫鱗貪餌落盤盂。", "主人非爲清香護，愛此煙波似五湖。"]'),
('cc5e075f-de34-4754-a1ab-f5b3d5244a6e','吟石','陶弼','宋','宋诗','song-poetry','','[]','守邊無一事，江上得閒吟。',48,'全唐诗/poet.song.23000.json','["守邊無一事，江上得閒吟。", "醉囈歌微出，狂書墨不深。", "潮痕沒高岸，月色透疏林。", "此意無人解，宵分泪滿襟。"]'),
('34a74906-27c0-43f6-abb6-76497d5bf8d8','永平寨道中','陶弼','宋','宋诗','song-poetry','','[]','疊帳深千里，窮途令一隅。',48,'全唐诗/poet.song.23000.json','["疊帳深千里，窮途令一隅。", "北風家信息，南斗客程途。", "嶺勢頻開合，猿聲乍有無。", "過溪人語笑，隔岸戍煙孤。"]'),
('5ba31af9-979f-4292-8123-964dd0abe309','瑞蓮池','陶弼','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u7eaa\u6e38", "\u5199\u666f", "\u95f2\u9002"]','五月紅蓮繁盛時，隼旟同賞郡南池。',64,'全唐诗/poet.song.23000.json','["五月紅蓮繁盛時，隼旟同賞郡南池。", "額名舊載零陵志，碑字新鎸子厚詩。", "採藥銜杯愁滿滿，折花行令笑遲遲。", "明年歲熟歌聲穩，伴醉清香客是誰。"]'),
('891b99c2-b3ad-417d-b678-a7e6227c4d35','九龍巖','陶弼','宋','宋诗','song-poetry','','[]','巖有真龍卧未醒，此龍於物本無情。',32,'全唐诗/poet.song.23000.json','["巖有真龍卧未醒，此龍於物本無情。", "可能暫起爲甘雨，洗我征南十萬兵。"]'),
('199b1d0a-b706-4c48-b7be-080c6c000721','句  其一','陶弼','宋','宋诗','song-poetry','','[]','蒐兵四解降王縛，報國三登上將壇。',16,'全唐诗/poet.song.23000.json','["蒐兵四解降王縛，報國三登上將壇。"]'),
