('9b792047-529c-4645-8df2-412b3a7779d9','句  其五四','陶弼','宋','宋诗','song-poetry','','[]','柳與揚州今獨在，水和隋帝不重來。',16,'全唐诗/poet.song.23000.json','["柳與揚州今獨在，水和隋帝不重來。"]'),
('62597869-b4b7-46d4-9fda-70f91b8b1ee2','句  其五五','陶弼','宋','宋诗','song-poetry','','[]','人心如地少平處，天氣似春無冷時。',16,'全唐诗/poet.song.23000.json','["人心如地少平處，天氣似春無冷時。"]'),
('09467de5-28db-4495-bd8f-ebb5ce9b7e8c','句  其五六','陶弼','宋','宋诗','song-poetry','','[]','兵堪渡海將軍老，史不占天處士閒。',16,'全唐诗/poet.song.23000.json','["兵堪渡海將軍老，史不占天處士閒。"]'),
('a85b02a5-4cee-4d7e-9e03-7f40fd1a1d33','句  其五七','陶弼','宋','宋诗','song-poetry','','[]','路小馬蹄高復下，村深鷄唱有如無。',16,'全唐诗/poet.song.23000.json','["路小馬蹄高復下，村深鷄唱有如無。"]'),
('1e595b04-748d-4839-8919-db28bba08061','句  其五八','陶弼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','扁舟興盡且休去，五嶺以南皆洞庭。',16,'全唐诗/poet.song.23000.json','["扁舟興盡且休去，五嶺以南皆洞庭。"]'),
('3756ac9f-9576-4a05-8f52-b197c926f104','題涪州雙魚次劉郎中韵','丘無逸','宋','宋诗','song-poetry','','[]','誰將江石作魚鎸，奮鬣揚鬐似戲蓮。',64,'全唐诗/poet.song.23000.json','["誰將江石作魚鎸，奮鬣揚鬐似戲蓮。", "今報豐登當此日，昔模形狀自何年。", "雪因呈瑞爭高下，星以分宮較後先。", "八使經財念康阜，寄詩褒激守臣賢。"]'),
('5421af06-c5a4-4e2c-82fc-1cef356575bd','題左溪齊雲閣','于房','宋','宋诗','song-poetry','','[]','籃輿遊古寺，危閣倚天外。',72,'全唐诗/poet.song.23000.json','["籃輿遊古寺，危閣倚天外。", "山川混一色，雲霞忽萬態。", "啼鳥聲交呼，牧豎歌相對。", "憑欄增氣味，披襟絕埃𡏖。", "飛泉出陰窅，清風來相背。", "文酒歡賓朋，樂哉時褫带。"]'),
('ae490877-3326-4d10-8d6a-75cbe73c0687','金城山','李思聰','宋','宋诗','song-poetry','','[]','杏花洞天路崎嶇，曾見千年石斛奴。',32,'全唐诗/poet.song.23000.json','["杏花洞天路崎嶇，曾見千年石斛奴。", "試問金城山裏事，只言仙境似蓬壺。"]'),
('99d47436-f677-4150-927f-cc00fadcc490','雲山','李思聰','宋','宋诗','song-poetry','','[]','水石光涵千里色，川林陰翠濕芝蘭。',32,'全唐诗/poet.song.23000.json','["水石光涵千里色，川林陰翠濕芝蘭。", "杏花塢接投龍洞，瀑濺蒼崖鶴骨寒。"]'),
('42f730a0-1b9f-4d0b-bec2-764a81e62a31','朱陵洞','李思聰','宋','宋诗','song-poetry','','[]','靈峰七十二巑岏，紫蓋芙蓉杳靄間。',64,'全唐诗/poet.song.23000.json','["靈峰七十二巑岏，紫蓋芙蓉杳靄間。", "影浸瀟湘盤地脈，秀擎翼軫插天關。", "真君玉冊光千古，赤帝璇宮鎮八蠻。", "好比吾皇大椿算，萬年松在最高山。"]'),
('447aeeed-457e-4ab9-a563-5c187a4d9fc1','凉軒','陳庸','宋','宋诗','song-poetry','','[]','宰予居豐暇，構軒凉愈清。',48,'全唐诗/poet.song.23000.json','["宰予居豐暇，構軒凉愈清。", "塵襟當此釋，暑氣未嘗生。", "植竹助真性，弄琴宜正聲。", "披風茲可會，觴詠豁交情。"]'),
('a1f51015-e910-4d6c-a76c-3d9b9d684d0e','題招提院靜照堂','張芻','宋','宋诗','song-poetry','','[]','槜李舊禪扉，叢林自翠微。',48,'全唐诗/poet.song.23000.json','["槜李舊禪扉，叢林自翠微。", "寺居天外靜，僧向日邊歸。", "野水涵齋几，閒雲宿釣磯。", "庭前祖來意，誰爲相依依。"]'),
('9117e6d1-59fc-4767-8770-036be350f002','偈','釋法寶','宋','宋诗','song-poetry','','[]','千般言，萬種喻，只要教君早回去。',32,'全唐诗/poet.song.23000.json','["千般言，萬種喻，只要教君早回去。", "夜來一片黑雲生，莫教錯却山前路。"]'),
('316eb490-14f8-439d-bb18-24a6eb4ec4c6','萊石茶酒器寄邵先生作詩代書','王益柔','宋','宋诗','song-poetry','','[]','寶刀切石如春泥，雕剜成器青玻璃。',160,'全唐诗/poet.song.23000.json','["寶刀切石如春泥，雕剜成器青玻璃。", "吾嘗閱視得而有，惜不自用長提携。", "前時過君銅駝陌，門巷深僻無輪蹄。", "呼兒烹茶酌白酒，陶器自稱藿與藜。", "愛君居貧趣閒放，一語不涉青雲梯。", "嗟予都城走塵土，日遠樽杓愁鹽齏。", "緘封不啟置牆角，頓撼時作瓊瑶嘶。", "爭如特寄邵高士，書帙几杖同幽棲。", "荷鋤賸治田間穢，抱甕勤灌園蔬畦。", "明年春酒或共酌，爲我掃石臨清溪。"]'),
('e5dcbe9e-ff1a-4c74-b12a-3b698202b8b4','奉答堯夫先生金雀石硯詩','王益柔','宋','宋诗','song-poetry','','[]','般陽有山名金雀，山發清輝産奇璞。',256,'全唐诗/poet.song.23000.json','["般陽有山名金雀，山發清輝産奇璞。", "望氣嘗言玉寶藏，賈胡幾遣良工度。", "金剛寶鑽競窮搜，百里青蒼困鑱鑿。", "瓊瑰未獲得研材，溫潤還將六美學。", "有若玉徽琴面瑩，有如金彈陶輪著。", "規天矩地形制毓，中或辟流外圭角。", "晴窗氣暖墨花春，牋襞毫奔光照灼。", "吾生特好惟四物，累載裒鳩盈几格。", "先生閉戶日著書，朝餐每不饜藜藿。", "高閎粱肉雖有餘，孰敢就門賙隠約。", "先生固自嘗有言，不忍將身作溝壑。", "先生崖岸高莫攀，持此謂宜無見却。", "一留爲惠固已多，敢冀新詩旋踵作。", "精深雅健迫風騷，使我憂荒忽驚矍。", "還如甘露醒心昏，更似神篦除眼膜。", "先生精義已入神，準易時容見涯略。"]'),
('bc9c3422-000d-480f-b8c4-4f912648a126','奉和堯夫','王益柔','宋','宋诗','song-poetry','','[]','固窮終不悔沉淪，滿腹深藏上古珍。',32,'全唐诗/poet.song.23000.json','["固窮終不悔沉淪，滿腹深藏上古珍。", "手寫新詩成幾卷，亦教餘事照千春。"]'),
('3b212df1-f4d5-4ebd-ac8c-fca2e7f887cd','送程給事知越州','王益柔','宋','宋诗','song-poetry','','[]','紫紱黄金太守章，旌旗遥指五雲鄉。',64,'全唐诗/poet.song.23000.json','["紫紱黄金太守章，旌旗遥指五雲鄉。", "若耶溪上朝風快，宛委山中六月凉。", "政事雍容多潤澤，詩情閒淡合宮商。", "羨君一入蓬萊閣，吟醉蕭然未遽央。"]'),
('bd4c767e-d378-4585-95f1-38db769d8200','遥題錢公輔衆樂亭','王益柔','宋','宋诗','song-poetry','','[]','四明舊說南湖好，歲久瀕厓變涂潦。',144,'全唐诗/poet.song.23000.json','["四明舊說南湖好，歲久瀕厓變涂潦。", "建旟一日得賢侯，千里山川真再造。", "偃月堤成車馬道，湖光如截天如抱。", "鴛鴦瓦影亂鳬鷖，綠柳環堤花映島。", "珠宮貝闕競來還，泉客鮫人爭獻寶。", "春風浩蕩波濤起，彷彿仙人騎赤鯉。", "金盤下筯飽鱸魚，塵事茫茫隔烟水。", "都人士女從如雲，絲竹清音兩岸聞。", "飲酣落筆歌綠水，爛漫天葩飄遠芬。"]'),
('184eb930-30e0-4d98-b1d9-5f89c49bf992','題招提院靜照堂','王益柔','宋','宋诗','song-poetry','','[]','構堂幽僻斷塵蹤，靜照爲名我所通。',64,'全唐诗/poet.song.23000.json','["構堂幽僻斷塵蹤，靜照爲名我所通。", "一室可知天下事，十方齊見定心中。", "清朝雲散層峰出，後夜潮回漲海空。", "槜李禦兒多舊迹，幾時烟舸訪支公。"]'),
('16d3525d-7001-44ae-b050-01a6fb54426a','題泉州萬安橋','陳偁','宋','宋诗','song-poetry','','[]','跨海爲橋布石牢，那知直下壓靈鼇。',64,'全唐诗/poet.song.23000.json','["跨海爲橋布石牢，那知直下壓靈鼇。", "基連島嶼規模壯，勢截淵潭氣象豪。", "鐵馬著行橫絕漠，玉鯨張鬣露寒濤。", "縑圖已幸天顔照，應得元豐史筆褒。"]'),
('ea2d4aa2-6f47-42f3-a7ea-1bcd9fd77f11','栟櫚山','陳偁','宋','宋诗','song-poetry','','[]','名藍依凈境，風物倍精神。',48,'全唐诗/poet.song.23000.json','["名藍依凈境，風物倍精神。", "翠巘藏山迹，寒潭絕世塵。", "嶺猿吟送月，山鳥語留人。", "擬學棲真客，林泉老此身。"]'),
('adacebc0-0f5b-4f3f-8b52-47e1e340a89b','重登羅浮','陳偁','宋','宋诗','song-poetry','','[]','十里山光翠障開，重遊何事意徘徊。',64,'全唐诗/poet.song.23000.json','["十里山光翠障開，重遊何事意徘徊。", "石樓自向雲中見，仙島誰知海上來。", "丹竈尚能含日月，龍潭還解起風雷。", "天南爲郡空華髮，十二年間到兩回。"]'),
('aaa05097-43ea-4dce-9e1a-886eb3912180','句','陳偁','宋','宋诗','song-poetry','','[]','壺漿壓境來迎拜，猶記溪山舊主人。',16,'全唐诗/poet.song.23000.json','["壺漿壓境來迎拜，猶記溪山舊主人。"]'),
('80f7fff9-9468-4855-b07b-4c2f06293043','送程給事知越州','石牧之','宋','宋诗','song-poetry','','[]','越絕江東第一州，邦人相慶得賢侯。',64,'全唐诗/poet.song.23000.json','["越絕江東第一州，邦人相慶得賢侯。", "已知和氣先春到，佇聽歡謠混海流。", "去醉湖山無賀老，坐吟風月揖浮丘。", "此行定奉丁寧詔，更老歸來侍冕旒。"]'),
('c63f11ac-c6ca-4fd6-b745-93cb79bafee9','送程給事知越州','崇大年','宋','宋诗','song-poetry','','[]','三朝風跡號名臣，十道宣勞德在民。',64,'全唐诗/poet.song.23000.json','["三朝風跡號名臣，十道宣勞德在民。", "大筆有功爭造化，宏才無地展經綸。", "方登青瑣瞻天近，又駕朱轓撫俗頻。", "宸眷正隆時望重，佇趨嚴召秉陶鈞。"]'),
('d1ff12a1-8ce4-44b9-acb5-72feeecf5200','宿朝宗驛遊洞天 宿朝宗驛','王越石','宋','宋诗','song-poetry','','[]','炎洲望處雲南北，嶢闕歸時路屈盤。',32,'全唐诗/poet.song.23000.json','["炎洲望處雲南北，嶢闕歸時路屈盤。", "喜得夜深清枕簟，月華斜白洞天寒。"]'),
('306ef200-88ad-423b-bcf6-9d2be3700385','宿朝宗驛遊洞天 遊洞天四首 其一','王越石','宋','宋诗','song-poetry','','[]','靜然華燭扣靈關，雲路登尋過幾盤。',32,'全唐诗/poet.song.23000.json','["靜然華燭扣靈關，雲路登尋過幾盤。", "溪水定流何處去，一條沈碧練光寒。"]'),
('448eb5e0-bd84-4fe2-90be-d6676acb90f3','宿朝宗驛遊洞天 遊洞天四首 其二','王越石','宋','宋诗','song-poetry','','[]','藥盆丹竈石床閒，龍虎當年向此盤。',32,'全唐诗/poet.song.23000.json','["藥盆丹竈石床閒，龍虎當年向此盤。", "雲馭久登天穴路，仙風依舊拂衣寒。"]'),
('e5576f50-79f4-4ace-bcbb-8b48b138fa85','宿朝宗驛遊洞天 遊洞天四首 其三','王越石','宋','宋诗','song-poetry','','[]','亂峰如展畫屏看，老蔓紆根虺鬥盤。',32,'全唐诗/poet.song.23000.json','["亂峰如展畫屏看，老蔓紆根虺鬥盤。", "飛步尋真儘深處，乳花凝雪逼人寒。"]'),
('1e519620-b2fd-4128-9410-871bdc57dd08','宿朝宗驛遊洞天 遊洞天四首 其四','王越石','宋','宋诗','song-poetry','','[]','清泉流急響珊珊，丹竈無煙玉石寒。',32,'全唐诗/poet.song.23000.json','["清泉流急響珊珊，丹竈無煙玉石寒。", "拂石坐來心慮息，氣清冰在玉精盤。"]'),
('90c50512-3b44-4304-9265-3744319971c0','春陰','呂夏卿','宋','宋诗','song-poetry','','[]','海棠陰淺日黄昏，畫閣輕寒繡被溫。',32,'全唐诗/poet.song.23000.json','["海棠陰淺日黄昏，畫閣輕寒繡被溫。", "春夢醒來能記否，賣花聲過忽開門。"]'),
('1fe8791e-e727-4015-a9c7-e1722317a94d','謁張相公祠','呂夏卿','宋','宋诗','song-poetry','','[]','天以伊皋生百越，力回堯舜作開元。',48,'全唐诗/poet.song.23000.json','["天以伊皋生百越，力回堯舜作開元。", "波濤漏網魚龍活，日月無光螮蝀昏。", "一自漁陽鼙鼓起，九重方憶老臣存。"]'),
('35e5ed55-9df6-4b7f-a149-12344f8d2a51','題憲師壁','釋法輝','宋','宋诗','song-poetry','','[]','遠浸溪光碧，寒生松檜陰。',24,'全唐诗/poet.song.23000.json','["遠浸溪光碧，寒生松檜陰。", "漁舟驚暮雨，高吹入秋林。"]'),
('58eac30b-1a85-41cf-b4c5-f09265ccd5b8','寄吳山人','釋法輝','宋','宋诗','song-poetry','','[]','夜召山翁酌，花間聊撫琴。',48,'全唐诗/poet.song.23000.json','["夜召山翁酌，花間聊撫琴。", "酒香來竹外，古意入雲深。", "月色臨諸水，溪光射遠岑。", "擬教塵土客，對此滌煩襟。"]'),
('466ca533-4f9e-406a-b8cf-4ab15dacb440','武陵別文瑩上人  其一','張師正','宋','宋诗','song-poetry','','[]','憶昔荆州屢過從，當時心已慕冥鴻。',64,'全唐诗/poet.song.23000.json','["憶昔荆州屢過從，當時心已慕冥鴻。", "渚宮禪伯唐齊己，淮甸詩豪宋惠崇。", "老格疏閒松倚澗，清談瀟灑坐生風。", "史官若覓高僧事，莫把名參伎術中。"]'),
('7b8cedf7-8cc5-4dff-b583-09f193482680','武陵別文瑩上人  其二','張師正','宋','宋诗','song-poetry','','[]','碧嶂孤雲冉冉歸，解携情緒異常時。',32,'全唐诗/poet.song.23000.json','["碧嶂孤雲冉冉歸，解携情緒異常時。", "餘生歲月能多少，此別應難約後期。"]'),
('7993d418-2478-44c8-b2d2-592a06dcc42e','句  其一','張師正','宋','宋诗','song-poetry','','[]','舊將封侯盡，降王賜姓歸。',12,'全唐诗/poet.song.23000.json','["舊將封侯盡，降王賜姓歸。"]'),
('7fa4c727-4c1b-4dd4-8d96-12ecd678f5cb','句  其二','張師正','宋','宋诗','song-poetry','','[]','蝸角功名時不與，澗松材幹老甘休。',16,'全唐诗/poet.song.23000.json','["蝸角功名時不與，澗松材幹老甘休。"]'),
('4496a108-0da3-43dd-9378-fb6414cdaf54','句  其三','張師正','宋','宋诗','song-poetry','','[]','分鹿是非皆委夢，落花貴賤不由人。',16,'全唐诗/poet.song.23000.json','["分鹿是非皆委夢，落花貴賤不由人。"]'),
('d254948f-c29e-437a-b103-dd6f218c1a30','建茶  其一','羅拯','宋','宋诗','song-poetry','','[]','自昔稱吳蜀，芳鮮尚未真。',36,'全唐诗/poet.song.23000.json','["自昔稱吳蜀，芳鮮尚未真。", "于今盛閩粵，冠絕始無倫。", "地占群山秀，時先百卉春。"]'),
('9b13c55c-452e-455c-8ef8-07110a868854','建茶  其二','羅拯','宋','宋诗','song-poetry','','[]','草木英華聚，樓臺紫翠重。',24,'全唐诗/poet.song.23000.json','["草木英華聚，樓臺紫翠重。", "山形仙苑鳳，泉脈御池龍。"]'),
('3b52156f-b93b-483d-a925-ef98f1e975e2','自嘲落牙','曹琰','宋','宋诗','song-poetry','','[]','昨朝飯裏有粗砂，隠落翁翁一箇牙。',32,'全唐诗/poet.song.23000.json','["昨朝飯裏有粗砂，隠落翁翁一箇牙。", "爲報妻兒莫惆悵，見存足以養渾家。"]'),
('3ed2aa3d-1a36-467b-8032-0618f3cfba77','圓通白衣閣','釋懷賢','宋','宋诗','song-poetry','','[]','白衣閣外繞珠欄，人在琉璃菡萏間。',32,'全唐诗/poet.song.23000.json','["白衣閣外繞珠欄，人在琉璃菡萏間。", "誰把此花爲刻漏，修行不放一時閒。"]'),
('85ba0883-1323-41e4-97df-77615200bd3f','燕子樓','陳薦','宋','宋诗','song-poetry','','[]','僕射新阡狐兔游，侍兒猶住水邊樓。',64,'全唐诗/poet.song.23000.json','["僕射新阡狐兔游，侍兒猶住水邊樓。", "風清玉簟慵欹枕，月好珠簾懶上鈎。", "寒夢覺來滄海闊，新詩吟罷紫蘭秋。", "樂天才思如春雨，斷送殘花一夕休。"]'),
('b091c40b-3515-4444-b4db-c2ff511008f4','子房廟','陳薦','宋','宋诗','song-poetry','','[]','博浪沙頭觸副車，潛游東夏識真符。',64,'全唐诗/poet.song.23000.json','["博浪沙頭觸副車，潛游東夏識真符。", "風雲智略移秦鼎，星斗功名啟漢圖。", "商老已來寧少海，赤松還約訪仙都。", "雍容進退全天道，凜凜高風萬古無。"]'),
('ae1c9996-4ee0-4980-9a38-e55ddc982b88','垓下','陳薦','宋','宋诗','song-poetry','','[]','九里山南楚漢爭，風波翻覆走長鯨。',64,'全唐诗/poet.song.23000.json','["九里山南楚漢爭，風波翻覆走長鯨。", "霸圖欲斷中宵失，帝業時來一戰成。", "懶渡滄江慚父老，更無勍敵壓韓彭。", "農人不識當時意，祗得春霖事耦耕。"]'),
('8079a6dc-9f8f-4e9f-b2f6-14d119517018','范增墓','陳薦','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','藏名羞立虎狼朝，乘鶴東依項籍豪。',64,'全唐诗/poet.song.23000.json','["藏名羞立虎狼朝，乘鶴東依項籍豪。", "憤失壯圖撞玉斗，不知天命與金刀。", "還家落日埋英氣，回首浮雲委舊勞。", "百步西連陵母塚，峨峨先識泰山高。"]'),
('11d009e0-6da2-41a8-a73f-2fb4a64b06a1','句','陳薦','宋','宋诗','song-poetry','','[]','塵靜山川狂鹿死，雷驚天地老龍飛。',16,'全唐诗/poet.song.23000.json','["塵靜山川狂鹿死，雷驚天地老龍飛。"]'),
('599e7952-03da-4338-bcf3-5d906a6b30e5','送程給事知越州  其一','孫固','宋','宋诗','song-poetry','','[]','朔南萬里使車馳，忽得山陰虎節歸。',64,'全唐诗/poet.song.23000.json','["朔南萬里使車馳，忽得山陰虎節歸。", "華省班聯青瑣貴，故鄉心逐白雲飛。", "江風雙槳催紅旆，海日層樓倚翠微。", "郡事逍遥吟醉裏，老年行樂更光輝。"]'),
('076feec7-e0d6-40de-9955-dd051a66e3a0','送程給事知越州  其二','孫固','宋','宋诗','song-poetry','','[]','東過錢塘第一州，郡城高爽五雲浮。',64,'全唐诗/poet.song.23000.json','["東過錢塘第一州，郡城高爽五雲浮。", "會稽山碧人多秀，賀監湖清月正秋。", "偃息鄉邦如志意，慰安雅俗自風流。", "朝廷賢舊方圖任，只恐蓬萊得暫留。"]'),
('64a9e56e-b3fa-4a92-90e3-1f9260531f1a','上元日駕幸太乙宮燒香','孫固','宋','宋诗','song-poetry','','[]','金輿晨動暖風微，比屋歡呼望帝暉。',64,'全唐诗/poet.song.23000.json','["金輿晨動暖風微，比屋歡呼望帝暉。", "天喜宴開祈福地，雲深香滿侍臣衣。", "九韶鳳舞當雙闕，萬燭龍趨護六飛。", "爲與吾民同樂事，月寒猶未下端闈。"]'),
('b0b775eb-0c6c-46e3-8a43-0ebd4b1bc6fb','鐵袈裟','張稚圭','宋','宋诗','song-poetry','','[]','愛山特地上山來，俗慮醒如醉眼開。',32,'全唐诗/poet.song.23000.json','["愛山特地上山來，俗慮醒如醉眼開。", "舉首但驚雲漢近，直疑平步出塵埃。"]'),
('1508774d-0fae-4d50-bdfa-ab4c44346650','多景樓','裴煜','宋','宋诗','song-poetry','','[]','登臨每憶衛公詩，多景唯於此處宜。',64,'全唐诗/poet.song.23000.json','["登臨每憶衛公詩，多景唯於此處宜。", "海岸千艘浮若芥，邦人萬室布如棋。", "江山氣象回環見，宇宙端倪指點知。", "禪老莫辭勤迓候，使君官滿有歸期。"]'),
('4100eb07-a1c4-406d-bece-6cd41a9be138','送程給事知越州','裴煜','宋','宋诗','song-poetry','','[]','邦人偏喜使君回，隔歲腰金護漕來。',64,'全唐诗/poet.song.23000.json','["邦人偏喜使君回，隔歲腰金護漕來。", "梓里萬□青鎖闥，偃蕃聊寄小蓬萊。", "中和已樂宣風職，平易還施報政才。", "休論引年祈退尚，即圖舊德陟公台。"]'),
('decf1253-b094-478e-8f9b-cadfecd84471','峴山','裴煜','宋','宋诗','song-poetry','','[]','襄陽有佳山，名著無如峴。',168,'全唐诗/poet.song.23000.json','["襄陽有佳山，名著無如峴。", "嘗休賢達足，我獨愧未踐。", "君侯把麾符，政暇興不淺。", "命車極登臨，旌旆隨谷轉。", "心思羊鉅平，息樹宜勿剪。", "于今戴清風，整整如冠冕。", "高碑本墮泪，雨漬至苔蘚。", "廟祠委榛蕪，奚勸千載善。", "馳章動天聽，口以功烈侔。", "果聞帝曰俞，恢宇明祭典。", "哦詩序其事，筆銳犀可剸。", "景無一髮遺，粲若丹青展。", "乃知覽觀時，非止在游衍。", "聲氣異代同，美從江漢顯。"]'),
('e13fe5ff-82b9-4d08-bfd2-3215f420fab6','送梵才上人歸天台','許懋','宋','宋诗','song-poetry','','[]','北岫巉巉敞佛居，詩翁安隠類逃虛。',64,'全唐诗/poet.song.23000.json','["北岫巉巉敞佛居，詩翁安隠類逃虛。", "平生節行清無玷，到老精神健有餘。", "門俯清江軒挂月，晝吟佳景夜觀書。", "黄山俗客嗟官縛，不得梯雲款凈廬。"]'),
('637a9387-3ecf-4767-b948-0d45420e931c','句','許懋','宋','宋诗','song-poetry','','[]','千丈峽峰石，淙錚寒玉鳴。',12,'全唐诗/poet.song.23000.json','["千丈峽峰石，淙錚寒玉鳴。"]'),
('3653a110-b81b-4031-87c5-628ce47b013f','示子','侯友彰','宋','宋诗','song-poetry','','[]','老去官仍舊，貧來口亦添。',48,'全唐诗/poet.song.23000.json','["老去官仍舊，貧來口亦添。", "舉杯瓶易罄，下箸味難兼。", "吾祖從來儉，癡兒莫謾嫌。", "萬錢終有命，遺汝不如廉。"]'),
('793ca9b9-ffae-4942-9796-43fb24ad7698','吏隠山','詹迥','宋','宋诗','song-poetry','','[]','五雲古名邑，維東有崇山。',72,'全唐诗/poet.song.23000.json','["五雲古名邑，維東有崇山。", "群峰屹羅列，一水相迴環。", "李侯築崇臺，吏隠於其間。", "斯人不可見，篆蝕苔文斑。", "我來訪遺跡，臨風發長嘆。", "洗尊挹醽醁，落日猶忘還。"]'),
('f2886780-634b-4f77-b581-15d8ab380616','天光觀','句士良','宋','宋诗','song-poetry','','[]','古殿千年屋，高松百尺陰。',24,'全唐诗/poet.song.23000.json','["古殿千年屋，高松百尺陰。", "真人不可問，時有鶴遺音。"]'),
('02393b86-12c3-47dd-898d-3ca06a5fc669','和','句士良','宋','宋诗','song-poetry','','[]','佛土依山福遠州，春行繡騎上雲頭。',64,'全唐诗/poet.song.23000.json','["佛土依山福遠州，春行繡騎上雲頭。", "補天彩石盈池在，朝海清江遶寺流。", "四國仰煩郇伯勞，群生翹望謝安遊。", "早知爲礪爲霖意，惟有西民欲暫留。"]'),
('2356d93a-f1ff-4a00-9f22-f9e426168189','拙詩五十六言贈富樂山海公長老','馮如晦','宋','宋诗','song-poetry','','[]','山名富樂冠三巴，佛子今生此出家。',64,'全唐诗/poet.song.23000.json','["山名富樂冠三巴，佛子今生此出家。", "六祖禪宗心頓悟，碧雲詩句衆爭誇。", "虎聞講法馴高座，鷗識忘機立淺沙。", "八十餘年無俗慮，只應幽會有蓮華。"]'),
('6edbf9cf-d129-497e-a47e-9915ed27e87f','奉和','袁陟','宋','宋诗','song-poetry','','[]','客意正索寞，詩筒江際來。',240,'全唐诗/poet.song.23000.json','["客意正索寞，詩筒江際來。", "一聞清玉韵，如見翠屏開。", "磅礴雲霄外，騰凌鸞鳳迴。", "仙源朝露蔽，乳竇夜風豗。", "九月已冰霰，三時無沴災。", "徒均南畝澤，應老鄧林材。", "岌岌聳天柱，巖巖尊國台。", "高名皆禍爾，真賞豈然哉。", "紫蓋欹松蔓，青錢點石苔。", "神虬潛夭矯，皓鶴舞毰毸。", "采藥蕃芝朮，尋花有杏梅。", "丹臺今窅窅，蒼壁古嵬嵬。", "絕頂飛泉落，平崖枯柏摧。", "勢堪卑蔣霍，名不假劉雷。", "釋子安生計，幽人足隠媒。", "雲中認旛剎，漢上醉觥罍。", "蓽戶方窮阨，籃軒阻奉陪。", "耳愁塵事入，心怯歲華催。", "已作五噫咏，元非三傑才。", "先將丘壑意，模寫寄春臺。"]'),
('2c844fc8-3a83-42eb-a709-ecf595cf1d45','宿簡寂觀','袁陟','宋','宋诗','song-poetry','','[]','名山崇秘祠，終夜得清賞。',96,'全唐诗/poet.song.23000.json','["名山崇秘祠，終夜得清賞。", "真氣溢空浮，流泉隨砌響。", "林巒片月散，殿閣高風行。", "天際斗杓直，庭中盤石橫。", "逸人今何之，故嶺不改秀。", "白鶴唳松梢，青燈覢巖竇。", "怳追汗漫駕，深悟逍遥言。", "四顧群動寂，冥心歸灝元。"]'),
('25b19d09-a87c-43c2-8bdb-118f5b27c6cf','再游雲居','袁陟','宋','宋诗','song-poetry','','[]','風吹嶺頭樹，似欲招行客。',240,'全唐诗/poet.song.23000.json','["風吹嶺頭樹，似欲招行客。", "緣雲過絕頂，復見紫霄宅。", "平觀三百里，下視八千尺。", "隼擊九秋嚴，鵬展萬里翮。", "五老鎮相望，西岫天與敵。", "可笑培塿群，亦自矜寸碧。", "氛埃卷宇宙，雁鶩下川澤。", "既諧慧智心，若蹈聖賢域。", "危亭據中峰，回抱竦天壁。", "沈沈古帝坐，左右列夔稷。", "舉頭河漢通，直欲攀南極。", "合奏天地籟，兩耳清歷歷。", "吁嗟萬類微，胡爲競朝夕。", "安知太清上，我方適所適。", "尚思西巘路，去冬躡雙屐。", "高興挹洪厓，大句鼓天力。", "到今巖壑間，浩浩起金石。", "安得少陵翁，物外講新格。", "重來羈紲在，欲隠世累迫。", "多謝受命松，長存歲寒色。"]'),
('8a821b1c-eef4-4428-bcb6-6f2b4ed825da','過金陵謁吳大帝廟','袁陟','宋','宋诗','song-poetry','','[]','人苦曹瞞虐，天悲漢祿終。',240,'全唐诗/poet.song.23000.json','["人苦曹瞞虐，天悲漢祿終。", "山河分鼎峙，氣象發江東。", "一旦墟京洛，彌年豢幼沖。", "炎精竟灰燼，紫蓋出艨艟。", "長策資公瑾，雄才得呂蒙。", "招延師友義，繼述父兄忠。", "舊府峨雙闕，驚濤涌半空。", "風雲龍虎勢，日月帝王功。", "地力因時險，神謀與意通。", "屈伸思所濟，逆順審于衷。", "駿足嗤交貨，靈牙耀即戎。", "同盟界函谷，獨斷保蠶叢。", "定霸葵丘劣，推心建武同。", "長沙兆生讖，典午頼餘風。", "戰守遺蹤在，登臨四望中。", "陵遷成萬古，世異想群雄。", "歌舞居民祀，干戈逐虜功。", "征帆來浦外，久客愴途窮。", "精銳銷孤劍，飄零若斷蓬。", "徘徊靈廡下，暮葉亂江楓。"]'),
('bd3f53c3-9d47-4438-b702-f6e8b06b7c52','題劉仁瞻畫像','袁陟','宋','宋诗','song-poetry','','[]','陣前仙琕生無愧，鼓下蠻奴死合羞。',32,'全唐诗/poet.song.23000.json','["陣前仙琕生無愧，鼓下蠻奴死合羞。", "三尺吳縑暗塵土，凜然蒼鶻欲橫秋。"]'),
('1caa2800-da6c-4ea2-9a34-352705b512a1','贈郭功甫二絕  其一','袁陟','宋','宋诗','song-poetry','','[]','從來多病王僧祐，自小能文謝惠連。',32,'全唐诗/poet.song.23000.json','["從來多病王僧祐，自小能文謝惠連。", "各厭塵勞思物外，莫辭携手訪林泉。"]'),
('57ca2ffc-a90d-483c-9f2b-aac497f61ee6','贈郭功甫二絕  其二','袁陟','宋','宋诗','song-poetry','','[]','雪後姑溪水更深，冥冥寒雨作連陰。',32,'全唐诗/poet.song.23000.json','["雪後姑溪水更深，冥冥寒雨作連陰。", "旅懷未可頓消遣，思與洛生溪上吟。"]'),
('d31f20d5-8f44-49ef-b28f-2d2f678ed955','贈功甫','袁陟','宋','宋诗','song-poetry','','[]','方山憶共汎金船，屈指于今五六年。',64,'全唐诗/poet.song.23000.json','["方山憶共汎金船，屈指于今五六年。", "風送梨花吹醉面，月和溪水上歸韉。", "浮生聚散應難料，末路窮通盡偶然。", "欲問故人牢落事，鹿裘深入白雲眠。"]'),
('8b241efc-9437-4f6f-a8e9-fbd9d591f463','臨終作','袁陟','宋','宋诗','song-poetry','','[]','青靄千峰暝，悲風萬古呼。',48,'全唐诗/poet.song.23000.json','["青靄千峰暝，悲風萬古呼。", "其誰挂寶劍，應有奠生芻。", "皎月東方隕，長松半壑枯。", "山泉吾所愛，聲到夜臺無。"]'),
('6962e5a6-358a-4bca-8e86-cd960e9b123b','百丈山','袁陟','宋','宋诗','song-poetry','','[]','複嶺踰崷崒，層崖遍屈盤。',72,'全唐诗/poet.song.23000.json','["複嶺踰崷崒，層崖遍屈盤。", "寺當幽谷面，路指白雲端。", "樹老蒼天骨，藍凝上帝冠。", "石屏秋已凍，板屋夜多寒。", "三宿孤懷戀，千山遠夢殘。", "惟愁鐘動曉，西下見征鞍。"]'),
('983c88e3-fa85-440f-832f-cd0d8c664011','浮雲宮','袁陟','宋','宋诗','song-poetry','','[]','爲余傳語嶺頭雲，君自無心笑我勤。',32,'全唐诗/poet.song.23000.json','["爲余傳語嶺頭雲，君自無心笑我勤。", "我亦暫來稱使者，眼看官職似看君。"]'),
('a2eac5fe-8e62-4e24-aae6-4f74e6c03243','句','袁陟','宋','宋诗','song-poetry','','[]','瓊田收𥝧稏，玉溜注琅玕。',12,'全唐诗/poet.song.23000.json','["瓊田收𥝧稏，玉溜注琅玕。"]'),
('d325a5e2-fcce-445e-ba97-19b0f384c726','雲門寺','蔡冠卿','宋','宋诗','song-poetry','','[]','憶昔雲門月正明，煩襟消盡覺神清。',64,'全唐诗/poet.song.23000.json','["憶昔雲門月正明，煩襟消盡覺神清。", "林泉自濯塵埃事，松檜靜含風雨聲。", "山鬼聽經藏戶牖，野猿偷果墮檐楹。", "幾年京洛緇塵滿，何日臨流一濯纓。"]'),
('02c0b40d-a05a-48ad-b0b1-98fe71bce6f6','送靈巖','蔡冠卿','宋','宋诗','song-poetry','','[]','僧讀儒書舉世稀，惟師精學出塵機。',64,'全唐诗/poet.song.23000.json','["僧讀儒書舉世稀，惟師精學出塵機。", "上都香火安禪久，東國林泉徇衆歸。", "道在莫從形相索，身閒都覺利名非。", "靈巖到日秋應晚，還寫新詩遍翠微。"]'),
('0df89d8f-989d-42a5-98e5-d3e2a6384d5d','過子陵釣臺','葉棐恭','宋','宋诗','song-poetry','','[]','勢利輕捐寄傲中，毅然高節凜秋風。',64,'全唐诗/poet.song.23000.json','["勢利輕捐寄傲中，毅然高節凜秋風。", "耕閒釣寂千年迹，立懦貪廉萬世功。", "須信林間無怨鶴，更知天外有冥鴻。", "扁舟夜泊靈祠下，慨慕先生道不窮。"]'),
('68d94248-8dd3-4008-a2d9-26424e407db8','次韵','楊蟠','宋','宋诗','song-poetry','','[]','零落東山老佛師，古來獨往似君稀。',64,'全唐诗/poet.song.23000.json','["零落東山老佛師，古來獨往似君稀。", "雪邊氣候春將破，林下神情句欲飛。", "後日當尋慧遠社，何人更贈大顛衣。", "一篇感發渾閑事，須脫青衫動少微。"]'),
('2156041b-237f-4a04-983e-976f9091c58c','約沖晦宿東山禪寺精舍先寄','楊蟠','宋','宋诗','song-poetry','','[]','上人合動林間興，吾恨衰遲學謝安。',64,'全唐诗/poet.song.23000.json','["上人合動林間興，吾恨衰遲學謝安。", "納屐操筇那有限，吹雲落雨漫無端。", "先憑報信春枝破，預想分題雪屋寒。", "林下不諳人世苦，笑將雙鬢與君看。"]'),
('69d26a80-9bb6-4546-8633-3328f47498f5','宿永安方丈書呈東山禪師','楊蟠','宋','宋诗','song-poetry','','[]','千年道在高僧傳，未論詩人更有評。',64,'全唐诗/poet.song.23000.json','["千年道在高僧傳，未論詩人更有評。", "曾著文章原大道，獨推性命濟群生。", "白雲已鎖山間寺，流水空傳世上名。", "林遠不聞鐘磬作，五更幽鳥轉春聲。"]'),
('32acf48b-a594-4336-a77c-7c4793dbbeea','次韵和酬','楊蟠','宋','宋诗','song-poetry','','[]','數百招提隠亂峰，蒼茫豈復辨君鐘。',64,'全唐诗/poet.song.23000.json','["數百招提隠亂峰，蒼茫豈復辨君鐘。", "春含未得黄鸝報，路轉唯尋白鹿蹤。", "庵在月邊長不鎖，興來天外忽相逢。", "山人莫笑衣冠客，亦有鴻來待賃舂。"]'),
('4aa4dc66-6375-4ba2-ba40-6a54054f199a','遊靈隠遇雨呈普慈及二詩翁','楊蟠','宋','宋诗','song-poetry','','[]','山老未容山客去，故將雲陣鎖山門。',64,'全唐诗/poet.song.23000.json','["山老未容山客去，故將雲陣鎖山門。", "雨催晚色凝諸嶺，雷送春聲落後村。", "今夜青林妨月上，故人白首把詩論。", "來朝山水終瀰汎，策杖相隨討澗源。"]'),
('ae9eff35-3f3b-4348-90da-7d903fc69210','次韵和酬','楊蟠','宋','宋诗','song-poetry','','[]','山風亦會山人意，卷盡天紛掃雪花。',64,'全唐诗/poet.song.23000.json','["山風亦會山人意，卷盡天紛掃雪花。", "明月當樓情已興，碧雲落紙句還佳。", "天威忽霽應通物，仙侶相便合姓麻。", "群動已消林木響，卧看星斗隔窗紗。"]'),
('5d6d15ae-3b10-4d70-b8a3-a23f7fcd7d80','早過天竺呈明智及同游二老','楊蟠','宋','宋诗','song-poetry','','[]','雨夜靈峰卧竹床，平明屐齒到雲堂。',64,'全唐诗/poet.song.23000.json','["雨夜靈峰卧竹床，平明屐齒到雲堂。", "門前雨過新溪滿，石上風回舊草香。", "山抱鐘聲圓不散，雪鋪瓦面冷無光。", "理公莫怪詩相惱，今日偕行總姓湯。"]'),
('537a47a1-1240-4b82-9dfc-5e75058f5925','次韵和酬','楊蟠','宋','宋诗','song-poetry','','[]','澗南一嘯清風發，林下重來白日長。',64,'全唐诗/poet.song.23000.json','["澗南一嘯清風發，林下重來白日長。", "雲遠石深連鷲嶺，水寒沙淺似魚梁。", "漫因野老詢前事，閒伴幽人擷衆芳。", "更欲窮源情未已，知君嗔我索歸忙。"]'),
('5cb48bf6-659c-411c-a0fb-2aa75ad3b3f1','遊天竺上寺呈東山仲靈沖晦','楊蟠','宋','宋诗','song-poetry','','[]','入林已忻猿鳥樂，共傲浮生勝大還。',64,'全唐诗/poet.song.23000.json','["入林已忻猿鳥樂，共傲浮生勝大還。", "身外是非雲不繫，社中留戀雨相關。", "籃輿寂寞愧彭澤，拄杖風流肖德山。", "寄語葛洪巖下水，莫流清夢落人間。"]'),
('3fba6735-b4ff-42d2-93e0-76347e131391','次韵和酬','楊蟠','宋','宋诗','song-poetry','','[]','不問猿崖鳥道深，携筇著屐伴君尋。',64,'全唐诗/poet.song.23000.json','["不問猿崖鳥道深，携筇著屐伴君尋。", "山中桂子驚寒夜，雪後梅花偪歲陰。", "欲住更逢青眼顧，相看須盡白頭吟。", "他年若續高僧傳，未放湯休與道林。"]'),
('add21b78-d6e1-441c-afc8-ccce0e1c4d68','宿天竺再贈東山禪師與沖晦','楊蟠','宋','宋诗','song-poetry','','[]','仲靈述作慚知己，沖晦篇章竊賞音。',64,'全唐诗/poet.song.23000.json','["仲靈述作慚知己，沖晦篇章竊賞音。", "勝侶俱恬山水樂，神交已過雪霜深。", "燈前自笑平生事，雨後重論一夜心。", "相檢莫教詩閒斷，更闌同聽夜猿吟。"]'),
('9237742b-adc2-4842-817d-e4e2b4555254','宿天竺寺賦聞泉呈二老','楊蟠','宋','宋诗','song-poetry','','[]','我有泉中興，平生愛水經。',48,'全唐诗/poet.song.23000.json','["我有泉中興，平生愛水經。", "山空時决决，夜靜轉泠泠。", "暗脈來湍急，清聲出混冥。", "月寒風不響，高枕與君聽。"]'),
('1b8e13d0-7a4c-40bb-821a-0c089f6697a8','次韵奉酬','楊蟠','宋','宋诗','song-poetry','','[]','臘後東風掃翠微，同看芳柳破春機。',64,'全唐诗/poet.song.23000.json','["臘後東風掃翠微，同看芳柳破春機。", "三宵聽水都無夢，四日登山未肯歸。", "野老止憑雲送客，家人應笑雨霑衣。", "君詩兼簡佳公子，只恐囊傾一夜飛。"]'),
('51fee87d-f958-47f5-945f-b6eba1e90847','游山歸遇雨呈仲靈沖晦','楊蟠','宋','宋诗','song-poetry','','[]','九里松門雪過時，籃輿裊裊礙松枝。',64,'全唐诗/poet.song.23000.json','["九里松門雪過時，籃輿裊裊礙松枝。", "雨留宿客還斜落，風送行人亦倒吹。", "華表忽驚黄鶴反，耳中猶带白猿悲。", "來朝弗著登山屐，可避君呼謝客兒。"]'),
('5a44a2a3-bb47-45ea-9e7e-a37faf93a424','山中回憶東山老','楊蟠','宋','宋诗','song-poetry','','[]','山游興發特尋君，屐齒筇枝繞四鄰。',64,'全唐诗/poet.song.23000.json','["山游興發特尋君，屐齒筇枝繞四鄰。", "峰北看雲忘世務，澗南聽水得天真。", "名高寂寞存僧史，林下風流似晉人。", "何日枇杷苦筍熟，却游未減去年春。"]'),
('eaaab4bb-d412-49c6-90e4-70a25fd04da7','次韵奉酬','楊蟠','宋','宋诗','song-poetry','','[]','幾夕論詩坐石窗，憐君百首妙無雙。',64,'全唐诗/poet.song.23000.json','["幾夕論詩坐石窗，憐君百首妙無雙。", "句牽野興侵孤月，惱亂詞源涌大江。", "數紙忽然來竺嶺，千年猶可照吳邦。", "相思未免還相挑，莫豎旗旛却詐降。"]'),
('69d1ca0a-f5e2-43d2-a65a-976728ccd57d','次韵奉酬','楊蟠','宋','宋诗','song-poetry','','[]','猿聲未落鳥聲愁，筍發花開澗水流。',64,'全唐诗/poet.song.23000.json','["猿聲未落鳥聲愁，筍發花開澗水流。", "還對春風驚節物，漫思野老傍林邱。", "古人得道多深隠，賢守知名貴早收。", "林下頻過君莫怪，自看骨相匪封侯。"]'),
('841797d5-587e-4b0e-8f4c-bd5ac6b20fbd','次韵奉和','楊蟠','宋','宋诗','song-poetry','','[]','聞說西庵好，藤州恐不歸。',48,'全唐诗/poet.song.23000.json','["聞說西庵好，藤州恐不歸。", "延年松可食，避世草堪衣。", "山塢雪應滾，林端梅亦稀。", "猶憐二禪老，佳句及城扉。"]'),
('3aa4df52-3c72-489d-a49d-c6148833504f','寄東山禪師','楊蟠','宋','宋诗','song-poetry','','[]','高卧西林月，孤閒獨見君。',48,'全唐诗/poet.song.23000.json','["高卧西林月，孤閒獨見君。", "杖藜探澗水，欹枕看山雲。", "鹿過何人見，猿啼只自聞。", "篇章知幾首，寄我莫辭勤。"]'),
('1f460d95-339c-4f34-a8e3-64428600d1b9','蟠雪夜登涌金樓遠望西山憶仲靈灑然有邁世之風因思山陰王徽之雪夜獨酌四望皎然徘徊詠左太沖招隠詩忽憶戴逵扁舟乘興余恨未能遂往聊寄此詩','楊蟠','宋','宋诗','song-poetry','','["\u897f\u6e56"]','家占西湖島上雲，雪光月色更侵魂。',64,'全唐诗/poet.song.23000.json','["家占西湖島上雲，雪光月色更侵魂。", "興來爛漫心空老，詩罷蒼茫眼正昏。", "晉國衣冠何處覓，梁朝殿閣儼猶存。", "思君不及山陰夜，遥望青松聽雪猿。"]'),
('74d4e194-5137-40bc-8615-c94181ffbe63','寄勉沖晦速和拙作','楊蟠','宋','宋诗','song-poetry','','[]','沖晦僧儒詩者豪，尤憐頼汝壯方袍。',64,'全唐诗/poet.song.23000.json','["沖晦僧儒詩者豪，尤憐頼汝壯方袍。", "一千篇興時無敵，三十年功格最高。", "白髪逢春今更勇，清吟徹老莫辭勞。", "何朝始肯將珠玉，却報仙人換木桃。"]'),
('3301a375-3da5-4ee1-8d1a-5f1c2c953240','次韵和酬','楊蟠','宋','宋诗','song-poetry','','[]','林扉厭聽雨聲頻，爲惜春風只九旬。',64,'全唐诗/poet.song.23000.json','["林扉厭聽雨聲頻，爲惜春風只九旬。", "裛撲山花將放杏，侵尋歲月已過人。", "何時好去游南澗，每夜空來望北辰。", "愁坐更無車馬客，獨憐詩筆謾相親。"]'),
('88e24cb0-09c4-40bc-b1b5-bc8306b1693b','初冬同晤賢二師登映發亭望會稽','楊蟠','宋','宋诗','song-poetry','','[]','我有二林侶，相邀步寒日。',144,'全唐诗/poet.song.23000.json','["我有二林侶，相邀步寒日。", "超然人外遊，下見衆山出。", "木葉落已靜，乾坤欠蕭瑟。", "浮雲當空翻，慘慘百鳥沒。", "欲辨越中岸，青烟易爲失。", "山川何寂寥，宮闕猶彷彿。", "誰是古來者，念之難再述。", "功名隨塵埃，豈復有其骨。", "今我二三子，永爲傲時物。", "篇章逢太平，窈窕坐天末。", "生理本無固，願言從此畢。", "登臨望前人，世事安敢忽。"]'),
('de19e067-ef5b-4db5-869f-c8d20a8a2956','墨池懷古','楊蟠','宋','宋诗','song-poetry','','[]','書畫嘗聞晉右軍，當時深遁樂天真。',64,'全唐诗/poet.song.23000.json','["書畫嘗聞晉右軍，當時深遁樂天真。", "空山寂寞人何在，一水泓澄墨尚新。", "靈運也思輕印綬，季鷹還解憶鱸蓴。", "高風敻古應相照，共是知幾此避身。"]'),
('759fb078-8992-4ed5-8175-30f9bf4078a0','憶越','楊蟠','宋','宋诗','song-poetry','','[]','蓬萊閣面對青山，地上遊人半是仙。',64,'全唐诗/poet.song.23000.json','["蓬萊閣面對青山，地上遊人半是仙。", "漁浦夕陽橫挂雨，鑒湖春浪倒垂天。", "高城尚鎖當時月，故殿空留幾處烟。", "長愛剡溪堪乘興，雪中曾棹子猷船。"]'),
('29ff226f-01f5-4fa4-8511-0f26a9ac5b58','蓴菜','楊蟠','宋','宋诗','song-poetry','','[]','休說江東春水寒，到來且覓鑒湖船。',64,'全唐诗/poet.song.23000.json','["休說江東春水寒，到來且覓鑒湖船。", "鶴生嫩頂浮新紫，龍脫香髯带舊涎。", "玉割鱸魚迎刃滑，香炊稻飯落匙圓。", "歸期不待秋風起，漉酒調羹任我年。"]'),
('66b9b469-18e5-4084-878d-231d63a9e9dc','永嘉雙蓮橋','楊蟠','宋','宋诗','song-poetry','','[]','昨日采蓮者，雙雙橋畔新。',24,'全唐诗/poet.song.23000.json','["昨日采蓮者，雙雙橋畔新。", "舊花今不見，喜見似花人。"]'),
('dd0ffe18-4ef1-4fe5-b8b2-1c6b1cfc3810','平南謠','楊蟠','宋','宋诗','song-poetry','','[]','海南山似刀，溪惡如發弩。',144,'全唐诗/poet.song.23000.json','["海南山似刀，溪惡如發弩。", "溪山毒烟中人骨，水有蛟蜃陸豺虎。", "蠻人傜賊行若飛，縱火劫民殺官府。", "溪中之水漲赤血，山頭積屍變成土。", "經年鬥戰兵已窮，磔將屠城不可數。", "官家發軍救死國，萬里歡喜得時雨。", "誅擒凶黨功德高，海水一清奏歌舞。", "山非無險，水非無阻。", "有地不城，城亦不武。", "將民赤肉致戈戟，口不能言心自苦。"]'),
('61e6f93f-ee4a-4580-ad18-f17dd00d334f','就食','楊蟠','宋','宋诗','song-poetry','','[]','未知田上勞，徒厭鼎中味。',48,'全唐诗/poet.song.23000.json','["未知田上勞，徒厭鼎中味。", "及與農事接，方驚食者貴。", "余生寡營求，念此豈易致。", "况敢懷寸祿，平居但羞愧。"]'),
('4487a6ad-d536-42de-8934-fcb2c7a0b31f','春日獨遊南園','楊蟠','宋','宋诗','song-poetry','','[]','天凈鳥飛遠，路幽花自香。',48,'全唐诗/poet.song.23000.json','["天凈鳥飛遠，路幽花自香。", "春風吹草木，野水滿池塘。", "事去青山在，人閒白日長。", "興來搔短髪，此意久難忘。"]'),
('f7205095-7f4f-415a-ba71-a5a7a8da6846','喜聞中丞包公稱職有書','楊蟠','宋','宋诗','song-poetry','','[]','薛宣執法動朝廷，丙魏如今亦有聲。',64,'全唐诗/poet.song.23000.json','["薛宣執法動朝廷，丙魏如今亦有聲。", "公道未亡猶可立，世人不慣却須驚。", "幅員潤澤嘉謀進，臺閣風流故事明。", "時論已兼言責重，莫教天下笑虛名。"]'),
('e52e208c-d80f-47a9-b978-3458c027fa4a','陪潤州裴如晦學士遊金山回作','楊蟠','宋','宋诗','song-poetry','','[]','世上蓬萊第幾洲，長雲漠漠鳥飛愁。',64,'全唐诗/poet.song.23000.json','["世上蓬萊第幾洲，長雲漠漠鳥飛愁。", "海山亂點當軒出，江水中分繞檻流。", "天遠樓臺橫北固，夜深燈火見揚州。", "回船却望金陵月，獨倚牙旗坐浪頭。"]'),
('bfa0f019-faf5-44d4-afc9-88f9631373a9','秦王纜船石','楊蟠','宋','宋诗','song-poetry','','[]','色陰長带雨，疑是白雲根。',24,'全唐诗/poet.song.23000.json','["色陰長带雨，疑是白雲根。", "欲問東巡事，今猶不敢言。"]'),
('d12da8d7-5822-4f66-a290-c227cac1f23e','醉眠亭  其一','楊蟠','宋','宋诗','song-poetry','','[]','江花可醉草堪眠，細想人間底處便。',32,'全唐诗/poet.song.23000.json','["江花可醉草堪眠，細想人間底處便。", "客散樽空欲歸去，此身還被月留連。"]'),
('bc26c3e2-4c0d-4f6a-8fbd-196bd2ea6839','醉眠亭  其二','楊蟠','宋','宋诗','song-poetry','','[]','江上聊遊我未能，羨君長醉卧高亭。',32,'全唐诗/poet.song.23000.json','["江上聊遊我未能，羨君長醉卧高亭。", "不因鶴唳破殘夢，還有凉風吹酒醒。"]'),
('78629589-1550-44be-96f8-2330d8bd7de9','醉眠亭  其三','楊蟠','宋','宋诗','song-poetry','','[]','清簟疏簾一醉身，寂寥不稱詠詩人。',32,'全唐诗/poet.song.23000.json','["清簟疏簾一醉身，寂寥不稱詠詩人。", "春風亦有憐才意，故擺殘花作綉裀。"]'),
('1aeb0d38-253a-47cc-94d0-c7da4b94aad7','慈雲嶺','楊蟠','宋','宋诗','song-poetry','','[]','左右盼江湖，游人憩半途。',24,'全唐诗/poet.song.23000.json','["左右盼江湖，游人憩半途。", "山高步步上，何用歎崎嶇。"]'),
('e7bd606b-54b8-4a2a-865e-7e95b06a7dcc','九師堂','楊蟠','宋','宋诗','song-poetry','','[]','易道已南矣，清風今尚寒。',24,'全唐诗/poet.song.23000.json','["易道已南矣，清風今尚寒。", "山人空再拜，不識漢衣冠。"]'),
('d6f031d1-773b-4715-b0d0-64d346b65191','虹橋','楊蟠','宋','宋诗','song-poetry','','[]','兩岸履聲雲外合，三州帆影月邊歸。',32,'全唐诗/poet.song.23000.json','["兩岸履聲雲外合，三州帆影月邊歸。", "欄干獨立秋風早，豈待鱸魚始拂衣。"]'),
('e2556b2a-643e-4e74-bd02-759da5ee3a62','笠澤','楊蟠','宋','宋诗','song-poetry','','[]','行吟澤畔心空健，解劍江頭事已非。',32,'全唐诗/poet.song.23000.json','["行吟澤畔心空健，解劍江頭事已非。", "把酒滄浪愧漁父，何人獨向秋風歸。"]'),
('1ead0ac3-525b-4fec-a538-ac64cb6d9aa4','鎮江','楊蟠','宋','宋诗','song-poetry','','[]','雲間鐵甕近青天，縹緲飛甍百尺連。',32,'全唐诗/poet.song.23000.json','["雲間鐵甕近青天，縹緲飛甍百尺連。", "幾番畫角催紅日，無事滄洲起白煙。"]'),
('9d4f609a-8514-46cc-9401-a071bf8039e3','練江亭','楊蟠','宋','宋诗','song-poetry','','[]','寒光萬頃淡高秋，粉壁朱欄凈客愁。',64,'全唐诗/poet.song.23000.json','["寒光萬頃淡高秋，粉壁朱欄凈客愁。", "晚月蕭蕭聞落葉，晴天歷歷數飛鷗。", "煙橫絕島疏難捲，月在平波瑩不流。", "懷抱未忘知有處，且吟風笛醉滄洲。"]'),
('8dd6760a-195c-492b-b428-a86fd831bb53','澄江亭','楊蟠','宋','宋诗','song-poetry','','[]','萬里松州對海門，蒼亭縹緲出飛塵。',64,'全唐诗/poet.song.23000.json','["萬里松州對海門，蒼亭縹緲出飛塵。", "東浮不礙三江下，北轉無聲百谷濱。", "月靜秋紋收白縠，天橫暮色變黄銀。", "風流小謝千年外，解咏消愁更有人。"]'),
('b5edf9ca-430e-48b2-a15f-d5864f8759e1','無題','釋行海','宋','宋诗','song-poetry','','[]','欲將心腹問漁翁，可住湘山第幾峰。',64,'全唐诗/poet.song.230000.json','["欲將心腹問漁翁，可住湘山第幾峰。", "世遠合應披薜荔，道存何必怨芙蓉。", "難教牧笛鳴如鳳，誰把漁竿釣得龍。", "極目危樓千里思，曉烟藏雨晚烟濃。"]'),
('12422c8a-f9d5-4b60-8cd2-73d9111f9cc9','經舊遊','釋行海','宋','宋诗','song-poetry','','[]','望望東西草色新，杖藜曾逐少年身。',64,'全唐诗/poet.song.230000.json','["望望東西草色新，杖藜曾逐少年身。", "風烟半是親題處，泉石多非舊主人。", "黄鳥有情頻喚侶，野花無語自傷春。", "閑心一片閑如水，心管悠悠陌上塵。"]'),
('a32e73ba-aa10-49ae-bc41-afed1baf488f','鷗','釋行海','宋','宋诗','song-poetry','','[]','從來潔白勝鸂鶒，不解浮沉愧鷺鷥。',64,'全唐诗/poet.song.230000.json','["從來潔白勝鸂鶒，不解浮沉愧鷺鷥。", "今日獨留楊柳岸，何年合到鳳凰池。", "風波自險身常穩，網罟雖多意不疑。", "四海五湖皆有分，人多相識少相知。"]'),
('84cd3881-65ce-4bb9-ac88-748df5d31c42','詠梅','釋行海','宋','宋诗','song-poetry','','[]','跨蹇尋芳带雪晴，幾番溪驛又山程。',64,'全唐诗/poet.song.230000.json','["跨蹇尋芳带雪晴，幾番溪驛又山程。", "可憐歲晚心偏苦，忽見春風眼倍明。", "淺磵石邊留野趣，矮籬竹外託幽情。", "繁華滿地凋零盡，難寫夷齊一種清。"]'),
('118cb5fa-b00d-47c3-9ce4-50d8edb0e4ca','松','釋行海','宋','宋诗','song-poetry','','[]','一樹喬喬迥出林，兔絲千尺附清陰。',64,'全唐诗/poet.song.230000.json','["一樹喬喬迥出林，兔絲千尺附清陰。", "怒枝伸縮蒼龍臂，翠頂盤桓老鶴心。", "古蘚皴皮藏凍蛻，細風入葉轉幽琴。", "婆娑獨秀青山裏，定有茯苓無處尋。"]'),
('96a913fb-dc67-4f6b-aabe-52a758ce71b7','紀感','釋行海','宋','宋诗','song-poetry','','[]','吳楚經年殺氣凝，艱難國步涉春冰。',64,'全唐诗/poet.song.230000.json','["吳楚經年殺氣凝，艱難國步涉春冰。", "義旗東下誰相似，誓楫中流我不能。", "水到南徐圍鐵甕，山從北固抱金陵。", "捷音尚隔蒼茫外，貂尾良弓足股肱。"]'),
('0282119a-da2f-44e7-a255-86bcf9ce2dd4','偶作  其一','釋行海','宋','宋诗','song-poetry','','[]','翩翩白鶴竟難尋，每對春山憶道林。',64,'全唐诗/poet.song.230000.json','["翩翩白鶴竟難尋，每對春山憶道林。", "百歲豈能長稱意，五湖難得盡知心。", "大槐國裏乾坤小，杜宇鄉中草木深。", "今古窮通皆是夢，林泉風月自閑吟。"]'),
('f72090e9-04cc-4c37-9e27-eeaaa7260b72','偶作  其二','釋行海','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','楚甸荒荒雜戍塵，行藏日日倚樓頻。',64,'全唐诗/poet.song.230000.json','["楚甸荒荒雜戍塵，行藏日日倚樓頻。", "風烟易老東西客，泉石偏疎富貴人。", "喜有白鷗知靜思，恨無黄鵠載閑身。", "岳僧近報匡廬事，瀑布房邊藥蕊新。"]'),
('7f71e954-8285-4599-86a2-e36eae5c5057','草廬爲張茂才賦','釋行海','宋','宋诗','song-poetry','','[]','風流全是漢衣簪，白首已成梁甫吟。',64,'全唐诗/poet.song.230000.json','["風流全是漢衣簪，白首已成梁甫吟。", "浮世渾無容易事，先生長有太平心。", "樽前暮雨苔花老，枕上晴烟稻葉深。", "最是懶迎金馬客，不曾彈鋏向知音。"]'),
('911fec67-428e-40c8-9593-ab7a03487c5c','風浪阻行再獲聚首故作是詩','釋行海','宋','宋诗','song-poetry','','[]','魚龍吹浪阻行舟，又得相尋暫聚頭。',64,'全唐诗/poet.song.230000.json','["魚龍吹浪阻行舟，又得相尋暫聚頭。", "不是於君多惜別，自緣今日少交遊。", "斜風細雨吳天遠，芳草垂楊越路愁。", "昨夜不知人未去，誤教魂夢過南州。"]'),
('29e507d7-e62f-453b-a63f-f64bb5d40cb4','前之十首次詩  其一','釋行海','宋','宋诗','song-poetry','','[]','十五游方今五十，駸駸白盡少年頭。',64,'全唐诗/poet.song.230000.json','["十五游方今五十，駸駸白盡少年頭。", "看來造物真兒戲，憶著平生冷汗流。", "宇宙何須三兔窟，山川總是一菟裘。", "眼前不見江湖處，終是相忘欠白鷗。"]'),
('aea6c467-da55-4087-b1ec-38d00915689a','前之十首次詩  其二','釋行海','宋','宋诗','song-poetry','','[]','十五游方今五十，風霜歷盡幾風波。',64,'全唐诗/poet.song.230000.json','["十五游方今五十，風霜歷盡幾風波。", "雌雄自古烏難辨，魚魯如今字轉訛。", "白日消磨英雄盡，青山埋葬故人多。", "烏啼花發茆廬暖，更喜春風長薜蘿。"]'),
('e0a4d1c2-91a5-4317-bf11-1aaa6e0c724e','前之十首次詩  其三','釋行海','宋','宋诗','song-poetry','','[]','十五游方今五十，異鄉偏感故鄉春。',64,'全唐诗/poet.song.230000.json','["十五游方今五十，異鄉偏感故鄉春。", "吳檣語燕頻留客，楚谷蠻鶑苦喚人。", "柳癭冷懸芳信雨，花鬚暖污阿香塵。", "如今又在長安別，夜夜天邊望北辰。"]'),
('ab9f1b15-3819-4819-a532-72d11276e196','前之十首次詩  其四','釋行海','宋','宋诗','song-poetry','','[]','十五游方今五十，久將孤錫掛山林。',64,'全唐诗/poet.song.230000.json','["十五游方今五十，久將孤錫掛山林。", "平生不作可憐色，是事但求無愧心。", "陌上春迴青草暖，天涯人去碧雲深。", "滿園風滾梅花雪，更有幽禽弄好音。"]'),
('56d19820-1034-4332-9771-3cf4fc2d3f2a','前之十首次詩  其五','釋行海','宋','宋诗','song-poetry','','[]','十五游方今五十，翻思四十九年非。',64,'全唐诗/poet.song.230000.json','["十五游方今五十，翻思四十九年非。", "守株林下頭添雪，掩卷燈前泪滴衣。", "過隙寸陰真可惜，流芳百世不如歸。", "沐蘭幾度彈烏帽，又欲沖天放鶴飛。"]'),
('dab5a481-1990-454c-8fde-e9a7fa9749cc','竹','釋行海','宋','宋诗','song-poetry','','[]','兩竿烟篠翠涓涓，數里清陰带渭川。',32,'全唐诗/poet.song.230000.json','["兩竿烟篠翠涓涓，數里清陰带渭川。", "自抱歲寒君子節，鳳凰不到已多年。"]'),
('cbdd1c22-5bc3-43dd-bc3e-10bbd3ee105d','蘭','釋行海','宋','宋诗','song-poetry','','[]','紫莖綠葉带春陰，千古湘江一寸心。',32,'全唐诗/poet.song.230000.json','["紫莖綠葉带春陰，千古湘江一寸心。", "今日已無君子佩，不如瀟灑在深林。"]'),
('0cab8c31-6fd0-487e-82e0-8557786fc094','荷花','釋行海','宋','宋诗','song-poetry','','[]','圓綠風翻翡翠雲，嬌紅露淡石榴裙。',32,'全唐诗/poet.song.230000.json','["圓綠風翻翡翠雲，嬌紅露淡石榴裙。", "采蓮聲隔花深處，應有鴛鴦夢裏聞。"]'),
('77cd70fa-e793-478a-be2d-9d0d7784d7c7','蟋蟀','釋行海','宋','宋诗','song-poetry','','[]','少年不解客中愁，砌下尋來鬭過秋。',32,'全唐诗/poet.song.230000.json','["少年不解客中愁，砌下尋來鬭過秋。", "今夜雨窗聽不得，聲聲渾欲白人頭。"]'),
('f3aba7ee-27cf-46fe-9905-892bae64634b','杜宇','釋行海','宋','宋诗','song-poetry','','[]','蜀水蜀山歸路迷，烟林春晚草萋萋。',32,'全唐诗/poet.song.230000.json','["蜀水蜀山歸路迷，烟林春晚草萋萋。", "野花如血無人管，空向長安枝上啼。"]'),
('929d096b-f5a5-4cd9-9835-fb305e8316c0','蝶','釋行海','宋','宋诗','song-poetry','','[]','三三兩兩舞春暄，玉翅香鬚更可憐。',32,'全唐诗/poet.song.230000.json','["三三兩兩舞春暄，玉翅香鬚更可憐。", "拂草巡花情未定，又隨風絮過鞦韆。"]'),
('aa2b7257-a011-4c7c-a276-7a284925c144','杜宇','釋行海','宋','宋诗','song-poetry','','[]','白首幾人能到家，暮雲殘月隔三巴。',32,'全唐诗/poet.song.230000.json','["白首幾人能到家，暮雲殘月隔三巴。", "巴江不是無皈路，何事年年怨□□。"]'),
('700785d3-fe35-484e-8712-c8a0b49b6396','燕','釋行海','宋','宋诗','song-poetry','','[]','細雨斜風綠滿郊，春風初度杏花梢。',32,'全唐诗/poet.song.230000.json','["細雨斜風綠滿郊，春風初度杏花梢。", "銜泥自向朱門去，不管茅簷有故巢。"]'),
('a5c91cc0-e6ef-4f8e-a603-530b3dd65e10','漁翁','釋行海','宋','宋诗','song-poetry','','[]','歷盡江湖白盡頭，生涯惟有一扁舟。',32,'全唐诗/poet.song.230000.json','["歷盡江湖白盡頭，生涯惟有一扁舟。", "醉來吹笛空沙上，魚自相忘水自流。"]'),
('27d5f977-c3bf-48e2-bb6e-74ea12956818','碁','釋行海','宋','宋诗','song-poetry','','[]','一著臨期下手難，但尋活路向前行。',32,'全唐诗/poet.song.230000.json','["一著臨期下手難，但尋活路向前行。", "從教對面成千里，黑白分明不用爭。"]'),
('4fafbfd4-5cf9-4308-af84-f882737f9915','離剡','釋行海','宋','宋诗','song-poetry','','[]','滿目溪山欠故人，在家翻憶異鄉春。',32,'全唐诗/poet.song.230000.json','["滿目溪山欠故人，在家翻憶異鄉春。", "明朝又向長安路，愁對鶑花憶老親。"]'),
('e0cd7a04-78b4-4c6a-b4e1-96757dd05997','述懷','釋行海','宋','宋诗','song-poetry','','[]','五月山中長對雨，一春湖上懶看花。',32,'全唐诗/poet.song.230000.json','["五月山中長對雨，一春湖上懶看花。", "杜鵑莫惱麻衣客，何處野泉不是家。"]'),
('aa44c283-4e85-487a-883a-33a301c4c4a7','夜坐','釋行海','宋','宋诗','song-poetry','','[]','寂寞燈花慰客情，濕雲收盡月還明。',32,'全唐诗/poet.song.230000.json','["寂寞燈花慰客情，濕雲收盡月還明。", "夜寒不作東歸夢，坐聽空山落葉聲。"]'),
('9aec5a81-3cda-436a-b9db-f036c47ee4fa','己酉作','釋行海','宋','宋诗','song-poetry','','[]','十載風烟不蹔閑，往來吳越舊江山。',32,'全唐诗/poet.song.230000.json','["十載風烟不蹔閑，往來吳越舊江山。", "如今結屋雲深處，不欲聽人話世間。"]'),
('8b33b646-2567-4698-a123-811f6bb73669','送蘭秋谷皈雙溪兼簡諸友','釋行海','宋','宋诗','song-poetry','','["\u897f\u6e56"]','故人多住山頭寺，到日先煩問起居。',32,'全唐诗/poet.song.230000.json','["故人多住山頭寺，到日先煩問起居。", "花柳西湖好時節，不來須寄幾行書。"]'),
('3e246968-7bfd-4e74-b814-95a6b7a31b5c','送俊癯翁并憶少野','釋行海','宋','宋诗','song-poetry','','[]','少野不來君又去，獨看花柳不成春。',32,'全唐诗/poet.song.230000.json','["少野不來君又去，獨看花柳不成春。", "江湖豈是無兄弟，如此知心有幾人。"]'),
('cdebdd87-c7f2-49d8-bd7a-ff85139754e1','題所見','釋行海','宋','宋诗','song-poetry','','[]','草埋苔染石麒麟，曾是何年富貴人。',32,'全唐诗/poet.song.230000.json','["草埋苔染石麒麟，曾是何年富貴人。", "雨打梨花寒食近，王孫騎馬自游春。"]'),
('fe581b36-fcae-465d-9d86-4c17112e759b','聽子善琴','釋行海','宋','宋诗','song-poetry','','[]','青松宿鶴磵泉流，雲意遲遲山意秋。',32,'全唐诗/poet.song.230000.json','["青松宿鶴磵泉流，雲意遲遲山意秋。", "一曲廣陵休盡奏，月寒天地古人愁。"]'),
('72842e2b-83e2-40f7-b823-f0cc1322b236','遠山平野','釋行海','宋','宋诗','song-poetry','','[]','雲山影影接暗沙，頻見回鵰打暮鴉。',32,'全唐诗/poet.song.230000.json','["雲山影影接暗沙，頻見回鵰打暮鴉。", "曾是吳王絃管地，春風吹草不吹花。"]'),
('4ebcffe2-f19d-4e8a-b489-f0f4b3d833ed','有所思','釋行海','宋','宋诗','song-poetry','','[]','又見春風草色肥，鳳樓塵鎖燕飛飛。',32,'全唐诗/poet.song.230000.json','["又見春風草色肥，鳳樓塵鎖燕飛飛。", "洛陽近日無花柳，猶恨多年不得歸。"]'),
('efd6559b-883e-4c76-b293-333e25898ade','除夜','釋行海','宋','宋诗','song-poetry','','[]','一年只有今宵在，心事悠悠陌上塵。',32,'全唐诗/poet.song.230000.json','["一年只有今宵在，心事悠悠陌上塵。", "風雪閉門誰念舊，燈花獨對未歸人。"]'),
('bd8acde8-7d87-442f-a276-5cdebc12f23e','讀朋友舊書','釋行海','宋','宋诗','song-poetry','','[]','故人南北路漫漫，舊信重將子細看。',32,'全唐诗/poet.song.230000.json','["故人南北路漫漫，舊信重將子細看。", "字字總添離別恨，暮天風急雁聲寒。"]'),
('e3a2c9e6-b6a5-4e7b-896d-2e33bdfbc8d1','江上','釋行海','宋','宋诗','song-poetry','','[]','江雨隨風打客身，鼕鼕津鼓祭潮神。',32,'全唐诗/poet.song.230000.json','["江雨隨風打客身，鼕鼕津鼓祭潮神。", "帆來帆去朝還暮，老盡東西南北人。"]'),
('36b400ca-8a74-4c0d-a405-6421ca3d0f57','閑倚','釋行海','宋','宋诗','song-poetry','','[]','閑倚江樓聽角聲，春風兩岸野花明。',32,'全唐诗/poet.song.230000.json','["閑倚江樓聽角聲，春風兩岸野花明。", "漁人占得烟波闊，日日扁舟自太平。"]'),
('7e7843fa-c03c-4be5-b081-b5777741b409','雨後','釋行海','宋','宋诗','song-poetry','','[]','雨過山林近暮鐘，片懷寂寂對孤松。',32,'全唐诗/poet.song.230000.json','["雨過山林近暮鐘，片懷寂寂對孤松。", "夜深笛怨梅花落，月照人間睡正濃。"]'),
('adb941ea-6a97-4af2-a4d5-4b9a7a7b046c','客吟','釋行海','宋','宋诗','song-poetry','','[]','花落花開春自迷，白雲流水客東西。',32,'全唐诗/poet.song.230000.json','["花落花開春自迷，白雲流水客東西。", "獨眠野店無燈火，雨濕黄昏杜宇啼。"]'),
('45505f19-5396-47ba-b16f-05fc8e8f6386','夜坐','釋行海','宋','宋诗','song-poetry','','[]','永夜青燈照獨吟，蕭蕭風雨遍山林。',32,'全唐诗/poet.song.230000.json','["永夜青燈照獨吟，蕭蕭風雨遍山林。", "十年如此倦遊客，只恐梅花識此心。"]'),
('283b3ac2-b7ca-412d-8e40-d21a4feac948','行京','釋行海','宋','宋诗','song-poetry','','[]','錦繡杭州幾萬家，野人猶戀舊京華。',32,'全唐诗/poet.song.230000.json','["錦繡杭州幾萬家，野人猶戀舊京華。", "舊京三百春風巷，一巷笙歌一巷花。"]'),
('24873f30-f215-4737-a33e-9446548fde63','寄南山簡行古','釋行海','宋','宋诗','song-poetry','','[]','澗畔梅花似杏紅，思君日日對春風。',32,'全唐诗/poet.song.230000.json','["澗畔梅花似杏紅，思君日日對春風。", "扁舟甚欲來相訪，聞道身長在定中。"]'),
('0410c5cc-e755-4ffb-a523-902c920f5d46','辛亥夏','釋行海','宋','宋诗','song-poetry','','[]','五月山窗擁綠陰，瘦身閑枕斷絃琴。',32,'全唐诗/poet.song.230000.json','["五月山窗擁綠陰，瘦身閑枕斷絃琴。", "如今不是花時節，可惜黄鸝弄好音。"]'),
('3fca6070-4924-47cf-b0d0-1620bd97bd37','送雲南上人','釋行海','宋','宋诗','song-poetry','','[]','雁雲蛩雨異鄉秋，聞道君家水石幽。',32,'全唐诗/poet.song.230000.json','["雁雲蛩雨異鄉秋，聞道君家水石幽。", "時節飄零皈去好，路歧南北使人愁。"]'),
('20b9cece-4503-409e-949c-1abdf2455ac6','天姥道中','釋行海','宋','宋诗','song-poetry','','[]','春風陌上野花香，目送北歸鴻雁行。',32,'全唐诗/poet.song.230000.json','["春風陌上野花香，目送北歸鴻雁行。", "百里青山行不盡，隔烟啼鳥又斜陽。"]'),
('7863ef9b-a2d6-4a10-b150-7596fcb117c6','南明道中','釋行海','宋','宋诗','song-poetry','','[]','麥長綠鬚桑蕾黄，百禽調舌百花香。',32,'全唐诗/poet.song.230000.json','["麥長綠鬚桑蕾黄，百禽調舌百花香。", "今年笑裏逢春色，笑裏逢春有幾場。"]'),
('73b2e6c0-c3f5-4ccf-92a0-72cf8d4c5277','別白雲養恬齋','釋行海','宋','宋诗','song-poetry','','[]','扁舟去看沃洲梅，門鎖寒雲徑鎖苔。',32,'全唐诗/poet.song.230000.json','["扁舟去看沃洲梅，門鎖寒雲徑鎖苔。", "只待百花都謝了，清和時節我歸來。"]'),
('48808899-818d-4189-b226-a246a36acaa7','天竺冬夜','釋行海','宋','宋诗','song-poetry','','[]','白雲寂寂樹蒼蒼，夜靜泉聲到石房。',32,'全唐诗/poet.song.230000.json','["白雲寂寂樹蒼蒼，夜靜泉聲到石房。", "淡月照窗寒夢醒，枕邊聞得野梅香。"]'),
('bdfebb25-6b0f-47bb-a5b7-f1d309a6a33c','湖上懷同少野','釋行海','宋','宋诗','song-poetry','','[]','衰柳殘陽泊釣船，白鷗零落畫橋邊。',32,'全唐诗/poet.song.230000.json','["衰柳殘陽泊釣船，白鷗零落畫橋邊。", "咸平處士梅花樹，不得同看又兩年。"]'),
('720d4ab0-e9bd-42af-b89e-8e7265794b9d','懷同小野','釋行海','宋','宋诗','song-poetry','','[]','秋雨秋風落葉頻，江湖誰念寂寥身。',32,'全唐诗/poet.song.230000.json','["秋雨秋風落葉頻，江湖誰念寂寥身。", "雁行自向東南去，太白山中有故人。"]'),
('be967334-52ad-42f8-9d3a-2184e1454167','溪上','釋行海','宋','宋诗','song-poetry','','[]','小艇悠悠載夕暉，岸花紅白鷺鷥飛。',32,'全唐诗/poet.song.230000.json','["小艇悠悠載夕暉，岸花紅白鷺鷥飛。", "十年不見溪頭石，今日重重裹綠衣。"]'),
('6e1d9aed-4240-4fd4-8dac-cf40528df8d7','送選上人','釋行海','宋','宋诗','song-poetry','','[]','江天雁過客心遥，一舸凉風八月潮。',32,'全唐诗/poet.song.230000.json','["江天雁過客心遥，一舸凉風八月潮。", "七十二湖烟雨岸，蓼花楓葉正蕭蕭。"]'),
('fe2b7287-7e14-46ad-acfd-d2233808e539','北山作','釋行海','宋','宋诗','song-poetry','','[]','客思年年雲水長，寒花春草總堪傷。',32,'全唐诗/poet.song.230000.json','["客思年年雲水長，寒花春草總堪傷。", "如今自愛山林好，却聽猿啼不斷腸。"]'),
('7f78ff89-a48c-4663-aed3-5ddaa0fe35e6','湖上懷周汶陽','釋行海','宋','宋诗','song-poetry','','[]','看了梅花看柳條，可憐斜日照蓬蒿。',32,'全唐诗/poet.song.230000.json','["看了梅花看柳條，可憐斜日照蓬蒿。", "踏歌社裏人無數，誰伴春風醉碧桃。"]'),
('bbd76d0c-a2bd-44da-9191-783512728d9f','有懷','釋行海','宋','宋诗','song-poetry','','[]','小雨如烟柳杪迷，伯勞東去燕西飛。',32,'全唐诗/poet.song.230000.json','["小雨如烟柳杪迷，伯勞東去燕西飛。", "須臾又是春三月，門對碧桃人未歸。"]'),
('97062020-b54e-4205-8843-1407c358a4ac','清明日作  其一','釋行海','宋','宋诗','song-poetry','','[]','楊柳池邊獨倚闌，清明時節雨生寒。',32,'全唐诗/poet.song.230000.json','["楊柳池邊獨倚闌，清明時節雨生寒。", "春風不是多憔悴，今歲鶑花自懶看。"]'),
('7484164e-8b20-41d9-b5fb-25494720552b','清明日作  其二','釋行海','宋','宋诗','song-poetry','','[]','柳外田園耕野苔，長安誰又棄官來。',32,'全唐诗/poet.song.230000.json','["柳外田園耕野苔，長安誰又棄官來。", "黄花亦謂先生死，歲歲重陽少得開。"]'),
('ecf151e9-e898-4bf7-a467-4e441bab0516','天台清溪','釋行海','宋','宋诗','song-poetry','','[]','碧草生芽鳥弄春，短長亭外柳條新。',32,'全唐诗/poet.song.230000.json','["碧草生芽鳥弄春，短長亭外柳條新。", "釣船來往清溪上，定有桃花洞裏人。"]'),
('b0425940-4980-4834-9672-1b68bd3b8a5a','送懋上人','釋行海','宋','宋诗','song-poetry','','[]','青山三月野花紅，來伴天涯寂寞中。',32,'全唐诗/poet.song.230000.json','["青山三月野花紅，來伴天涯寂寞中。", "知子本無相別意，杜鵑昨夜惡春風。"]'),
('0d3f0183-ed9c-4744-83b3-55eeb2bb89f3','寄無相寧道二友','釋行海','宋','宋诗','song-poetry','','[]','只隔青山百餘里，都無消息是何如。',32,'全唐诗/poet.song.230000.json','["只隔青山百餘里，都無消息是何如。", "春來雖有遊人使，逆旅情懷懶作書。"]'),
('fcb64151-bad8-48ea-bbd5-4fd0ea177b83','夜坐','釋行海','宋','宋诗','song-poetry','','[]','雨雪蕭蕭在異鄉，冷看孤影百愁生。',32,'全唐诗/poet.song.230000.json','["雨雪蕭蕭在異鄉，冷看孤影百愁生。", "江南江北春風好，坐對寒燈到五更。"]'),
('1fd61b63-8f5c-4e79-9cbd-8c08f8264d61','回東州','釋行海','宋','宋诗','song-poetry','','[]','幾年燈火客長安，三十無成亦自慚。',32,'全唐诗/poet.song.230000.json','["幾年燈火客長安，三十無成亦自慚。", "吾道寂寥先輩盡，人尋山水向東南。"]'),
('a8107b4b-b3ad-4e31-b6db-4cc644cbcd69','寄淵仲深','釋行海','宋','宋诗','song-poetry','','[]','一樹梅花獨對門，雪風吹雁沒寒雲。',32,'全唐诗/poet.song.230000.json','["一樹梅花獨對門，雪風吹雁沒寒雲。", "夢魂昨夜東南去，行盡江山不見君。"]'),
('10034a75-f357-4518-a600-38ca5efd4b49','送當上人歸四明','釋行海','宋','宋诗','song-poetry','','[]','數載相隨見子情，今朝難使別離輕。',32,'全唐诗/poet.song.230000.json','["數載相隨見子情，今朝難使別離輕。", "此心恰似寒潮水，直送征帆到四明。"]'),
('cba962d4-23e1-4817-a4aa-42a2e37c0057','送穆上人歸鳳山兼簡仲深  其一','釋行海','宋','宋诗','song-poetry','','[]','客亭楊柳思悠悠，隔岸青山是越州。',32,'全唐诗/poet.song.230000.json','["客亭楊柳思悠悠，隔岸青山是越州。", "風急片帆飛鳥外，一江烟雨結春愁。"]'),
('21ad7b71-edbf-496d-8b41-fffe7503f2ae','送穆上人歸鳳山兼簡仲深  其二','釋行海','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南國風烟暗客塵，鳳凰山上百花春。',32,'全唐诗/poet.song.230000.json','["南國風烟暗客塵，鳳凰山上百花春。", "煩君話我相思苦，十載西湖欠一人。"]'),
('12600d48-89f5-4337-8cf8-7262b833aa98','暮春','釋行海','宋','宋诗','song-poetry','','[]','老盡春風蝶未知，綠陰深處囀黄鸝。',32,'全唐诗/poet.song.230000.json','["老盡春風蝶未知，綠陰深處囀黄鸝。", "如今不作看花念，空對垂楊惜別離。"]'),
('72cffef3-8b74-497f-aabb-32dcffa2fc7d','永定寺客窗','釋行海','宋','宋诗','song-poetry','','[]','千古門前水自流，小春天氣奪清秋。',32,'全唐诗/poet.song.230000.json','["千古門前水自流，小春天氣奪清秋。", "寂寥方丈黄昏月，照見梨花一樹愁。"]'),
('8215597c-21e8-4b34-80de-be11db101867','林間','釋行海','宋','宋诗','song-poetry','','[]','林間隨分樂清朝，長愛菖蒲對寂寥。',32,'全唐诗/poet.song.230000.json','["林間隨分樂清朝，長愛菖蒲對寂寥。", "客到每嫌聞夜雨，窗前不要種芭蕉。"]'),
('0cd808fd-4505-4416-b2a8-2c9763e97aac','小池','釋行海','宋','宋诗','song-poetry','','[]','白綿飛盡綠絲深，無數魚兒聚藻陰。',32,'全唐诗/poet.song.230000.json','["白綿飛盡綠絲深，無數魚兒聚藻陰。", "日夜潺湲聲不斷，分明一片伯牙心。"]'),
('781cdd11-0aa0-4117-8d2e-2d8312c4972b','客中','釋行海','宋','宋诗','song-poetry','','[]','白雲流水自東西，漠漠楊花客思迷。',32,'全唐诗/poet.song.230000.json','["白雲流水自東西，漠漠楊花客思迷。", "杜宇亦來歸未得，一春不向此山啼。"]'),
('c2ede79a-b813-442f-a68e-65139da9d08a','悼許梅屋','釋行海','宋','宋诗','song-poetry','','[]','相伴梅花過一生，月香水影是肝腸。',32,'全唐诗/poet.song.230000.json','["相伴梅花過一生，月香水影是肝腸。", "如今梅壞先生死，屋外春風吹夕陽。"]'),
('547b7119-ee16-4890-abbd-0158b6bb1421','懷希晉此山二友','釋行海','宋','宋诗','song-poetry','','[]','長思石色草堂前，更有梅花曲水邊。',32,'全唐诗/poet.song.230000.json','["長思石色草堂前，更有梅花曲水邊。", "昨夜珊瑚枝上月，照人何事不團圓。"]'),
('a3e297ca-290d-413b-9d77-fe674b0a3bd4','春意','釋行海','宋','宋诗','song-poetry','','["\u897f\u6e56"]','生來不識舊京春，望斷春風滿眼塵。',32,'全唐诗/poet.song.230000.json','["生來不識舊京春，望斷春風滿眼塵。", "二月西湖好花柳，相逢都是太平人。"]'),
('f6f675f9-61ce-4158-926e-691af1d918a0','客中得雲浦書以舟見招','釋行海','宋','宋诗','song-poetry','','[]','字草情真讀未休，夕陽河上便登舟。',32,'全唐诗/poet.song.230000.json','["字草情真讀未休，夕陽河上便登舟。", "望中不見書來日，一點征鴻一點愁。"]'),
('c1e94bc5-d9db-4213-aee6-7894488eaf55','別東岑上人','釋行海','宋','宋诗','song-poetry','','[]','明朝蹤跡又天涯，不及同看九日花。',32,'全唐诗/poet.song.230000.json','["明朝蹤跡又天涯，不及同看九日花。", "莫道秋來難作客，心閑隨處即吾家。"]'),
('71a9d40b-4e20-4597-bcc1-7bc563ba556f','周浦道中','釋行海','宋','宋诗','song-poetry','','[]','淺蘆深葦雨叢叢，一浦潮來一浦風。',32,'全唐诗/poet.song.230000.json','["淺蘆深葦雨叢叢，一浦潮來一浦風。", "船傍水籬門外過，數聲白犬吠魚翁。"]'),
('df3e8626-5e1c-4dc2-9c77-d7ad4e117d62','客永定寺懷天竺','釋行海','宋','宋诗','song-poetry','','[]','寂寞潮聲入寺門，浦風吹落樹頭雲。',32,'全唐诗/poet.song.230000.json','["寂寞潮聲入寺門，浦風吹落樹頭雲。", "幾番憶著薌林石，昨夜孤猿夢裏聞。"]'),
('6db35d11-01ad-4e87-8601-5bd603ec3725','諸友夜話','釋行海','宋','宋诗','song-poetry','','[]','愛戰將軍未白頭，寸心猶自不忘憂。',32,'全唐诗/poet.song.230000.json','["愛戰將軍未白頭，寸心猶自不忘憂。", "華夷百歲興亡事，一夜同君說蔡州。"]'),
('a079e437-ebab-4abe-be66-24e53fe66c72','無題','釋行海','宋','宋诗','song-poetry','','[]','笙歌日日醉春風，簾捲畫堂花影中。',32,'全唐诗/poet.song.230000.json','["笙歌日日醉春風，簾捲畫堂花影中。", "不是鳳凰飛不到，更無一樹是梧桐。"]'),
('e17728d9-09c9-4297-bd58-69c6e6c64546','冷泉冬夜','釋行海','宋','宋诗','song-poetry','','[]','數峰奇石翠層層，一片沙泉夜作冰。',32,'全唐诗/poet.song.230000.json','["數峰奇石翠層層，一片沙泉夜作冰。", "月照樹頭風不起，白猿應見倚闌僧。"]'),
('0c3ece34-5bf0-46a7-b428-697f6c5754ec','鷺','釋行海','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','來往長江點翠屏，江風裊裊頂絲輕。',32,'全唐诗/poet.song.230000.json','["來往長江點翠屏，江風裊裊頂絲輕。", "有時拳足蘆花畔，魚在蘆花影裏行。"]'),
('de3ffb0a-2753-440a-9e6d-b92c72a98423','書野店壁','釋行海','宋','宋诗','song-poetry','','[]','門逕斜斜草色深，傷春蝴蝶亦傷心。',32,'全唐诗/poet.song.230000.json','["門逕斜斜草色深，傷春蝴蝶亦傷心。", "野花落盡無人見，空有黄鸝囀綠陰。"]'),
('740a62ff-0e1d-47bd-a33f-06171f0a9617','薌林感舊','釋行海','宋','宋诗','song-poetry','','[]','平生最愛薌林石，奇樹怪藤猿往來。',32,'全唐诗/poet.song.230000.json','["平生最愛薌林石，奇樹怪藤猿往來。", "舊友共題行記處，如今字字是蒼苔。"]'),
('af06810a-0266-4838-9a10-056ba9c1637e','臨川道中','釋行海','宋','宋诗','song-poetry','','[]','谿林烟靄雜斜陽，髣髴遥岸是故鄉。',32,'全唐诗/poet.song.230000.json','["谿林烟靄雜斜陽，髣髴遥岸是故鄉。", "客裏忽驚時節過，酒旗山店菊花黄。"]'),
('974d6b4a-355e-4775-bf4a-2df7f0bd5f6f','北山春暮','釋行海','宋','宋诗','song-poetry','','[]','滿山朝氣藹芳晴，鳥蹈幽松弄好聲。',32,'全唐诗/poet.song.230000.json','["滿山朝氣藹芳晴，鳥蹈幽松弄好聲。", "九十日春如夢過，看花不是少年情。"]'),
('1ac565ae-c157-456c-a4c1-034e1d876d7d','登姑蘇臺','釋行海','宋','宋诗','song-poetry','','[]','姑蘇臺上鹿麇來，流水千年去不回。',32,'全唐诗/poet.song.230000.json','["姑蘇臺上鹿麇來，流水千年去不回。", "野草青青都是恨，春風不放百花開。"]'),
('7c71998b-7b52-4e4e-9073-a7bdea096fa1','仲春夜客航值雪','釋行海','宋','宋诗','song-poetry','','[]','夜航憂雪到桑麻，冬暖春寒感物華。',32,'全唐诗/poet.song.230000.json','["夜航憂雪到桑麻，冬暖春寒感物華。", "中有五陵年少客，只憐桃杏凍無花。"]'),
('45510b42-46d1-458b-b2a6-c198f241112c','和林逢吉','釋行海','宋','宋诗','song-poetry','','[]','金鴨香銷白晝長，玉階春影弄垂楊。',32,'全唐诗/poet.song.230000.json','["金鴨香銷白晝長，玉階春影弄垂楊。", "東風不管人憔悴，頻送飛花出禁牆。"]'),
('272353d1-d43b-4de2-ace6-738102ffa775','懷昭樵屋并越中諸友','釋行海','宋','宋诗','song-poetry','','[]','又見春風湖上花，故人南北已無多。',32,'全唐诗/poet.song.230000.json','["又見春風湖上花，故人南北已無多。", "誰能記得同遊處，不奈萋萋綠草何。"]'),
('fa660b3f-7445-46eb-b805-2e2607720860','北橋夜泊','釋行海','宋','宋诗','song-poetry','','[]','夜泊北橋楊柳汀，捲蓑爲枕夢魂清。',32,'全唐诗/poet.song.230000.json','["夜泊北橋楊柳汀，捲蓑爲枕夢魂清。", "覺來亂滴孤蓬雨，認作梧桐葉上聲。"]'),
('41f4b159-82f7-47ec-8028-ef5ea5dce8e2','楊柳枝詞  其一','釋行海','宋','宋诗','song-poetry','','[]','□天纖□起新愁，青眼鵞黄憶舊遊。',32,'全唐诗/poet.song.230000.json','["□天纖□起新愁，青眼鵞黄憶舊遊。", "唯有長絲牽不斷，洛陽城裏映朱樓。"]'),
('0a576079-6879-4cf1-853d-a1921870052d','楊柳枝詞  其二','釋行海','宋','宋诗','song-poetry','','[]','一陣楊花一陣愁，綠陰陰處暫停舟。',32,'全唐诗/poet.song.230000.json','["一陣楊花一陣愁，綠陰陰處暫停舟。", "莫嫌不折長條贈，有個黄鶑在上頭。"]'),
('579d266e-ab1a-411c-9b05-21477e40269a','楊柳枝詞  其三','釋行海','宋','宋诗','song-poetry','','[]','渭水橋邊送別時，馬前折贈笛中吹。',32,'全唐诗/poet.song.230000.json','["渭水橋邊送別時，馬前折贈笛中吹。", "若教繫得離情住，那管千絲又萬絲。"]'),
('1758ea85-796a-4448-b75f-05fa33b8db87','對月','釋行海','宋','宋诗','song-poetry','','[]','海兔上天星斗稀，滿身清影立多時。',32,'全唐诗/poet.song.230000.json','["海兔上天星斗稀，滿身清影立多時。", "望中欲倩姮娥手，擲下秋香一兩枝。"]'),
('66ebd88a-0123-49fc-a7c2-cd3900014ec6','無題','釋行海','宋','宋诗','song-poetry','','[]','聽罷楊花聽竹枝，上樓偏是下樓遲。',32,'全唐诗/poet.song.230000.json','["聽罷楊花聽竹枝，上樓偏是下樓遲。", "片雲歲晚皈何處，江水東流無盡時。"]'),
('11d40211-f90b-4bf5-a16e-d4aeebdb06b3','自永和溪上泛舟至餘不  其一','釋行海','宋','宋诗','song-poetry','','[]','水天空闊正斜陽，何處山川是故鄉。',32,'全唐诗/poet.song.230000.json','["水天空闊正斜陽，何處山川是故鄉。", "望斷吳雲心更遠，寒鴉成陣雁成行。"]'),
('9bbf3a64-b4d4-425e-9f90-a59e1bae5df4','自永和溪上泛舟至餘不  其二','釋行海','宋','宋诗','song-poetry','','[]','來往篙師夜唱歌，動人離思惱人多。',32,'全唐诗/poet.song.230000.json','["來往篙師夜唱歌，動人離思惱人多。", "就船欲作東皈夢，無奈溪山月色何。"]'),
('1e414394-beb3-42fb-9d5c-d0812b5c65f6','自永和溪上泛舟至餘不  其三','釋行海','宋','宋诗','song-poetry','','[]','看看又年別年華，多在征途少在家。',32,'全唐诗/poet.song.230000.json','["看看又年別年華，多在征途少在家。", "一種客懷清更苦，水村山磵見梅花。"]'),
('44d1e006-fc57-49ed-9fed-f4185c3cdcaa','思溪舟中','釋行海','宋','宋诗','song-poetry','','[]','鄰雞三唱趣行舟，霜結銀花滿樹頭。',32,'全唐诗/poet.song.230000.json','["鄰雞三唱趣行舟，霜結銀花滿樹頭。", "好景留人歸未得，客愁一半是吟愁。"]'),
('decad662-2181-4222-ac99-97f6ffe48503','回龍橋上晚望','釋行海','宋','宋诗','song-poetry','','[]','回龍橋上憶龍回，營角嗚咿怨落梅。',32,'全唐诗/poet.song.230000.json','["回龍橋上憶龍回，營角嗚咿怨落梅。", "旦暮北風吹雁急，誰從沙漠寄書來。"]'),
('8f467b02-397b-4af7-a051-85cbbd969cb7','宜晚樓','釋行海','宋','宋诗','song-poetry','','[]','奇峰列列樹蒼蒼，每愛危闌挹翠光。',32,'全唐诗/poet.song.230000.json','["奇峰列列樹蒼蒼，每愛危闌挹翠光。", "宿鳥皈時看最好，淡烟一抹鎖斜陽。"]'),
('bc1a2116-a454-4dcb-a6e0-d6fd3143dee1','憶西湖','釋行海','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水北雲南最好春，柳橋花架污芳塵。',32,'全唐诗/poet.song.230000.json','["水北雲南最好春，柳橋花架污芳塵。", "如今老大情遍懶，分付江山與後人。"]'),
('6ff5c780-5088-4e52-a1e5-6aac8c75ea2b','送思上人歸霅上','釋行海','宋','宋诗','song-poetry','','[]','長安城外別垂楊，溪上蘋花滿棹香。',32,'全唐诗/poet.song.230000.json','["長安城外別垂楊，溪上蘋花滿棹香。", "明月照人應有恨，西風吹雁不成行。"]'),
('c48fad08-e6a3-4756-a291-bdedf16da44a','送姪孫周上人歸剡余亦入吳門  其一','釋行海','宋','宋诗','song-poetry','','[]','兩年相伴白雲間，一棹秋風又獨還。',32,'全唐诗/poet.song.230000.json','["兩年相伴白雲間，一棹秋風又獨還。", "目斷江南無過雁，小樓寂寞對青山。"]'),
('4a38e293-ba97-4472-bf91-34c77a113e1b','送姪孫周上人歸剡余亦入吳門  其二','釋行海','宋','宋诗','song-poetry','','[]','年老心孤怕別離，天涯唯有影相隨。',32,'全唐诗/poet.song.230000.json','["年老心孤怕別離，天涯唯有影相隨。", "子今皈去重來日，須及梅花未放時。"]'),
('90fe7246-f3df-4d77-9582-cd1c3f1cadc6','送姪孫周上人歸剡余亦入吳門  其三','釋行海','宋','宋诗','song-poetry','','[]','片帆明日下長洲，今日分携浙水頭。',32,'全唐诗/poet.song.230000.json','["片帆明日下長洲，今日分携浙水頭。", "回首故鄉猶更遠，雁來紅葉夕陽秋。"]'),
('0a9db324-3f0a-4a2d-8a5e-f9d4e8a8a498','自上竺閑行至後磵題所見','釋行海','宋','宋诗','song-poetry','','[]','莓苔一徑趁溪斜，行盡松陰見水涯。',32,'全唐诗/poet.song.230000.json','["莓苔一徑趁溪斜，行盡松陰見水涯。", "遶屋花開非舊主，隔林烟起是誰家。"]'),
('152aff82-bcae-4542-b4c3-e0036c78fc5c','寫懷  其一','釋行海','宋','宋诗','song-poetry','','[]','話別蘇堤第一橋，白頭孤客悵難消。',32,'全唐诗/poet.song.230000.json','["話別蘇堤第一橋，白頭孤客悵難消。", "山中蹈華皈來晚，只有青燈作寂寥。"]'),
('96e3ffbd-40a1-43a3-b9ce-774fb39b9aac','寫懷  其二','釋行海','宋','宋诗','song-poetry','','[]','獨立吳山望越山，海門人去幾時還。',32,'全唐诗/poet.song.230000.json','["獨立吳山望越山，海門人去幾時還。", "故鄉猶隔蒼茫外，一點征愁落日間。"]'),
('9e37e44e-53d8-4cd8-9ec0-11396008a07e','初夏客懷','釋行海','宋','宋诗','song-poetry','','[]','綠樹成陰四月天，紫桐花放石池邊。',32,'全唐诗/poet.song.230000.json','["綠樹成陰四月天，紫桐花放石池邊。", "風光暗換人雙鬢，一別江南二十年。"]'),
('3b95004d-344e-499c-89f8-457de9ab42f8','遁溪','釋行海','宋','宋诗','song-poetry','','[]','白石磯頭鷺一叢，隔烟何處夕陽鐘。',32,'全唐诗/poet.song.230000.json','["白石磯頭鷺一叢，隔烟何處夕陽鐘。", "青山兩岸人家少，不種桃花只種松。"]'),
('c570d5a6-14c2-4f4a-bab6-11ac08d09dfc','夜泊吳城','釋行海','宋','宋诗','song-poetry','','[]','下纜吳城古樹根，打頭風緊欲黄昏。',32,'全唐诗/poet.song.230000.json','["下纜吳城古樹根，打頭風緊欲黄昏。", "雁聲南去蒹葭響，燈火家家半掩門。"]'),
('d7c88cab-077e-4de3-8de2-4cbc180b09f0','春興','釋行海','宋','宋诗','song-poetry','','[]','花透香鬚宿雨乾，柳飄晴絮送春寒。',32,'全唐诗/poet.song.230000.json','["花透香鬚宿雨乾，柳飄晴絮送春寒。", "最憐蝴蝶雙飛舞，只作莊周一夢看。"]'),
('9e837dae-513a-4817-9c02-5ee1a016e4db','柳下','釋行海','宋','宋诗','song-poetry','','[]','白絮隨風作雪飛，青絲拂地带烟齊。',32,'全唐诗/poet.song.230000.json','["白絮隨風作雪飛，青絲拂地带烟齊。", "湖光瀲灧春光暖，上有流鶑款曲啼。"]'),
('7c9f34c7-e5dd-4ea6-bffe-393e69fd7d84','即事','釋行海','宋','宋诗','song-poetry','','[]','江上烽烟雜戰塵，鳳城風景可憐人。',32,'全唐诗/poet.song.230000.json','["江上烽烟雜戰塵，鳳城風景可憐人。", "白頭老母關情切，眼見鶑花不是春。"]'),
('0e96991d-3944-4bf4-b7e1-184e4d50ae48','社日聞笛','釋行海','宋','宋诗','song-poetry','','[]','江南已有杏花開，社日都無燕子來。',32,'全唐诗/poet.song.230000.json','["江南已有杏花開，社日都無燕子來。", "人在白雲流水外，一聲折柳十分哀。"]'),
('5b3870e7-2831-4b1e-b7ef-27e1a8e3b6b2','有懷','釋行海','宋','宋诗','song-poetry','','[]','燕無消息雁都回，三疊陽關笛更哀。',32,'全唐诗/poet.song.230000.json','["燕無消息雁都回，三疊陽關笛更哀。", "可惜梅花逢夜雨，一場春怨滿蒼苔。"]'),
('618d73dc-4739-4f64-b12e-7d937980ba17','晚興  其一','釋行海','宋','宋诗','song-poetry','','[]','遶岸烟林半有無，夕陽人散釣船孤。',32,'全唐诗/poet.song.230000.json','["遶岸烟林半有無，夕陽人散釣船孤。", "小橋獨倚紅闌上，不覺閑身在畫圖。"]'),
('cf0d43cf-47d6-4587-9f11-ae7909a74c8c','晚興  其二','釋行海','宋','宋诗','song-poetry','','[]','塞北風寒雁字稀，羣鴉日暮貼雲飛。',32,'全唐诗/poet.song.230000.json','["塞北風寒雁字稀，羣鴉日暮貼雲飛。", "畫船皈後水天碧，隔岸鐘聲出翠微。"]'),
('d428e058-a0d0-4088-ac23-26cb8ffc13fd','小游仙','釋行海','宋','宋诗','song-poetry','','[]','青鳥銜書徧海涯，香風不返五雲車。',32,'全唐诗/poet.song.230000.json','["青鳥銜書徧海涯，香風不返五雲車。", "可憐夜夜瑶池月，空照蟠桃一樹花。"]'),
('babfb76d-2ebe-4830-a1e0-666d245102f5','梅  其一','釋行海','宋','宋诗','song-poetry','','[]','玉神何事带紅綃，未讓胭脂與杏桃。',32,'全唐诗/poet.song.230000.json','["玉神何事带紅綃，未讓胭脂與杏桃。", "天下更無清可比，湘纍不敢入離騷。"]'),
('72c6f957-713f-473b-ab7b-34fa916b4c06','梅  其二','釋行海','宋','宋诗','song-poetry','','[]','竹友當年已化龍，松朋久亦受秦封。',32,'全唐诗/poet.song.230000.json','["竹友當年已化龍，松朋久亦受秦封。", "此花有味調無鼎，且吐芳心過一冬。"]'),
('1186d93e-5117-4f7d-9785-98b5ba4273be','梅  其三','釋行海','宋','宋诗','song-poetry','','[]','此外無花耐歲寒，花魁今古品題難。',32,'全唐诗/poet.song.230000.json','["此外無花耐歲寒，花魁今古品題難。", "清香合讓梅爲最，陽艷叢中許牡丹。"]'),
('9973311d-ff70-4389-b4af-3a229ab80202','梅  其四','釋行海','宋','宋诗','song-poetry','','[]','二分明月是揚州，况有春風在樹頭。',32,'全唐诗/poet.song.230000.json','["二分明月是揚州，况有春風在樹頭。", "莫怪當年何水部，歲寒心事向誰愁。"]'),
('0ed23846-03fd-4347-ac45-52296397548f','梅  其五','釋行海','宋','宋诗','song-poetry','','[]','暖力回春萬木衰，苦心唯有自心知。',32,'全唐诗/poet.song.230000.json','["暖力回春萬木衰，苦心唯有自心知。", "水村山磵無人處，月下風前獨立時。"]'),
('dde13903-f9ea-4913-a543-3ef6be7a163d','梅  其六','釋行海','宋','宋诗','song-poetry','','[]','拂拂霜風掠面寒，清愁猶倚玉欄干。',32,'全唐诗/poet.song.230000.json','["拂拂霜風掠面寒，清愁猶倚玉欄干。", "月中香韻渾無頼，雪後晴花最好看。"]'),
('69b4b93e-66ee-4477-b855-9936f2d2789b','梅  其七','釋行海','宋','宋诗','song-poetry','','[]','占斷江南第一春，偏同雪月鬭精神。',32,'全唐诗/poet.song.230000.json','["占斷江南第一春，偏同雪月鬭精神。", "東君曾許殘花片，粧點壽陽宮裏人。"]'),
('1242fb0d-7a67-4114-9a0c-a3f97448389b','梅  其八','釋行海','宋','宋诗','song-poetry','','[]','難將羯鼓喚春回，一種風光傍雪開。',32,'全唐诗/poet.song.230000.json','["難將羯鼓喚春回，一種風光傍雪開。", "婀娜水仙難作弟，山礬猶自欠清才。"]'),
('9c11e0ad-1511-4479-aabf-7ffc67255ff4','梅  其九','釋行海','宋','宋诗','song-poetry','','[]','玉門關外雜塵埃，白帝城邊對酒杯。',32,'全唐诗/poet.song.230000.json','["玉門關外雜塵埃，白帝城邊對酒杯。", "今日孤山尤可惜，已無和靖在時梅。"]'),
('86b01625-52ce-41e1-a00b-6f9d8da539cc','梅  其一○','釋行海','宋','宋诗','song-poetry','','[]','冷澹孤芳雪裏春，園林風景一番新。',32,'全唐诗/poet.song.230000.json','["冷澹孤芳雪裏春，園林風景一番新。", "可憐花與頭俱白，豈晚相看似故人。"]'),
('985b6ba9-6e44-4690-ad10-a5dbb3f0c764','閑居  其一','釋行海','宋','宋诗','song-poetry','','[]','屋頭烟樹綠婆娑，最愛樵鄰夜唱歌。',32,'全唐诗/poet.song.230000.json','["屋頭烟樹綠婆娑，最愛樵鄰夜唱歌。", "獨坐小窗山寂寂，不知門外月明多。"]'),
('3e8a49f8-4b84-4ef2-b4df-474769fd9515','閑居  其二','釋行海','宋','宋诗','song-poetry','','[]','閑拈白拂坐筠床，靜聽幽禽弄夕陽。',32,'全唐诗/poet.song.230000.json','["閑拈白拂坐筠床，靜聽幽禽弄夕陽。", "滿地落花春已闌，深林只有蕙蘭香。"]'),
('8a61e284-d5d3-4d2e-bed1-cd3f228aa701','閑居  其三','釋行海','宋','宋诗','song-poetry','','[]','山礬香氣近幽蓀，玉色桃花靜對門。',32,'全唐诗/poet.song.230000.json','["山礬香氣近幽蓀，玉色桃花靜對門。", "曉日照烟林塢濕，春雲過雨石池渾。"]'),
('fe3f067a-83cc-4c4e-ba26-3b47b50d383e','閑居  其四','釋行海','宋','宋诗','song-poetry','','[]','蕩蕩空山草木青，枝禽飛下菜池冰。',32,'全唐诗/poet.song.230000.json','["蕩蕩空山草木青，枝禽飛下菜池冰。", "夜深月照茅簷靜，翠石幽泉落幾層。"]'),
('d65d3c5c-9a9d-4eaa-adc1-c056f46c71ba','閑居  其五','釋行海','宋','宋诗','song-poetry','','[]','遶岸奇峰半沒烟，滿窗凉影竹涓涓。',32,'全唐诗/poet.song.230000.json','["遶岸奇峰半沒烟，滿窗凉影竹涓涓。", "雙鳩並睡枯桑上，一鷺閑行白水邊。"]'),
('8afa4bd2-cfed-4901-b95e-1ac7f6574e50','田翁','釋行海','宋','宋诗','song-poetry','','[]','春晴野老喜桑麻，恣縱兒孫鬭萬花。',32,'全唐诗/poet.song.230000.json','["春晴野老喜桑麻，恣縱兒孫鬭萬花。", "頭白縣門猶未識，但聞人說有官家。"]'),
('8a413367-84b7-4c50-850b-a1249860d7de','無題','釋行海','宋','宋诗','song-poetry','','[]','金谷園中草色深，水樓終日柳陰陰。',32,'全唐诗/poet.song.230000.json','["金谷園中草色深，水樓終日柳陰陰。", "風前撥盡琵琶調，誰識當年馬上心。"]'),
('4d60f93c-b570-4383-a447-b66175bdb31e','吾廬','釋行海','宋','宋诗','song-poetry','','[]','二月吾廬感物華，傷春多在別人家。',32,'全唐诗/poet.song.230000.json','["二月吾廬感物華，傷春多在別人家。", "今年莫使春憔悴，能有幾番歸看花。"]'),
('5ebb58d3-a4fa-4e25-aa55-7240d32e6494','贈日者應菊坡','釋行海','宋','宋诗','song-poetry','','[]','東籬秋色徧幽坡，蔟蔟金英洗露華。',32,'全唐诗/poet.song.230000.json','["東籬秋色徧幽坡，蔟蔟金英洗露華。", "君且試推彭澤看，五行何處愛黄花。"]'),
('a7f45745-e75f-4982-b228-b3a448f0e1f8','南明道中','釋行海','宋','宋诗','song-poetry','','[]','酒旗猶寫天台紅，小白花繁綠刺叢。',32,'全唐诗/poet.song.230000.json','["酒旗猶寫天台紅，小白花繁綠刺叢。", "蜂蝶不來春意靜，日斜桐角奏東風。"]'),
('77a9aee1-44b9-4688-89b6-71b30635121b','少年子','釋行海','宋','宋诗','song-poetry','','[]','紫陌香塵逐馬蹄，玉簫聲裏看花開。',32,'全唐诗/poet.song.230000.json','["紫陌香塵逐馬蹄，玉簫聲裏看花開。", "綠衣鸚鵡臙脂嘴，一百金錢買得來。"]'),
('859c2515-14e8-40b7-ad38-91eceb6fe19b','梅邊','釋行海','宋','宋诗','song-poetry','','[]','寂寂春心在樹頭，冷香疎影更清幽。',32,'全唐诗/poet.song.230000.json','["寂寂春心在樹頭，冷香疎影更清幽。", "野籬山畔無人見，月下風前一段愁。"]'),
('05aed74d-682c-481e-8c91-86f9b7fb58b5','趙氏廢園','釋行海','宋','宋诗','song-poetry','','[]','笙歌無復醉南樓，燕雀凄凉草木秋。',32,'全唐诗/poet.song.230000.json','["笙歌無復醉南樓，燕雀凄凉草木秋。", "記得小時來撲蝶，幾枝摘盡好花頭。"]'),
('89de59a0-6c4a-479d-a384-1219f0c86df1','湖上  其一','釋行海','宋','宋诗','song-poetry','','[]','數點紅春在杏梢，舞衣歌管醉蘭橈。',32,'全唐诗/poet.song.230000.json','["數點紅春在杏梢，舞衣歌管醉蘭橈。", "水邊折得新花朶，蝴蝶相隨過彩橋。"]'),
('803250f8-3bc1-4c2a-ab67-aacefc4e873d','湖上  其二','釋行海','宋','宋诗','song-poetry','','[]','橋上紅闌倚夕陽，東風吹送禁梅香。',32,'全唐诗/poet.song.230000.json','["橋上紅闌倚夕陽，東風吹送禁梅香。", "王孫走馬晴堤遠，楊柳青青春草長。"]'),
('4960dc1d-e637-468e-ab5e-7ed91d27a900','陌上','釋行海','宋','宋诗','song-poetry','','[]','別人楊柳別人花，自對春風感物華。',32,'全唐诗/poet.song.230000.json','["別人楊柳別人花，自對春風感物華。", "陌上最憐芳草色，王孫多是不還家。"]'),
('514de598-9a52-400e-bb54-2a692dd61201','題靈溪蘭若壁','釋行海','宋','宋诗','song-poetry','','[]','又逢春色在君家，碧草籠烟带淺沙。',32,'全唐诗/poet.song.230000.json','["又逢春色在君家，碧草籠烟带淺沙。", "燕子不皈人欲去，小窗寂寞海棠花。"]'),
('04ac6f36-428d-4ae0-838a-8cb7f69a8769','湖上','釋行海','宋','宋诗','song-poetry','','[]','鳳城樓閣藹春風，湖水綠平橋影紅。',32,'全唐诗/poet.song.230000.json','["鳳城樓閣藹春風，湖水綠平橋影紅。", "蛺蝶倚花香夢暖，管絃聲斷夕陽中。"]'),
('deda1a11-09c5-4e4c-850b-726c71decaf4','采藥徑','釋行海','宋','宋诗','song-poetry','','[]','千古蒼苔一徑春，來尋劉阮故鄉人。',32,'全唐诗/poet.song.230000.json','["千古蒼苔一徑春，來尋劉阮故鄉人。", "山中草木今爲宋，亦有桃花尚說秦。"]'),
('e0b0d8a3-8f2e-4737-ad60-9ba4b7496753','錢府園池','釋行海','宋','宋诗','song-poetry','','[]','玉蘂金花水面浮，翠禽閑暇鷺鷥愁。',32,'全唐诗/poet.song.230000.json','["玉蘂金花水面浮，翠禽閑暇鷺鷥愁。", "夕陽睡起涼亭上，坐看魚兒作隊游。"]'),
('30dbcc7b-67d8-44db-a995-ec5005ab6b9b','靈鷲池上','釋行海','宋','宋诗','song-poetry','','[]','荷蓋高低綠影涼，露珠忽自瀉秋光。',32,'全唐诗/poet.song.230000.json','["荷蓋高低綠影涼，露珠忽自瀉秋光。", "舊曾棹過高林浦，雨濕臙脂柄柄香。"]'),
('6ce77585-59fa-4da1-8fa7-3b245595b4e4','丙辰二月二日喜晴  其一','釋行海','宋','宋诗','song-poetry','','[]','十分花氣醉春情，拂曉先聞百舌聲。',32,'全唐诗/poet.song.230000.json','["十分花氣醉春情，拂曉先聞百舌聲。", "白玉摇鞭芳草暖，踏青時節雨初晴。"]'),
('7d6057cd-b0c0-44f5-8c8e-7b3b555eee4d','丙辰二月二日喜晴  其二','釋行海','宋','宋诗','song-poetry','','[]','春來處處有花看，一種芳心欲吐難。',32,'全唐诗/poet.song.230000.json','["春來處處有花看，一種芳心欲吐難。", "陌上鵞黄初染柳，不禁烟雨裊輕寒。"]'),
('cbe1e0d9-b84a-4789-b31e-797f79ed5d35','丙辰二月二日喜晴  其三','釋行海','宋','宋诗','song-poetry','','[]','殘梅一片過晴簷，忽感春風三十三。',32,'全唐诗/poet.song.230000.json','["殘梅一片過晴簷，忽感春風三十三。", "舊雁自歸江北去，鶑花只是戀江南。"]'),
('03c5eaf9-4814-4325-8a1b-97198cd6ad45','暮春詞','釋行海','宋','宋诗','song-poetry','','[]','春風蕩槳落花時，江鼓鼕鼕舞柘枝。',32,'全唐诗/poet.song.230000.json','["春風蕩槳落花時，江鼓鼕鼕舞柘枝。", "雨洗櫻紅蠶豆綠，金衣公子可憐誰。"]'),
('b2364b61-549b-437e-9b8b-37c06777a33b','湖上感春','釋行海','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖二月好笙歌，遊女遊郎半插花。',32,'全唐诗/poet.song.230000.json','["西湖二月好笙歌，遊女遊郎半插花。", "忽對春風懷故國，不知新燕入誰家。"]'),
('b7fae37c-3a66-41f2-9092-2cb5f4ffbedd','泊唐栖寺','釋行海','宋','宋诗','song-poetry','','[]','颯颯寒聲折葦風，唐栖岸下泊孤篷。',32,'全唐诗/poet.song.230000.json','["颯颯寒聲折葦風，唐栖岸下泊孤篷。", "白頭不見頤山老，寂寞門前楓葉紅。"]'),
('66d45caf-b44d-4ca1-87f9-badfd1fddfb6','賦秋蓬','釋行海','宋','宋诗','song-poetry','','[]','蘆莖密織水烟籠，恰與湘漁屋檨同。',32,'全唐诗/poet.song.230000.json','["蘆莖密織水烟籠，恰與湘漁屋檨同。", "昨夜蘋香熏夢醒，又添荷葉蓋西風。"]'),
('8994815f-bbfa-423d-821c-aa9970ee0fcd','題山水圖  其一','釋行海','宋','宋诗','song-poetry','','[]','暮色溪山遠，烟林一兩家。',24,'全唐诗/poet.song.230000.json','["暮色溪山遠，烟林一兩家。", "孤舟何不住，雁欲下平沙。"]'),
('66ea60f4-69e3-4377-8e78-d1888668050d','題山水圖  其二','釋行海','宋','宋诗','song-poetry','','[]','烟動蘆根出，天高雁點微。',24,'全唐诗/poet.song.230000.json','["烟動蘆根出，天高雁點微。", "谿林茅屋晚，遥認釣船歸。"]'),
('aeeeec6f-c25e-44ea-a1a1-5c7489b60a23','送春謠','釋行海','宋','宋诗','song-poetry','','[]','今日鶑鶑燕燕愁，春風忽白少年頭。',32,'全唐诗/poet.song.230000.json','["今日鶑鶑燕燕愁，春風忽白少年頭。", "拍殘十八胡笳拍，數片嬌紅逐水流。"]'),
('a224b729-d753-4ad3-9da2-161185e616e8','少年子','釋行海','宋','宋诗','song-poetry','','[]','馬頭垂柳復垂楊，日暖遊絲滿洛陽。',32,'全唐诗/poet.song.230000.json','["馬頭垂柳復垂楊，日暖遊絲滿洛陽。", "賤把黄金買歌笑，不知流水去茫茫。"]'),
('67a3f63f-7c70-465b-ae54-3e0270a3049e','野興','釋行海','宋','宋诗','song-poetry','','[]','鷗入籬門沙岸高，秋來新壁換蘆條。',32,'全唐诗/poet.song.230000.json','["鷗入籬門沙岸高，秋來新壁換蘆條。", "半池烟荇浮黄萼，一架寒藤掛綠瓢。"]'),
('09ba602f-2bd7-4aca-acc9-07529ba11aaf','述懷','釋行海','宋','宋诗','song-poetry','','[]','山郡人來水郡遊，雁驚秋色向南州。',32,'全唐诗/poet.song.230000.json','["山郡人來水郡遊，雁驚秋色向南州。", "日長意懶無消遣，醉劈芙蓉付水流。"]'),
('ea03827d-f594-4153-b28e-9b06f52a1898','皂角林','釋行海','宋','宋诗','song-poetry','','[]','皂角林邊殺氣新，凄凉偏感北征人。',32,'全唐诗/poet.song.230000.json','["皂角林邊殺氣新，凄凉偏感北征人。", "我來認作將軍樹，汲靜當年打女真。"]'),
('c13013a4-430c-4d5e-8738-24c555f28192','送靈江住金華講院  其一','釋行海','宋','宋诗','song-poetry','','[]','七里灘頭問去津，嶄岩漁石蘚花春。',32,'全唐诗/poet.song.230000.json','["七里灘頭問去津，嶄岩漁石蘚花春。", "自從一別劉文叔，直到如今少故人。"]'),
('ea2910a9-191f-4d7a-a71a-4019ea06aabd','送靈江住金華講院  其二','釋行海','宋','宋诗','song-poetry','','[]','石裏烟雲護洞天，一條流水狹通船。',32,'全唐诗/poet.song.230000.json','["石裏烟雲護洞天，一條流水狹通船。", "金華仙子如相見，應問人間是幾年。"]'),
('58861202-30e0-4268-b618-c0f53eeaba93','送靈江住金華講院  其三','釋行海','宋','宋诗','song-poetry','','[]','名自黄扉遴選來，山中亦有禰衡材。',32,'全唐诗/poet.song.230000.json','["名自黄扉遴選來，山中亦有禰衡材。", "清風八詠雙溪月，講徹蓮花第一迴。"]'),
('7cf80074-2034-46d9-a625-7e6c362892e4','送靈江住金華講院  其四','釋行海','宋','宋诗','song-poetry','','[]','功成身退只留侯，多少英雄隠白頭。',32,'全唐诗/poet.song.230000.json','["功成身退只留侯，多少英雄隠白頭。", "爲報襄陽今日事，未應先向赤松遊。"]'),
('ae792433-7ace-40a1-b141-6babd1ff6219','送靈江住金華講院  其五','釋行海','宋','宋诗','song-poetry','','[]','山北山南草木青，杜鵑入夜不堪聽。',32,'全唐诗/poet.song.230000.json','["山北山南草木青，杜鵑入夜不堪聽。", "月明一種相思處，遥見天邊婺女星。"]'),
('99519e12-cd68-4cd2-8c54-2a6b7a0a82af','竹院','釋行海','宋','宋诗','song-poetry','','[]','滿林凉影綠沈槍，對此渾無俗肺腸。',32,'全唐诗/poet.song.230000.json','["滿林凉影綠沈槍，對此渾無俗肺腸。", "閑客偶來清話久，戛簷風擺翠梢長。"]'),
('16ada2bb-683d-4507-b97c-080b7ce2bac3','桂巖爲學上人賦','釋行海','宋','宋诗','song-poetry','','[]','蟾枝花放月香浮，石裏幽人住最幽。',32,'全唐诗/poet.song.230000.json','["蟾枝花放月香浮，石裏幽人住最幽。", "昨夜滿林風露冷，廣寒宮殿一般秋。"]'),
('75020b22-b3d2-4534-b071-ffaabf5cb83f','抱節','釋行海','宋','宋诗','song-poetry','','[]','凜凜清風上拂天，直持霜操透心堅。',32,'全唐诗/poet.song.230000.json','["凜凜清風上拂天，直持霜操透心堅。", "最憐一種身難屈，嚥雪餐氈十九年。"]'),
('8ceb1591-7bb4-4ca7-8279-498e48c447e8','山窗即景','釋行海','宋','宋诗','song-poetry','','[]','陰陰苔坎亂鳴蛙，光射林霏落月斜。',32,'全唐诗/poet.song.230000.json','["陰陰苔坎亂鳴蛙，光射林霏落月斜。", "池面綠舖蕉葉影，露階紅徧鳳兒花。"]'),
('7c6c6946-563c-4035-bbf6-ac5a5cdf95dc','八月十三夜聞雁','釋行海','宋','宋诗','song-poetry','','[]','年年風景暗相催，雁葉初紅雁又來。',32,'全唐诗/poet.song.230000.json','["年年風景暗相催，雁葉初紅雁又來。", "枕上一聲聞最苦，江南人望寄書迴。"]'),
('f8e1f439-fbb9-4acf-ac40-9d9639fa0969','賦獨山','釋行海','宋','宋诗','song-poetry','','[]','一峰突兀上虛空，石怪藤幽樹樹風。',32,'全唐诗/poet.song.230000.json','["一峰突兀上虛空，石怪藤幽樹樹風。", "四面白雲人不見，磬聲如在有無中。"]'),
('97b2e0a5-c0f4-47fd-a38f-9348771ab651','賦古岩','釋行海','宋','宋诗','song-poetry','','[]','撐空亂石带雲霞，靈樹曾開幾劫花。',32,'全唐诗/poet.song.230000.json','["撐空亂石带雲霞，靈樹曾開幾劫花。", "人在玲瓏深處坐，疎疎泉點滴袈裟。"]'),
('d97a9231-d4b0-4c16-af17-c7f1f41df48b','早春後園即事','釋行海','宋','宋诗','song-poetry','','[]','紫芽紅甲爆春枝，幽步尋芳款款移。',32,'全唐诗/poet.song.230000.json','["紫芽紅甲爆春枝，幽步尋芳款款移。", "蜂未出房寒尚在，梅花開徧不曾知。"]'),
('0a9266f0-1927-44cc-ba41-7fd60e74bf77','翔泳堂即景','釋行海','宋','宋诗','song-poetry','','[]','一池荷蓋綠陰涼，數朶紅蕖浥露香。',32,'全唐诗/poet.song.230000.json','["一池荷蓋綠陰涼，數朶紅蕖浥露香。", "最是畫橋林薄外，滿湖烟景淡斜陽。"]'),
('148cd08a-0787-4802-814e-b2badd30a2fd','詠所種松','釋行海','宋','宋诗','song-poetry','','[]','蒼髯分種出山林，却憶當年鬰翠陰。',32,'全唐诗/poet.song.230000.json','["蒼髯分種出山林，却憶當年鬰翠陰。", "自是君王來避雨，初無一點大夫心。"]'),
('87451587-5d70-41d4-b186-a4d229867e67','贈竹卿','釋行海','宋','宋诗','song-poetry','','[]','一擊虛空成粉碎，渭川千畝亦徒勞。',32,'全唐诗/poet.song.230000.json','["一擊虛空成粉碎，渭川千畝亦徒勞。", "不霑一點湘妃淚，自是無心節更高。"]'),
('8428c835-0b79-48a6-8ba1-f177c2caf0a1','讀金錍集','釋行海','宋','宋诗','song-poetry','','[]','白水青山總上心，可憐月色夜沉沉。',32,'全唐诗/poet.song.230000.json','["白水青山總上心，可憐月色夜沉沉。", "平生到處無人到，說向人知路轉深。"]'),
('6c709526-103e-4219-9be0-f73c57350b72','送姪孫周上人歸剡余亦入吳門','釋行海','宋','宋诗','song-poetry','','[]','三十餘年不在家，齒摇髮白眼昏花。',32,'全唐诗/poet.song.230000.json','["三十餘年不在家，齒摇髮白眼昏花。", "如今送子東歸去，心逐征帆過白沙。"]'),
('87e2ac67-1294-4bfc-8f1b-7ef5b4b857b2','送用上人  其一','釋行海','宋','宋诗','song-poetry','','[]','秋風吹客客悽凉，君欲還鄉我憶鄉。',32,'全唐诗/poet.song.230000.json','["秋風吹客客悽凉，君欲還鄉我憶鄉。", "山好真登秦望處，石橋偏拾禹餘糧。"]'),
('fccd2154-b289-4110-8436-da6af3bf4328','送用上人  其二','釋行海','宋','宋诗','song-poetry','','["\u897f\u6e56"]','歸去人應問上都，飛蝗飛不到西湖。',32,'全唐诗/poet.song.230000.json','["歸去人應問上都，飛蝗飛不到西湖。", "襄陽應有班師日，□□風傳幙有烏。"]'),
('3c87c726-9fa2-4302-b78f-86b4f2192a93','初夏客懷','釋行海','宋','宋诗','song-poetry','','[]','塞雁南來已北歸，鄉心空逐暮雲飛。',32,'全唐诗/poet.song.230000.json','["塞雁南來已北歸，鄉心空逐暮雲飛。", "楝花落盡寒猶在，月下金波點客衣。"]'),
('9572523d-9428-4a45-b1b4-3c23cf28de00','後園四花','釋行海','宋','宋诗','song-poetry','','[]','綠苞初結牡丹叢，千葉夭桃爛熳紅。',32,'全唐诗/poet.song.230000.json','["綠苞初結牡丹叢，千葉夭桃爛熳紅。", "唯有海棠芳意懶，柳花無力受春風。"]'),
('a7f23134-5978-47f1-9161-6e470eef27ad','三月三日寒食','釋行海','宋','宋诗','song-poetry','','[]','三月初三寒食雨，春光黯淡似秋光。',32,'全唐诗/poet.song.230000.json','["三月初三寒食雨，春光黯淡似秋光。", "羽書未報江東捷，何日看花到洛陽。"]'),
('2b0f7646-f41d-4e08-8cff-5719ef53ab1b','晚春','吳璞','宋','宋诗','song-poetry','','[]','開盡荼䕷白晝沉，枝頭聲已變春禽。',32,'全唐诗/poet.song.230000.json','["開盡荼䕷白晝沉，枝頭聲已變春禽。", "落花莫遣東風惱，小立閒庭愛綠陰。"]'),
('c0423362-1cef-4340-8553-7b77b19262af','挽知臨安府兼浙西制置使曾公  其一','曾子良','宋','宋诗','song-poetry','','[]','德祐思良弼，江西出大臣。',48,'全唐诗/poet.song.230000.json','["德祐思良弼，江西出大臣。", "報忠昭漢議，靖獻有殷仁。", "皦日五朝老，清風百世人。", "幾時歸衮繡，秋草卧麒麟。"]'),
('94107db3-442e-43d4-b871-4f6b576e936f','挽知臨安府兼浙西制置使曾公  其二','曾子良','宋','宋诗','song-poetry','','[]','永紹傳賢啟，慈元拱女堯。',48,'全唐诗/poet.song.230000.json','["永紹傳賢啟，慈元拱女堯。", "鼇山猶贔屭，鵬海極扶摇。", "宮殿春旗曉，簾帷社飯朝。", "龍髯攀不及，鸞馭去何遥。"]'),
('15b4e2e4-3b77-4a0a-a154-a8a9515f4b5d','挽知臨安府兼浙西制置使曾公  其三','曾子良','宋','宋诗','song-poetry','','[]','立海終風黑，洗光雙日紅。',48,'全唐诗/poet.song.230000.json','["立海終風黑，洗光雙日紅。", "餘波濺渤澥，仙仗岌崆峒。", "宗廟神靈在，公師禮數崇。", "平生精履屐，尚覺小臣忠。"]'),
('f820dc17-6ae0-4e4a-9caa-d913e1e31db2','挽知臨安府兼浙西制置使曾公  其四','曾子良','宋','宋诗','song-poetry','','[]','返輤榮歸寢，帷堂哭設衣。',48,'全唐诗/poet.song.230000.json','["返輤榮歸寢，帷堂哭設衣。", "神情如夢叶，滄海悵心違。", "百世功言立，千年城郭非。", "任安猶未死，哀淚不堪揮。"]'),
('c6219e80-0c6e-43a4-b1d5-69258dc771de','題高遠樓','曾子良','宋','宋诗','song-poetry','','[]','獨行三十六峰頭，飛過東華百尺樓。',64,'全唐诗/poet.song.230000.json','["獨行三十六峰頭，飛過東華百尺樓。", "今日中原前日夢，天人極樂世人愁。", "後千載續後千載，外九州環外九州。", "此處名煩君著眼，區區復記又何求。"]'),
('e45b14de-6c8c-4e15-beaa-79782b9cf81a','題章明叔春雨庵','曾子良','宋','宋诗','song-poetry','','[]','春雨生草木，雨去作流水。',36,'全唐诗/poet.song.230000.json','["春雨生草木，雨去作流水。", "流水不顧返，草木生未已。", "願隨流水去，一日行萬里。"]'),
('317e3d52-f851-41cb-a0a3-f694adac1ead','崔清獻公祠堂落成','翟龕','宋','宋诗','song-poetry','','[]','象笏猶存舊典型，魏謨亦此振家聲。',64,'全唐诗/poet.song.230000.json','["象笏猶存舊典型，魏謨亦此振家聲。", "矧今故第堂堂復，不日新祠恰恰成。", "嘉定間關全蜀險，端平倉卒護鄉城。", "此功此德垂千古，自有人人香火情。"]'),
('dedeacf0-c2d5-4551-b44e-07ad1ae79af3','寄王祥季昆','翟龕','宋','宋诗','song-poetry','','[]','右軍孫子總奇才，一別俄驚秋又來。',64,'全唐诗/poet.song.230000.json','["右軍孫子總奇才，一別俄驚秋又來。", "冠佩正宜朝鳳闕，釣竿未許老鼇臺。", "雲昏野寺疏鐘斷，潮落寒汀野鶴回。", "咫尺相思不相見，渴心吟望欲生灰。"]'),
('ac7752c3-a850-455e-9e02-57731bcd3823','挽趙秋曉','翟龕','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','早向南宮掇一籌，英聲藉藉出南州。',64,'全唐诗/poet.song.230000.json','["早向南宮掇一籌，英聲藉藉出南州。", "襟懷雪月五更曉，器宇江天萬頃秋。", "方羨廬山高築室，奚虞夜壑遽藏舟。", "天朝弗爲斯文地，才羨如公不久留。"]'),
('cb82b2fc-7419-4e5c-8abc-93047ff58627','赤鑑湖','留祐','宋','宋诗','song-poetry','','[]','赤鑑有遺利，曠古無人興。',24,'全唐诗/poet.song.230000.json','["赤鑑有遺利，曠古無人興。", "今師欲斷海，海若當效靈。"]'),
('24d481e0-f718-40b3-881b-2009340e6ff1','游九鎖','朱杰','宋','宋诗','song-poetry','','[]','九天虎豹不守關，瑶京夜半墮塵寰。',64,'全唐诗/poet.song.230000.json','["九天虎豹不守關，瑶京夜半墮塵寰。", "化爲青山故曲折，中有玉殿開仙班。", "白龍天來三百丈，飛沫直下琉璃灣。", "神仙可望不可接，桃花伴我歸人間。"]'),
('99279474-cb04-4ccd-a2fa-7cb648f64542','勸孝','趙與泌','宋','宋诗','song-poetry','','[]','三復蓼莪思二親，親恩天地無比倫。',352,'全唐诗/poet.song.230000.json','["三復蓼莪思二親，親恩天地無比倫。", "生我鞠我長育我，出入腹我何艱辛。", "爲人之子欲報德，昊天于我心罔極。", "順承猶恐莫酬恩，况敢忘恩爲悖逆。", "此邦由來多孝義，縣西元有曾參里。", "後來因避大賢名，却易里名爲養志。", "乃知里有孝順人，至今名號猶芳芬。", "人心天理不相遠，前賢孝行胡不遵。", "習俗薄惡良可嘆，梟獍之徒肆其悍。", "不念父母劬勞恩，悖德悖禮如習慣。", "在汝當爲反哺烏，汝乃叱之若狗奴。", "在汝當爲羊跽乳，汝乃詈之如嚇鼠。", "此事雖云未必然，我乃聞之毛髮寒。", "一朝引咎深自責，由我教化有未格。", "思昔曾爲貴鄉令，見人母子偶相競。", "令因涕出受孝經，母子翻然起新敬。", "余今告汝以因緣，汝宜悉把舊惡悛。", "從前果報言難盡，孝順之中自有天。", "五刑不孝最爲大，汝宜猛省聽予誨。", "官法昭昭在眼前，輕則編置重則配。", "假如幸免遭官刑，必有天刑及汝身。", "六丁霹靂飛雷霆，此時無路可自新。"]'),
('da92994a-99a6-4168-8ec3-bb71add66366','游洞霄','徐玨','宋','宋诗','song-poetry','','[]','凡世纖塵不敢侵，瑶關自鎖白雲深。',64,'全唐诗/poet.song.230000.json','["凡世纖塵不敢侵，瑶關自鎖白雲深。", "地靈佳木有仙意，山靜啼禽多好音。", "五洞暗通蓬島路，九峰密拱石壇陰。", "步虛聲了幽人暇，一穟爐香三弄琴。"]'),
('d1e0ab69-c8ad-4af9-93bd-9690110d1642','次兄奕修群玉山留題韻','謝奕信','宋','宋诗','song-poetry','','[]','碧玉參差繞崛奇，來登勝概喜忘疲。',32,'全唐诗/poet.song.230000.json','["碧玉參差繞崛奇，來登勝概喜忘疲。", "人傳唾玉添芳潤，二十年前刺史爲。"]'),
('9778eee8-7d25-4240-8fb9-073e4c9d5ec5','次兄奕修群玉山留題韻','謝奕奎','宋','宋诗','song-poetry','','[]','喜登群玉訪幽奇，步步瓊瑶力不疲。',32,'全唐诗/poet.song.230000.json','["喜登群玉訪幽奇，步步瓊瑶力不疲。", "拂拭棠陰留石刻，天然仙境豈人爲。"]'),
('ba51888b-39c2-4e60-a992-010a72538d89','小亭夜坐即景','趙必常','宋','宋诗','song-poetry','','[]','小亭夜坐滌炎蒸，頓覺風清趣已成。',32,'全唐诗/poet.song.230000.json','["小亭夜坐滌炎蒸，頓覺風清趣已成。", "數點流螢亭外度，兒童戲逐月邊星。"]'),
('3863c48f-1899-408b-9ea4-f8fef5a77b95','靈巖一線天','徐幾','宋','宋诗','song-poetry','','[]','盡日摩挲蘚石斑，幾人來此駐吟鞍。',32,'全唐诗/poet.song.230000.json','["盡日摩挲蘚石斑，幾人來此駐吟鞍。", "誰知一線通天處，照見人心凜凜寒。"]'),
('0da39837-cd45-49d7-9602-3fc80f9b26a0','獅子峰','徐幾','宋','宋诗','song-poetry','','[]','舉首朝天據洞扉，怪形蹲踞類狻猊。',32,'全唐诗/poet.song.230000.json','["舉首朝天據洞扉，怪形蹲踞類狻猊。", "山中彈壓無豺虎，留得孤猿半夜啼。"]'),
('791653f5-992b-49b5-b1f0-393a718195df','天壺','徐幾','宋','宋诗','song-poetry','','[]','老松壓石洞門聳，青蘿曳樹牽雲影。',32,'全唐诗/poet.song.230000.json','["老松壓石洞門聳，青蘿曳樹牽雲影。", "天然物外清修地，巖頭殘月沈丹井。"]'),
('5a77d653-4121-4d46-8834-d297b199e7ae','遊仙','詹琦','宋','宋诗','song-poetry','','[]','弱齡秉永向，撰念遊蓬瀛。',192,'全唐诗/poet.song.230000.json','["弱齡秉永向，撰念遊蓬瀛。", "騰蓋玄圃臺，投轡赤霞城。", "紫府五香馥，丹丘四照縈。", "班龍何夭矯，青鳳來相迎。", "道逢王子喬，手曳芙蓉旌。", "靈風襲霓裳，邀我謁瑶京。", "天帝坐叢霄，羣仙列兩楹。", "羽節自飄揚，衆樂鏘然鳴。", "授我金龜秘，錫我玉室名。", "渴漱沆瀣漿，饑餌橘樹英。", "忘形思入玄，道在豈求贏。", "流覺神驅盡，逍遥雲翮輕。", "棗花千歲結，桃核萬年成。", "海水揚塵竭，天衣拂石平。", "祈年本無分，望仙徒自營。", "寄謝樊籠士，那知遺世情。"]'),
('7ff1a1d8-f49d-4734-b811-94eee1f9d30e','題太姥墓','陳嘉言','宋','宋诗','song-poetry','','[]','吾聞堯時種藍嫗，世代更移那可數。',174,'全唐诗/poet.song.230000.json','["吾聞堯時種藍嫗，世代更移那可數。", "帝堯朽骨無微塵，此閒猶有堯時墓。", "墓中老嫗知不知，五帝三王奚以爲。", "狼貪鼠竊攫尺士，窾木未枯已易主。", "君不見仙人掌，分明指取青天上。", "騎龍謁帝大羅天，不逐華蟲挂塵網。", "又不見石棋盤，人去盤空局已殘。", "當時勝負此何有，爭先奪劫摧心肝。", "請君絕頂試飛舄，左望東甌右東冶。", "山川不見無諸君，但見烽煙徧郊野。", "野老吞聲掩淚哀，茫茫滄海生蓬萊。"]'),
('e9a75387-4c8c-4760-a965-dcd18cf16f8f','遊霍童  其一','陳嘉言','宋','宋诗','song-poetry','','[]','洞尋黄鶴白鶴，峰過大童小童。',28,'全唐诗/poet.song.230000.json','["洞尋黄鶴白鶴，峰過大童小童。", "杖底泉聲滴瀝，水邊樹色空濛。"]'),
('0bb0d8c1-82fa-40d1-b13e-155bea5b696d','遊霍童  其二','陳嘉言','宋','宋诗','song-poetry','','[]','藤上老猿欲墮，松間野鹿相隨。',28,'全唐诗/poet.song.230000.json','["藤上老猿欲墮，松間野鹿相隨。", "苔蘚綠埋丹竈，桃花紅染金錘。"]');
